-- Poems batch 362
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('4b153821-dedf-4714-9e7d-f64f42186c00','友人惠芍藥并青梅一枝偶成三絕  其二','葛勝仲','宋','宋诗','song-poetry','','[]','芳叢的皪長明檻，不似餘花頃刻春。',32,'全唐诗/poet.song.78000.json','["芳叢的皪長明檻，不似餘花頃刻春。", "始信有常能耐久，何須逐巧鬭尖新。"]'),
('1662f80e-a98c-4cd3-8b78-6f4497cb1a9d','友人惠芍藥并青梅一枝偶成三絕  其三','葛勝仲','宋','宋诗','song-poetry','','[]','香雪一林初著子，和枝分餉不吾慳。',32,'全唐诗/poet.song.78000.json','["香雪一林初著子，和枝分餉不吾慳。", "含酸但止文園渇，青瑣無人蹙遠山。"]'),
('82d3d020-c06a-41c6-b8ed-b3210bd64345','以糟水灌芍葯戲題  其一','葛勝仲','宋','宋诗','song-poetry','','[]','年年國艷賞敷腴，酩酊供人就燕胥。',32,'全唐诗/poet.song.78000.json','["年年國艷賞敷腴，酩酊供人就燕胥。", "此段固應先骨醉，餔糟聊學楚三閭。"]'),
('c7143c2c-51d6-463a-83d8-31ff6d572967','以糟水灌芍葯戲題  其二','葛勝仲','宋','宋诗','song-poetry','','[]','金邊山畔汁偏羙，玉井峰頭船最多。',32,'全唐诗/poet.song.78000.json','["金邊山畔汁偏羙，玉井峰頭船最多。", "未敢磨刀供大嚼，却愁藏扎有修羅。"]'),
('8e002a1f-6a2d-46cb-9e7c-9157a9ba3317','山谷以寒巖子詩十二首作藁書詞筆俱絕裴繼之出示求跋因題絕句','葛勝仲','宋','宋诗','song-poetry','','[]','百篇詩已露玄關，欲免驚愚理亦難。',32,'全唐诗/poet.song.78000.json','["百篇詩已露玄關，欲免驚愚理亦難。", "招得使君來帳下，不應饒舌坐豐干。"]'),
('8e776f2e-1c15-4f65-b0a5-3587fe92f36d','跋子猷訪戴圖','葛勝仲','宋','宋诗','song-poetry','','[]','玉屑金波各眼塵，如何牽役不知勤。',32,'全唐诗/poet.song.78000.json','["玉屑金波各眼塵，如何牽役不知勤。", "往來擾擾天機亂，那似端居對此君。"]'),
('2961e099-92d9-4aef-bc33-c5ecff4cb856','跋陶淵明歸去來圖','葛勝仲','宋','宋诗','song-poetry','','[]','小邑絃歌始數旬，迷塗才覺便歸身。',32,'全唐诗/poet.song.78000.json','["小邑絃歌始數旬，迷塗才覺便歸身。", "欲從典午完高節，聊與無懷作外臣。"]'),
('361694dc-842d-4a0a-bca7-dd4a94d5abe3','吳道子畫鬼','葛勝仲','宋','宋诗','song-poetry','','[]','莫将幽顯較精粗，人鬼從來理不殊。',32,'全唐诗/poet.song.78000.json','["莫将幽顯較精粗，人鬼從來理不殊。", "磊砢挐雲傳怪狀，論師天眼識工夫。"]'),
('4faefa90-7200-412d-998c-ff55f1c25bcd','跋李伯時畫李元通隨虎圖三首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','華嚴寶軸掛於菟，笑問翻經有地無。',32,'全唐诗/poet.song.78000.json','["華嚴寶軸掛於菟，笑問翻經有地無。", "引下福山三十里，不應老馬獨知塗。"]'),
('82d4bd6a-850d-434c-a1a8-0897713c0824','跋李伯時畫李元通隨虎圖三首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','清樾寒潭土作宫，楊枝柏葉五年中。',32,'全唐诗/poet.song.78000.json','["清樾寒潭土作宫，楊枝柏葉五年中。", "論成永作將來眼，第一功歸大小空。"]'),
('12401b99-bbbe-4ac6-9af5-b89c8331b137','跋李伯時畫李元通隨虎圖三首  其三','葛勝仲','宋','宋诗','song-poetry','','[]','素幅工傳長者真，龍眠端恐是前身。',32,'全唐诗/poet.song.78000.json','["素幅工傳長者真，龍眠端恐是前身。", "只留散带經行影，不貌供齋兩玉人。"]'),
('721b6901-b1f1-4eb2-b363-8da852ef9906','跋黄魯直畫','葛勝仲','宋','宋诗','song-poetry','','[]','江南黄𪁟飛滿野，徐熙畫此何爲者。',32,'全唐诗/poet.song.78000.json','["江南黄𪁟飛滿野，徐熙畫此何爲者。", "百年幅紙無所直，公毎玩之常在把。"]'),
('768d5662-1acb-4d15-933a-73f730d4dfcc','畫竹二首  其一','葛勝仲','宋','宋诗','song-poetry','','[]','萬箇霜筠保歲寒，風枝輕戛玉琅玕。',32,'全唐诗/poet.song.78000.json','["萬箇霜筠保歲寒，風枝輕戛玉琅玕。", "何人重作翩翩賦，寫出高標與諦看。"]'),
('f312a2fe-aa35-4b30-9138-577c29cf9429','畫竹二首  其二','葛勝仲','宋','宋诗','song-poetry','','[]','眼到竹邊知未是，竹來眼裏亦全非。',32,'全唐诗/poet.song.78000.json','["眼到竹邊知未是，竹來眼裏亦全非。", "諸人問我真如意，不到山前带笠歸。"]'),
('7d8cf07b-c2f6-4e0a-83df-6b63787559b0','白樂天  其一','葛勝仲','宋','宋诗','song-poetry','','[]','平生趣操號安恬，退亦恬然進不貪。',32,'全唐诗/poet.song.78000.json','["平生趣操號安恬，退亦恬然進不貪。", "何事潯陽恨遷謫，輕將清淚濕青衫。"]'),
('64d4490c-1e11-4741-98cd-498e79a7c724','白樂天  其二','葛勝仲','宋','宋诗','song-poetry','','[]','及泉曾改莊公誓，勝母終回曾子車。',32,'全唐诗/poet.song.78000.json','["及泉曾改莊公誓，勝母終回曾子車。", "素綆銀床堪淚墮，更能賦詠獨何如。"]'),
('d62a65ff-3f62-42dc-b6bb-e81c024c3565','大安門詩','葛勝仲','宋','宋诗','song-poetry','','[]','飛觀橫空數百間，強扶衰病一躋攀。',32,'全唐诗/poet.song.78000.json','["飛觀橫空數百間，強扶衰病一躋攀。", "非移閶闔從天界，應墮蓬壺自海山。"]'),
('7cda1639-6446-4dde-8607-26396fa4688f','王坦之','葛勝仲','宋','宋诗','song-poetry','','[]','廢莊演論救時玄，未免仍爲習氣牽。',32,'全唐诗/poet.song.78000.json','["廢莊演論救時玄，未免仍爲習氣牽。", "諷寡勸多吾不解，遣辭全只用三篇。"]'),
('5acb8f17-c133-45fc-a081-189b288dc2d9','近蒙明堂使局賜酒元巳日與諸僚會飲城東王君儀先生辟穀獨不敢召以二尊爲壽','葛勝仲','宋','宋诗','song-poetry','','[]','上尊霑賜自明堂，蕝禮無功愧濫嘗。',64,'全唐诗/poet.song.78000.json','["上尊霑賜自明堂，蕝禮無功愧濫嘗。", "玄晏先生聞嗜飲，青州從事敢慳藏。", "芳醲聊薦杯鐺眼，涓滴難澆錦繡腸。", "輕舉忽荒何所礙，南烹更欲強張良。"]'),
('c28c7005-07a7-436a-bd05-4b4156cf949f','君儀見和復別爲一首因各次韻','葛勝仲','宋','宋诗','song-poetry','','[]','載酒輕塵論禮堂，區區好事愧原嘗。',64,'全唐诗/poet.song.78000.json','["載酒輕塵論禮堂，區區好事愧原嘗。", "糟丘未辨陳喧老，壑谷寧容伯有藏。", "盎盎新香浮蟻面，陶陶煖息助龜腸。", "物微意重君毋誚，熾絜泉甘器亦良。"]'),
('d6dffe3c-2608-41e0-9ba5-993912f50b2a','君儀再和復次韻答之','葛勝仲','宋','宋诗','song-poetry','','[]','醪敷映玉浪吹香，未餉徵君敢獨嘗。',64,'全唐诗/poet.song.78000.json','["醪敷映玉浪吹香，未餉徵君敢獨嘗。", "甕下無人容借飲，壺中有客共深藏。", "歌呼僅可供頳頰，酩酊那憂共腐腸。", "好似東皋求待詔，三升日給醖偏良。"]'),
('d951e67f-7988-4b9c-b8be-65613f3af838','詩一首','葛勝仲','宋','宋诗','song-poetry','','[]','快雨霽亭千，晴曦作春妍。',120,'全唐诗/poet.song.78000.json','["快雨霽亭千，晴曦作春妍。", "鄰曲饒勝士，共開浮棗筵。", "中流愜嘯詠，隱浪金壺偏。", "紅芰初出水，捧劍疑來前。", "緬懷蘭亭會，七百八十年。", "可憐右軍癡，生死情纏綿。", "由來彭殤齊，顧或謂不然。", "吾黨殆天放，卜夜就管弦。", "尺六細腰舞，女袖輕回旋。", "且畢今日懽，不問來者傳。"]'),
('ace7ea77-c8fb-4c72-ae2d-dac1f0fc2e36','伏日不預諸僚飲會','葛勝仲','宋','宋诗','song-poetry','','[]','賜肉歸來命支生，共驚至日已三庚。',64,'全唐诗/poet.song.78000.json','["賜肉歸來命支生，共驚至日已三庚。", "巧遮畏景槐陰重，輕送微涼竹影情。", "坐局阻陪河朔飲，交鋒空想汝南評。", "紫雲的是尊前物，御史無緣問姓名。"]'),
('756be9ec-0a3e-460d-8f13-b4e332a15536','伯氏少卿侍建安文安二王講席于資善堂夜被旨錫紫章服輒成長句紀慶','葛勝仲','宋','宋诗','song-poetry','','[]','岐嶷天人講肆筵，恩華夜到華門前。',64,'全唐诗/poet.song.78000.json','["岐嶷天人講肆筵，恩華夜到華門前。", "十行詔墨芝香重，三品朝衣葚色鮮。", "能取身章同拾芥，應酬古本似奔泉。", "拖金朱綠更旬日，豈待常塗二十年。"]'),
('4ea60c21-84dd-4a15-ab06-dd42343c2048','定光禪院','葛勝仲','宋','宋诗','song-poetry','','[]','雲巖五花樹，下臨碧玉潭。',180,'全唐诗/poet.song.78000.json','["雲巖五花樹，下臨碧玉潭。", "泛泛石溜中，此獨潴揉藍。", "潭底玉石響，聲如奏韶咸。", "名從襄陽樣，山神固不甘。", "姓字汙山谷，貞元歲所鑱。", "我來事登覽，云有神龍潛。", "驕陽虔禬禱，膏乳一境霑。", "靈祠錫碩號，丹雘飛楹簷。", "僧廬鎖深閟，靈境超塵凡。", "懸瀑二十丈，銀河掛高巖。", "飛流濺珠琲，餘潤霑松杉。", "震響洶朝夕，數里聲不殱。", "禪客伴幽討，高下皆窮探。", "猿鶴不足數，俗駕從譏嫌。", "何當叨龍宮，寶方求玉函。"]'),
('ab40fb6a-c4dd-4787-a250-4af81f774b21','道成墩','葛勝仲','宋','宋诗','song-poetry','','[]','翛翛一羽翁，奇骨兩目方。',192,'全唐诗/poet.song.78000.json','["翛翛一羽翁，奇骨兩目方。", "乃以貧自樂，餐霞辟穀腸。", "混世人莫識，結茅居僻荒。", "一墩僅十畝，培塿萃彼疆。", "惠峰作南屏，秦望橫北牆。", "隱此不記年，悟仙號青暘。", "翩然仙道成，陟墩神遠翔。", "指墩名道成，人以許仙揚。", "豈無緱山人，吹笙雲錦裳。", "令威去千年，歸來賦歌章。", "青暘得仙去，千古傳此鄉。", "訛而爲柳跖，吳魯路渺茫。", "柳爲橫行盜，安肯城此旁。", "不知何愚人，魚魯昧審詳。", "至今傳名誤，使志乘其將。", "吾爲正斯繆，百世流餘芳。"]'),
('8037f768-3809-4fa2-a6cd-12d883c5e99d','句  其一','葛勝仲','宋','宋诗','song-poetry','','[]','空翠沾我襟，溟濛認堂奧。',24,'全唐诗/poet.song.78000.json','["空翠沾我襟，溟濛認堂奧。", "兼乃張公超，五里方術妙。"]'),
('43bf1b6f-e6cd-4a73-b3b1-bee874cb9b79','句  其二','葛勝仲','宋','宋诗','song-poetry','','[]','路出古浮山，木杪飛華屋。',12,'全唐诗/poet.song.79000.json','["路出古浮山，木杪飛華屋。"]'),
('a3309c46-0937-465a-9827-22d228f1a1de','句  其三','葛勝仲','宋','宋诗','song-poetry','','[]','住山偘老富心機。',8,'全唐诗/poet.song.79000.json','["住山偘老富心機。"]'),
('8c4d5e51-35b9-4e44-8db5-70e009b52cf1','句  其四','葛勝仲','宋','宋诗','song-poetry','','[]','何須兼住用招提。',8,'全唐诗/poet.song.79000.json','["何須兼住用招提。"]'),
('00fd925c-9ddf-4763-b29d-526af59e7c5e','句  其五','葛勝仲','宋','宋诗','song-poetry','','[]','身嘗靜退緣知足，心不傾邪畏好還。',16,'全唐诗/poet.song.79000.json','["身嘗靜退緣知足，心不傾邪畏好還。"]'),
('19006393-be82-493f-9e78-9c313949b7c9','句  其六','葛勝仲','宋','宋诗','song-poetry','','[]','吟懷遶廢城。',6,'全唐诗/poet.song.79000.json','["吟懷遶廢城。"]'),
('653e29f4-5ad5-436c-a4fa-f1e727535bd6','題楚辭','王玠','宋','宋诗','song-poetry','','[]','忠臣遭放逐，委質湘江沉。',48,'全唐诗/poet.song.79000.json','["忠臣遭放逐，委質湘江沉。", "空餘離騷辭，萬世蒙賞音。", "我今未忍死，終有報國心。", "扣閽且無路，寫作哀怨吟。"]'),
('1fd53103-c50d-4962-837b-c939fb42d562','山門夕陽洞','章夏','宋','宋诗','song-poetry','','[]','暖憑磴蘚坐，蔭覓喬松倚。',36,'全唐诗/poet.song.79000.json','["暖憑磴蘚坐，蔭覓喬松倚。", "一詣雲屋深，猿鶴頗相喜。", "霜鬚白紛紛，謂我作黄綺。"]'),
('d015cfd7-6105-473e-94bf-2317e7b2bad3','漣漪洞','章夏','宋','宋诗','song-poetry','','[]','石竇定神鵷，控隘潭水際。',36,'全唐诗/poet.song.79000.json','["石竇定神鵷，控隘潭水際。", "神靈浮槎入，想到珠宮憩。", "豈似武陵源，尚容人避世。"]'),
('d671d873-b9ef-4b87-9ae9-95344c2a6fd8','碧雲洞','章夏','宋','宋诗','song-poetry','','[]','褰裳踏寒流，路險仰稱傴。',36,'全唐诗/poet.song.79000.json','["褰裳踏寒流，路險仰稱傴。", "崖根乳積雪，石脈泉溜雨。", "融結知何年，人間閱今古。"]'),
('d787b38d-9ba4-426b-bdff-0282a43666af','紫雲巖','章夏','宋','宋诗','song-poetry','','[]','林表翠光出，浮埃不能涴。',36,'全唐诗/poet.song.79000.json','["林表翠光出，浮埃不能涴。", "俯瞰松下石，冉冉飛雲過。", "何人來棲真，復懷須彌座。"]'),
('634b5d06-b26f-453f-ba62-5b60c2c41597','黄山湯泉','凌唐佐','宋','宋诗','song-poetry','','[]','一道出遙岑，潺湲古到今。',48,'全唐诗/poet.song.79000.json','["一道出遙岑，潺湲古到今。", "雪天聲瀉玉，月夜影搖金。", "歲旱施功大，民情被澤深。", "容成與軒帝，仙迹可追尋。"]'),
('f4454f71-3198-4e60-97e5-2012415e6508','鍊丹竈','凌唐佐','宋','宋诗','song-poetry','','[]','鍊丹峰畔隱軒皇，石臼空存歲月長。',64,'全唐诗/poet.song.79000.json','["鍊丹峰畔隱軒皇，石臼空存歲月長。", "林下宛然含浄色，風前依舊發餘香。", "雖留此地千般葯，難問當時九轉方。", "獨向溪頭重拂拭，五雲何處日茫茫。"]'),
('fbb3be86-4868-4b2d-9877-176c382cc93b','洗藥溪','凌唐佐','宋','宋诗','song-poetry','','[]','紅泉聲裏獨徘徊，帝子當年洗藥來。',32,'全唐诗/poet.song.79000.json','["紅泉聲裏獨徘徊，帝子當年洗藥來。", "怪底餘香至今在，四時芝朮有花開。"]'),
('13fdc4a4-3f16-487c-b49c-65d42e4f1e17','書蔡元長堂','釋妙應','宋','宋诗','song-poetry','','[]','相得端明似虎形，搖頭攞腦得人憎。',32,'全唐诗/poet.song.79000.json','["相得端明似虎形，搖頭攞腦得人憎。", "看取明年作宰相，張牙劈口喫眾生。"]'),
('65504467-e168-4541-b7b6-14dc20345609','句','釋妙應','宋','宋诗','song-poetry','','[]','姓名不過程家渡，出郭猶行十里村。',16,'全唐诗/poet.song.79000.json','["姓名不過程家渡，出郭猶行十里村。"]'),
('4d89552b-49e7-4e7b-b3ce-a8b57d297ab1','建炎四年正月二十五日過南山詩','趙子松','宋','宋诗','song-poetry','','[]','□望□□洞，北□刻劃兼無雙。',217,'全唐诗/poet.song.79000.json','["□望□□洞，北□刻劃兼無雙。", "怪□□奇□，□□□□□。", "虬龍□□脊，彪兕怒翀羾。", "□□作澒洞，哀湍瀉春撞。", "磨崖名相踵，快意言多哤。", "賞心或自得，有力誰扛。", "想當秋水至，萬壑爭淙淙。", "仙聖會縹緲，松竹導旌幢。", "祇今巖岫間，彷彿餘舌杠。", "豈無避世翁，台背霜眉龐。", "□許尋子真，不辭拜老龐。", "華髪去鄉國，炎荒寄逢窻。", "偶著兩□歷，端令寸心降。", "危守跂鳥翼，旅食空酒缸。", "歸鴉識故棲，野燒明枯樁。", "送客雨霖霏，催□鼓逢逢。", "推枕耿不寐，取火續寒缸。", "哦詩雜蠻語，嘲哳愧新腔。"]'),
('d51f3ff9-bc56-431f-ac11-4da5986cfd0c','世綵堂','朱震','宋','宋诗','song-poetry','','[]','公家王母九十餘，大父侍立垂白鬚。',176,'全唐诗/poet.song.79000.json','["公家王母九十餘，大父侍立垂白鬚。", "子孫還如祖妣壽，康強不用旁人扶。", "誰家高曾見五世，不比徐卿生二雛。", "聞說一門能養志，膳羞壺酒隨親意。", "畏暑黄童扇枕忙，學啼萊子斑衣戲。", "發爲碧落新除吏，兒齒童眉復駘背。", "得壽當如衛武好，著書擬邁張蒼貴。", "餌菊三公未聞道，芳泉萬斛空勞費。", "豈知安樂便延年，無意益生生自至。", "高堂大幅垂輕絹，畫出嬋娟金翠翹。", "不如畫出綵衣去，使人知德如唐堯。"]'),
('b0550d14-9365-4379-a50b-bb84e53a632f','偈','釋守遂','宋','宋诗','song-poetry','','[]','一拳拳倒黄鶴樓，一踏踏翻鸚鵡洲。',32,'全唐诗/poet.song.79000.json','["一拳拳倒黄鶴樓，一踏踏翻鸚鵡洲。", "慣向高樓驟玉馬，曾於急水打金毬。"]'),
('b55d70ff-4984-4020-8d46-1077d0a7b6e0','偈二首  其一','釋大通','宋','宋诗','song-poetry','','[]','上不見天，下不見地。',35,'全唐诗/poet.song.79000.json','["上不見天，下不見地。", "畐塞虛空，無處回避。", "爲君明破即不中，且向南山鼈鼻。"]'),
('29ab8db2-34fe-4522-89c1-6f16a4cba57c','偈二首  其二','釋大通','宋','宋诗','song-poetry','','[]','吾本來茲土，傳法救迷情。',24,'全唐诗/poet.song.79000.json','["吾本來茲土，傳法救迷情。", "一華開五葉，結果自然成。"]'),
('55b8e172-fc6a-4046-b911-381ba02bea08','偈','釋巖','宋','宋诗','song-poetry','','[]','乾坤肅靜，海晏河清。',30,'全唐诗/poet.song.79000.json','["乾坤肅靜，海晏河清。", "風不鳴條，雨不破塊。", "春生夏長，秋收冬藏。"]'),
('3d6faa4b-b1c9-4f54-bdd5-8cba30603129','偈五首  其一','釋巖','宋','宋诗','song-poetry','','[]','雨後鳩鳴，山前麥熟。',35,'全唐诗/poet.song.79000.json','["雨後鳩鳴，山前麥熟。", "何處牧兒，騎牛笑相逐。", "莫把短笛橫吹，風前一曲兩曲。"]'),
('fbb3552d-e47b-43f8-823f-42a8a8214e82','偈五首  其二','釋巖','宋','宋诗','song-poetry','','[]','衲僧現前三昧，釋迦老子不會。',42,'全唐诗/poet.song.79000.json','["衲僧現前三昧，釋迦老子不會。", "住世四十九年，說得天花亂墜。", "爭似饑餐渴飲，展腳堂中打睡。"]'),
('b61801c4-eff1-4887-a593-fc498aeba96a','偈五首  其三','釋巖','宋','宋诗','song-poetry','','[]','諸人知處，山僧盡知。',30,'全唐诗/poet.song.79000.json','["諸人知處，山僧盡知。", "山僧知處，諸人不知。", "頭上是天，腳下是地。"]'),
('5cce8241-1417-4040-a9e5-08ca7ff30467','偈五首  其四','釋巖','宋','宋诗','song-poetry','','[]','一境誰相到，翛然絕點塵。',24,'全唐诗/poet.song.79000.json','["一境誰相到，翛然絕點塵。", "天花莫狼藉，吾匪解空人。"]'),
('27f92c0f-d80c-4c1d-b3da-a33690e51a7f','偈五首  其五','釋巖','宋','宋诗','song-poetry','','[]','樵夫跣足下層巒，大笑漁翁溪上寒。',32,'全唐诗/poet.song.79000.json','["樵夫跣足下層巒，大笑漁翁溪上寒。", "山色橫擔鄽市去，家家門底透長安。"]'),
('15e14dc4-4618-4da1-b2a0-993e69285322','偈','釋慧印','宋','宋诗','song-poetry','','[]','韶石渡頭，舟橫野水。',56,'全唐诗/poet.song.79000.json','["韶石渡頭，舟橫野水。", "汾陽浪裏，棹發孤煙。", "雲月無私，谿山豈異。", "一言合轍，千里同風。", "八千弟子今何在，萬里山河屬帝家。"]'),
('84c16ac2-dbf9-4c77-b1de-7f9e47c0586e','偈','釋宗一','宋','宋诗','song-poetry','','[]','美玉藏頑石，蓮花出淤泥。',24,'全唐诗/poet.song.79000.json','["美玉藏頑石，蓮花出淤泥。", "須知煩惱處，悟得即菩提。"]'),
('13910e67-8851-4e78-8aab-2667735843f3','偈','釋惟白','宋','宋诗','song-poetry','','[]','過去已過去，未來且莫算。',36,'全唐诗/poet.song.79000.json','["過去已過去，未來且莫算。", "正當現在事，今朝正月半。", "明月正團圓，打鼓普請看。"]'),
('ec82a5f2-79ea-45d4-825f-d22df082d12b','偈','釋曉通','宋','宋诗','song-poetry','','[]','冷似秋潭月，無心合太虛。',24,'全唐诗/poet.song.79000.json','["冷似秋潭月，無心合太虛。", "山高流水急，何處駐游魚。"]'),
('c2676679-bef6-4bd8-84a6-3b77ccaaea5a','偈','釋子英','宋','宋诗','song-poetry','','[]','節目分明，生來條直。',26,'全唐诗/poet.song.79000.json','["節目分明，生來條直。", "冰雪敲開片片分，白雲點破承伊力。"]'),
('360ea546-2e7d-4279-87b2-a33c952ae687','偈二首  其一','釋法因','宋','宋诗','song-poetry','','[]','天上月圓，人間月半。',20,'全唐诗/poet.song.79000.json','["天上月圓，人間月半。", "七八是數，事卻難算。"]'),
('66252b6d-7e52-4267-a05a-ad2c8856f998','偈二首  其二','釋法因','宋','宋诗','song-poetry','','[]','祖師妙訣，別無可說，直饒釘觜鐵舌。',32,'全唐诗/poet.song.79000.json','["祖師妙訣，別無可說，直饒釘觜鐵舌。", "未免弄巧成拙，凈名已把天機泄。"]'),
('1b837cf2-d68c-4ef2-90e6-6174cab9797a','偈','釋仁繪','宋','宋诗','song-poetry','','[]','至道無難，唯嫌揀擇。',46,'全唐诗/poet.song.79000.json','["至道無難，唯嫌揀擇。", "但莫憎愛，洞然明白。", "山僧則不然，至道最難，須是揀擇。", "若無憎愛，爭見明白。"]'),
('529a86e6-9d0a-444a-996c-c7e547170392','偈','釋廣','宋','宋诗','song-poetry','','[]','日頭東畔出，月向西邊沒。',48,'全唐诗/poet.song.79000.json','["日頭東畔出，月向西邊沒。", "來去急如梭，催人成白骨。", "山僧有一法，堪爲保命術。", "生死不相干，打破精魂窟。"]'),
('0ae278de-ec2d-49a1-a0e3-569ac972177f','偈三首  其一','釋自齡','宋','宋诗','song-poetry','','[]','月裏走金烏，誰云一物無。',24,'全唐诗/poet.song.79000.json','["月裏走金烏，誰云一物無。", "趙州東壁上，掛箇大胡蘆。"]'),
('b0acc805-7cb0-4037-ade8-37f0c7a39bbb','偈三首  其二','釋自齡','宋','宋诗','song-poetry','','[]','五千餘卷詮不盡，三世諸佛讚不及。',32,'全唐诗/poet.song.79000.json','["五千餘卷詮不盡，三世諸佛讚不及。", "令人卻憶賣油翁，狼忙走下繩床立。"]'),
('697b51cf-0abc-421c-8a4f-62f9bee472e0','偈三首  其三','釋自齡','宋','宋诗','song-poetry','','[]','便乃忘機守默，已被金粟占先。',28,'全唐诗/poet.song.79000.json','["便乃忘機守默，已被金粟占先。", "擬欲展演詞鋒，落在瞿曇之後。"]'),
('06da06f4-6782-4af3-8cba-944c606ebc13','偈','釋真悟','宋','宋诗','song-poetry','','[]','揚聲止響，不知聲是響根。',88,'全唐诗/poet.song.79000.json','["揚聲止響，不知聲是響根。", "弄影逃形，不知形爲影本。", "以法問法，不知法本非法。", "以心傳心，不知心本無心。", "心本無心，知心如幻。", "了法非法，知法如夢。", "心法不實，莫謾追求。", "夢幻空花，何勞把捉。"]'),
('c249776c-30fe-4aa2-add1-35f4083af2aa','偈','釋燈','宋','宋诗','song-poetry','','[]','天不能蓋，地不能載。',20,'全唐诗/poet.song.79000.json','["天不能蓋，地不能載。", "一室無私，何處不在。"]'),
('46b1644a-dfe3-40d9-b744-1b39d8865f2d','凈土院','虞謩','宋','宋诗','song-poetry','','[]','法界惟心現，真風觸處涼。',48,'全唐诗/poet.song.79000.json','["法界惟心現，真風觸處涼。", "具茨非有路，建德豈須糧。", "地僻遠塵世，境幽聞妙香。", "此山斯凈土，不必往西方。"]'),
('5919901a-432c-4771-97fe-b179c0e182c7','觀海','郭異','宋','宋诗','song-poetry','','[]','洶洶瀾無際，滔滔勢欲東。',48,'全唐诗/poet.song.79000.json','["洶洶瀾無際，滔滔勢欲東。", "百川容莫量，三島杳難窮。", "天淡祠堂古，雲低客路通。", "暫來回首懶，歸轡逐西風。"]'),
('2fb43778-1ad4-4a4a-be5e-4409399423c5','洪巖山六題 石門','王輔世','宋','宋诗','song-poetry','','[]','巖穴神仙宅，山門向嶺開。',24,'全唐诗/poet.song.79000.json','["巖穴神仙宅，山門向嶺開。", "時橫雲作鑰，怕有俗人來。"]'),
('3ad40f9a-79a9-44c4-a87e-bcf73a48b16f','洪巖山六題 石金剛','王輔世','宋','宋诗','song-poetry','','[]','天地應憐我，遺留鉅力神。',24,'全唐诗/poet.song.79000.json','["天地應憐我，遺留鉅力神。", "定須憑國手，神妙與傳真。"]'),
('6be7230e-a413-40f8-aae4-9980f2814f21','洪巖山六題 仙人臺','王輔世','宋','宋诗','song-poetry','','[]','任峻我須上，更高人亦行。',24,'全唐诗/poet.song.79000.json','["任峻我須上，更高人亦行。", "神仙雖已往，咫尺是蓬瀛。"]'),
('34f2f7b3-7cf7-46fa-b50c-605d31886f37','洪巖山六題 石猴','王輔世','宋','宋诗','song-poetry','','[]','猿猴嘗學禪，立德固堅久。',24,'全唐诗/poet.song.79000.json','["猿猴嘗學禪，立德固堅久。", "能乘獅子遊，不爲獅子後。"]'),
('3e662791-5f06-4b85-945e-d5092eb8ab3c','洪巖山六題 山風','王輔世','宋','宋诗','song-poetry','','[]','山露濕吾履，山風吹我衣。',24,'全唐诗/poet.song.79000.json','["山露濕吾履，山風吹我衣。", "白雲褰舉處，依約認崖扉。"]'),
('1a7a5c07-2c40-43fd-bb1b-f352bdf85495','洪巖山六題 石山雞','王輔世','宋','宋诗','song-poetry','','[]','山雞化爲石，錦翼已成藏。',24,'全唐诗/poet.song.79000.json','["山雞化爲石，錦翼已成藏。", "俗類休爭食，吾心不爲粱。"]'),
('0476712e-24f9-4d96-a830-3d2e05939d31','留題凈相院橙軒','彭迪明','宋','宋诗','song-poetry','','[]','萬葉扶疏雙幹修，植臨禪坐色長幽。',64,'全唐诗/poet.song.79000.json','["萬葉扶疏雙幹修，植臨禪坐色長幽。", "影分渭北千家月，香散江南一檻秋。", "清液冰寒承露結，圓苞金重带霜收。", "會應登列西州貢，庭實寧無橘柚羞。"]'),
('13cba1c6-9e62-4ff1-8fc1-119636b51bd1','句','雍孝聞','宋','宋诗','song-poetry','','[]','官田種秫陶元亮，私釜生塵范史雲。',16,'全唐诗/poet.song.79000.json','["官田種秫陶元亮，私釜生塵范史雲。"]'),
('27f04aba-6a3d-4565-867d-619a8ba4d747','過草堂望終南山','梅澤','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','兩峰高插碧天寒，雖得春風雪未乾。',32,'全唐诗/poet.song.79000.json','["兩峰高插碧天寒，雖得春風雪未乾。", "謝屐自忘登覽倦，草堂終日憑欄桿。"]'),
('fabe7048-691d-4a71-af4a-e159dbb70b5e','經樊川懷杜牧之','梅澤','宋','宋诗','song-poetry','','[]','杜曲樹連蒼翠外，終南雲暗有無中。',32,'全唐诗/poet.song.79000.json','["杜曲樹連蒼翠外，終南雲暗有無中。", "清詩妙句空貽後，不見樊川一老翁。"]'),
('32e2000c-0324-4a36-9067-4ed6429c16f0','行役述懷二首  其一','梅澤','宋','宋诗','song-poetry','','[]','世路侵尋老客顔，黄埃遮眼鬢毛班。',32,'全唐诗/poet.song.79000.json','["世路侵尋老客顔，黄埃遮眼鬢毛班。", "青山未許教人去，白日何曾放我閑。"]'),
('c34768b0-5cfc-41ff-9b25-6aa2c0bd5077','行役述懷二首  其二','梅澤','宋','宋诗','song-poetry','','[]','明月一尊酒，清風萬卷書。',24,'全唐诗/poet.song.79000.json','["明月一尊酒，清風萬卷書。", "南山山下地，終欲卜休居。"]'),
('2e813a08-51a1-4958-a5b7-ba1b6ea3f04a','春暮','李時','宋','宋诗','song-poetry','','[]','小園泥滑又妨行，破曉東風始放晴。',64,'全唐诗/poet.song.79000.json','["小園泥滑又妨行，破曉東風始放晴。", "九十日春將解印，兩三杯酒自尋盟。", "花依好竹如年少，人對青山俱老成。", "俗客不來清意足，一吟聊復暢幽情。"]'),
('01127b84-2dc0-484a-9bd6-581081faff43','十二月立春','李時','宋','宋诗','song-poetry','','[]','東風昨夜到疏籬，早被游蜂探得知。',64,'全唐诗/poet.song.79000.json','["東風昨夜到疏籬，早被游蜂探得知。", "花子又從今日好，人情須勝去年時。", "盤裝薺菜迎春餅，瓶插梅花带雪枝。", "勸了親庭眉壽酒，旋裁春帖換新詩。"]'),
('1a6eb6aa-829e-4e2c-b2ae-5f8bcbf057aa','途中遇雪','李時','宋','宋诗','song-poetry','','[]','天寒鴉欲棲，客路尚遲遲。',48,'全唐诗/poet.song.79000.json','["天寒鴉欲棲，客路尚遲遲。", "泥滑寒驢澀，風斜破帽欹。", "雲藏山斷絕，梅苦雪禁持。", "客裏愁無著，愁邊卻有詩。"]'),
('b6c2dcb0-8faf-4a3e-8d80-1f979f9999f4','柴門','李時','宋','宋诗','song-poetry','','[]','柴門盡日扃，緣是少將迎。',48,'全唐诗/poet.song.79000.json','["柴門盡日扃，緣是少將迎。", "但得常無事，何須更入城。", "病同愁鶴瘦，吟伴月蛩清。", "我自於時左，非干避姓名。"]'),
('ed72c342-bcb2-4241-8a9f-a46a5bc68bb9','黄崗寓館作','李時','宋','宋诗','song-poetry','','[]','閑居迎送少，日對小山橫。',48,'全唐诗/poet.song.79000.json','["閑居迎送少，日對小山橫。", "雨過秋陽減，天虛夜氣清。", "候蟲依壁韻，野火隔谿明。", "迢遞誰家笛，西風一雨聲。"]'),
('bcd3005d-6309-4fe8-97dc-74e70682e9b4','松風','林幹','宋','宋诗','song-poetry','','[]','白雲滿巖阿，松聲亂飛瀑。',24,'全唐诗/poet.song.79000.json','["白雲滿巖阿，松聲亂飛瀑。", "中有餐霞人，悠然絕塵俗。"]'),
('61f90424-b510-40a2-8391-a1396d0162e9','米拜石','林幹','宋','宋诗','song-poetry','','[]','危疑欲墮石，蒼然曰米拜。',24,'全唐诗/poet.song.79000.json','["危疑欲墮石，蒼然曰米拜。", "吁嗟千古情，石在米亦在。"]'),
('c1a5c5cb-c212-4efd-872a-1fec870224fb','贈傳燈  其一','林幹','宋','宋诗','song-poetry','','[]','解印歸來臥白雲，風塵總不到松筠。',64,'全唐诗/poet.song.79000.json','["解印歸來臥白雲，風塵總不到松筠。", "身從寶蓋依華座，手散天花聽梵文。", "五峙法空霞作綺，一龕慧月虎成群。", "□知隨處皆蓮士，何事幽溪兩地分。"]'),
('8b6b7e0f-aca6-44db-aef2-af6d1ba2c887','贈傳燈  其二','林幹','宋','宋诗','song-poetry','','[]','台教源流遠，高明紹梵音。',48,'全唐诗/poet.song.79000.json','["台教源流遠，高明紹梵音。", "扶桑紅日近，華頂白雲深。", "清磬度山翠，黄花匝地金。", "三乘示方便，萬法總惟心。"]'),
('a95bc589-be81-46cd-9224-c732c9dde04f','贈陳夢和','周氏','宋','宋诗','song-poetry','','[]','夢和殘月到樓西，月過樓西夢已迷。',32,'全唐诗/poet.song.79000.json','["夢和殘月到樓西，月過樓西夢已迷。", "喚起一聲腸斷處，落花枝上鷓鴣啼。"]'),
('9c50e3ac-9eb3-4260-aaf9-2f1cd82d531c','春晴','周氏','宋','宋诗','song-poetry','','[]','瞥然飛過誰家燕，驀地香來甚處花。',32,'全唐诗/poet.song.79000.json','["瞥然飛過誰家燕，驀地香來甚處花。", "深院日長無個事，一瓶春水自煎茶。"]'),
('bf0584f6-c45e-4029-af0e-dba887a255cd','投任伯雨詩','陳師錫子','宋','宋诗','song-poetry','','[]','恭惟持節日畿邊，抗疏公車首薦賢。',32,'全唐诗/poet.song.79000.json','["恭惟持節日畿邊，抗疏公車首薦賢。", "議論不能符國是，精誠直可動淵泉。"]'),
('687da2a7-ee35-402d-a2c7-814f8fe2abdd','句','周子雍','宋','宋诗','song-poetry','','[]','風生閶闔春來早，月到蓬萊夜未中。',16,'全唐诗/poet.song.79000.json','["風生閶闔春來早，月到蓬萊夜未中。"]'),
('ea73174f-9e76-448f-bf4b-7ea3407342c8','題河南王氏所藏子敬帖','黄伯思','宋','宋诗','song-poetry','','[]','君家大令書盈紙，筆勢翩翩趣多媚。',145,'全唐诗/poet.song.79000.json','["君家大令書盈紙，筆勢翩翩趣多媚。", "雖云沓拖如少年，豈至拘攣同餘興隸。", "會稽七子五知名，此公風概尤超詣。", "太極琁題猶重書，一時凜凜標英氣。", "半袖精裓眾爭求，數幅新裙世猶貴。", "當時親遇得已難，況復傳今僅千歲。", "龍珠歸浦劍還津，此帖君藏真得地。", "才披尺許目增明，鸞跂鴻驚欲飛逝。", "硬黄響搨若傳吾，完璧摹刊願垂世。"]'),
('97ddb178-2fbf-4efb-a13a-2a8013fc0ecb','烏臼樹','曾紆','宋','宋诗','song-poetry','','[]','三年逐客弄湘流，華氣遮欄兩鬢秋。',32,'全唐诗/poet.song.79000.json','["三年逐客弄湘流，華氣遮欄兩鬢秋。", "祇有荒寒江上樹，尚成詩句聚眉頭。"]'),
('ebb5ccea-a4e8-465e-9808-74f009621267','和葉少藴慈感蚌珠','曾紆','宋','宋诗','song-poetry','','[]','不知一殻幾由旬，能納須彌不動尊。',64,'全唐诗/poet.song.79000.json','["不知一殻幾由旬，能納須彌不動尊。", "疑是吳興清霅水，直通方廣古靈源。", "月沉濁水圓明在，蓮出汙泥寶性存。", "隱現去來初一致，莫將虛幻點空門。"]'),
('b924b25d-e13c-49ee-8e47-f26675b3ddc6','戲作冷語','曾紆','宋','宋诗','song-poetry','','[]','萬山雲雪陰霾空，千林霧淞水搖風。',48,'全唐诗/poet.song.79000.json','["萬山雲雪陰霾空，千林霧淞水搖風。", "凍河徹底連三冬，嘉平曉獵崤函中。", "十二律呂相與宮，安得此候疏煩胸。"]'),
('072645d4-c505-4898-b768-733559c41b1f','宣州水西作','曾紆','宋','宋诗','song-poetry','','[]','杖藜出郭一水近，石蹬古路穿松筠。',64,'全唐诗/poet.song.79000.json','["杖藜出郭一水近，石蹬古路穿松筠。", "萬仞絕壑倚天末，八節驚灘當寺門。", "泉聲飛下錦繡谷，殿影插入玻璃盆。", "宣州水西天下勝，閬州城南何足云。"]'),
('4ea7ecb3-bbae-4740-ad72-4d298043a548','清樾軒二首  其一','曾紆','宋','宋诗','song-poetry','','[]','臥聽灘聲㶁㶁流，冷風凄雨似深秋。',32,'全唐诗/poet.song.79000.json','["臥聽灘聲㶁㶁流，冷風凄雨似深秋。", "江邊石上烏臼樹，一夜水長到梢頭。"]'),
('8120ffea-d377-47b5-bcff-c4270489699c','清樾軒二首  其二','曾紆','宋','宋诗','song-poetry','','[]','竹間嘉樹密扶疏，異鄉物色似吾廬。',32,'全唐诗/poet.song.79000.json','["竹間嘉樹密扶疏，異鄉物色似吾廬。", "清曉開門出負水，已有小舟來賣魚。"]'),
('3f2224c3-3dc5-4801-8e65-f0b45e6a0c53','客愁','曾紆','宋','宋诗','song-poetry','','[]','客愁如繭絲，一攬成萬緒。',48,'全唐诗/poet.song.79000.json','["客愁如繭絲，一攬成萬緒。", "秋風不可奈，又到庭前樹。", "秋風自有時，客子愁無期。", "不如飲美酒，誦我山中詩。"]'),
('e2300793-0af0-49b2-9211-a376df812d73','寧川道中','曾紆','宋','宋诗','song-poetry','','[]','渡水穿橋一徑斜，潦收溪足露汀沙。',64,'全唐诗/poet.song.79000.json','["渡水穿橋一徑斜，潦收溪足露汀沙。", "半山雲影前山雨，十里香風晚稻花。", "異縣悲秋多客思，豐年樂事屬田家。", "故園正好不歸去，滿眼西風吹鬢華。"]'),
('4114259f-524d-4148-9946-23588644fef8','踈山','曾紆','宋','宋诗','song-poetry','','[]','江海相望二十年，依前骯髒倚門邊。',64,'全唐诗/poet.song.79000.json','["江海相望二十年，依前骯髒倚門邊。", "家風敢謂龐居士，句法空悲孟浩然。", "想見風流繼蓮社，應傳圖畫入斜川。", "病夫詩思猶艱窘，正似潮迴上水船。"]'),
('eb9767b5-7ef4-4d2e-af11-bc215e0e640d','北固樓','曾紆','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u5199\u666f", "\u519c\u6751", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u8c6a\u8fc8", "\u5b8b\u8bd7"]','枕中雲氣千峰近，牀底松聲萬壑哀。',32,'全唐诗/poet.song.79000.json','["枕中雲氣千峰近，牀底松聲萬壑哀。", "要看銀山拍天浪，開窻放入大江來。"]'),
('87bc847a-629a-45a9-941d-70b0c44d483f','句  其一','曾紆','宋','宋诗','song-poetry','','[]','百步橋邊蕩槳時。',8,'全唐诗/poet.song.79000.json','["百步橋邊蕩槳時。"]'),
('da6c9ac9-a66b-460e-ba3b-b8adb2b92170','句  其二','曾紆','宋','宋诗','song-poetry','','[]','獨與暮猿哀。',6,'全唐诗/poet.song.79000.json','["獨與暮猿哀。"]'),
('c032c4b6-6965-4cfb-898a-becac5c7af69','句  其三','曾紆','宋','宋诗','song-poetry','','[]','此興未應賒。',6,'全唐诗/poet.song.79000.json','["此興未應賒。"]'),
('87ab6bc0-6191-4eee-a4ce-ab746b0af116','句  其四','曾紆','宋','宋诗','song-poetry','','[]','炊煙逗疏藹，樵徑入蒼苔。',12,'全唐诗/poet.song.79000.json','["炊煙逗疏藹，樵徑入蒼苔。"]'),
('dafdacaa-6ddb-4645-b0db-76ddfd07790b','句  其五','曾紆','宋','宋诗','song-poetry','','[]','苔侵垂磴蔓，竹隱斷巖花。',12,'全唐诗/poet.song.79000.json','["苔侵垂磴蔓，竹隱斷巖花。"]'),
('defa388e-9f9c-4e66-aedf-46744aeb7124','拙頌奉別知事頤首兼雲堂諸禪眾','釋凈如','宋','宋诗','song-poetry','','[]','七年林下冷相依，自愧鉛刀利同微。',32,'全唐诗/poet.song.79000.json','["七年林下冷相依，自愧鉛刀利同微。", "聚散莫云千里遠，輪天一月共同暉。"]'),
('e4be0326-d672-4e26-a7c9-f519785cf82d','慈書記寫予真求讚漫書此以塞來意','釋凈如','宋','宋诗','song-poetry','','[]','眉不修疏頭突兀，鼻罍垂兮顴無骨。',40,'全唐诗/poet.song.79000.json','["眉不修疏頭突兀，鼻罍垂兮顴無骨。", "長憐百醜兼且訥，慈禪慈禪不我拙。", "名兮邈兮水裏月。"]'),
('fbac3bc1-aa59-471e-ae44-376de483970c','頌一首','釋凈如','宋','宋诗','song-poetry','','[]','四大幻形，徒勞口別。',46,'全唐诗/poet.song.79000.json','["四大幻形，徒勞口別。", "緣會而生，緣散而滅。", "一片虛空，本無口缺。", "六十九年一夢身，臨行何用忉二說。"]'),
('5fec0272-9a63-4086-9668-524e8982b75e','雜詩六首  其一','劉豫','宋','宋诗','song-poetry','','[]','竹塢人家瀕小溪，數枝紅杏出疏籬。',32,'全唐诗/poet.song.79000.json','["竹塢人家瀕小溪，數枝紅杏出疏籬。", "門前山色带煙重，幽鳥一聲春日遲。"]'),
('a5ed676e-ee51-41d7-9d68-2d562dc768c4','雜詩六首  其二','劉豫','宋','宋诗','song-poetry','','[]','風荷柄柄弄清香，輕薄沙禽落又翔。',32,'全唐诗/poet.song.79000.json','["風荷柄柄弄清香，輕薄沙禽落又翔。", "紅日轉西漁艇散，一川山影暮天涼。"]'),
('38af963c-30e6-42a1-abbc-93d264d90768','雜詩六首  其三','劉豫','宋','宋诗','song-poetry','','[]','古渡停驂日向沈，凄涼歸思梗清吟。',32,'全唐诗/poet.song.79000.json','["古渡停驂日向沈，凄涼歸思梗清吟。", "碧山幾點塞天闊，紅葉一林秋意深。"]'),
('0b574a6f-8494-4d93-902f-bad1954ab56a','雜詩六首  其四','劉豫','宋','宋诗','song-poetry','','[]','倚巖蕭寺據危崖，丈室軒窻面水開。',32,'全唐诗/poet.song.79000.json','["倚巖蕭寺據危崖，丈室軒窻面水開。", "雪霽暮寒山月上，數竿修竹一枝梅。"]'),
('1ad3999b-afa4-43a7-9cc7-7d080fd348b8','雜詩六首  其五','劉豫','宋','宋诗','song-poetry','','[]','晝色晴明著色圖，山光凝翠接平湖。',32,'全唐诗/poet.song.79000.json','["晝色晴明著色圖，山光凝翠接平湖。", "煙嵐自古人難畫，遠即深深近卻無。"]'),
('d36d24e0-e216-42f8-8c04-e851b15fc196','雜詩六首  其六','劉豫','宋','宋诗','song-poetry','','[]','寒林煙重暝棲鴉，遠寺疏鐘送落霞。',32,'全唐诗/poet.song.79000.json','["寒林煙重暝棲鴉，遠寺疏鐘送落霞。", "無限嶺雲遮不斷，數聲和月到山家。"]'),
('9515d4d7-ca3a-4385-a97f-bf5fb90421bc','客館','劉豫','宋','宋诗','song-poetry','','[]','雪消北嶺安排暖，寒入東風阻節春。',32,'全唐诗/poet.song.79000.json','["雪消北嶺安排暖，寒入東風阻節春。", "絕塞亂山圍古驛，他時說著也愁人。"]'),
('fd46b0ce-791d-4551-b49f-0a7ef2343abf','登蘇門山百泉','劉豫','宋','宋诗','song-poetry','','[]','太行雄偉赤霄逼，枝分蘇門爲肘腋。',240,'全唐诗/poet.song.79000.json','["太行雄偉赤霄逼，枝分蘇門爲肘腋。", "孕奇產秀氣蟠鬰，涌作琉璃千頃碧。", "初疑驪龍蟄山趾，仰噴明珠飛的皪。", "忽如湘靈理新粧，大鑑開匣乍磨拭。", "峰巒倒影浸雲煙，蘋藻照沙改顔色。", "相輝一段佳風月，餘澤幾州及動植。", "昔聞隱淪有仙人，高標清與溪山敵。", "悠悠往事散浮雲，嘯有遺屋行有跡。", "我居東秦濟水南，無限泉池日親炙。", "一行作吏別經年，情思塵埃何處滌。", "雲祠因禱來憑欄，頓爽骨毛快胸臆。", "飄飄蘭舟七八客，尊俎笙簫隨分入。", "勝概紛並接不暇，恨乏魯戈延晷刻。", "歸來簿領厭沉迷，春睡每着蝶夢適。", "心約他時杖履遊，醉潄溪流枕溪石。"]'),
('01889350-dcb1-44ad-a897-769c76764849','偈四首  其一','釋文璉','宋','宋诗','song-poetry','','[]','諸方浩浩談玄，每日撞鐘打鼓。',64,'全唐诗/poet.song.79000.json','["諸方浩浩談玄，每日撞鐘打鼓。", "西禪無法可說，勘破燈籠露柱。", "門前不置下馬臺，免被傍人來借路。", "若借路，須照顧。", "腳下若參差，邯鄲學唐步。"]'),
('d3e0abf9-7357-4bb4-a033-b1ec66423bc6','偈四首  其二','釋文璉','宋','宋诗','song-poetry','','[]','心生種種法生，森羅萬象縱橫。',85,'全唐诗/poet.song.79000.json','["心生種種法生，森羅萬象縱橫。", "信手拈來便用，日輪午後三更。", "心滅種種法滅，四句百非路好處。", "直饒達磨出頭，也是眼中著屑。", "心生心滅是誰，木人攜手同歸。", "歸到故鄉田地，猶遭頂上一鎚。"]'),
('28090863-a39f-43dd-98f0-fcea9ddcddc5','偈四首  其三','釋文璉','宋','宋诗','song-poetry','','[]','正月孟春猶寒，直下言端語端。',28,'全唐诗/poet.song.79000.json','["正月孟春猶寒，直下言端語端。", "拈起衲僧鼻孔，穿開佛祖心肝。"]'),
('edbad397-9d4e-45b6-86e9-3c29c2ee0241','偈四首  其四','釋文璉','宋','宋诗','song-poetry','','[]','昨日與今日，說定說不定。',40,'全唐诗/poet.song.79000.json','["昨日與今日，說定說不定。", "寰中天子敕，塞外將軍令。", "外道當年入夢鄉，直至如今猶未省。"]'),
('54553637-58f2-4553-8c58-7efd37937dec','七夕','應廓','宋','宋诗','song-poetry','','[]','烏鵲成橋架碧空，人間天上此歡同。',64,'全唐诗/poet.song.79000.json','["烏鵲成橋架碧空，人間天上此歡同。", "仙槎逐浪浮銀漢，青鳥傳音到帝宮。", "牛女佳期情不斷，古今遺恨意難窮。", "綵樓乞巧知多少，直至更闌漏欲終。"]'),
('9c44c9f2-fee7-446b-8f76-245b795f37d2','鵝湖春色','張仁及','宋','宋诗','song-poetry','','[]','平湖漾晴綠，狎鷗自相逐。',84,'全唐诗/poet.song.79000.json','["平湖漾晴綠，狎鷗自相逐。", "歸艇小于盂，輕帆曬蒲幅。", "青萍恣漂流，白魚跳尺玉。", "柳線牽人衣，香林雨新沐。", "汀尾沙禽鳴，人家映脩竹。", "步履隨春風，席地傾醽醁。", "玩樂當如何，回首炎威促。"]'),
('d5070836-2325-4cb6-8e37-0555cf47c980','和吳公仲庶遊海雲寺','張湍','宋','宋诗','song-poetry','','[]','海雲真賞甲刀州，十里春光拂馬頭。',64,'全唐诗/poet.song.79000.json','["海雲真賞甲刀州，十里春光拂馬頭。", "花酒價高分宴樂，綺羅人好助風流。", "出郊行旆從編俗，摸石居民事勝遊。", "斜日歡心猶未足，藩侯歸轡爲遲留。"]'),
('e1d1af8b-800c-4f20-ac89-f7eea7ebdaab','句','張固','宋','宋诗','song-poetry','','[]','鹿石曉寒雲漠漠，虎溪春淺水潺潺。',16,'全唐诗/poet.song.79000.json','["鹿石曉寒雲漠漠，虎溪春淺水潺潺。"]'),
('4c9f1a4d-c0b5-4e7d-8950-66fc66d2b2bc','劍閣','何亮','宋','宋诗','song-poetry','','[]','千峰如劍列虛空，曾隔車書不混同。',32,'全唐诗/poet.song.79000.json','["千峰如劍列虛空，曾隔車書不混同。", "安得乾坤作爐冶，鑄爲農器散寰中。"]'),
('f804ca6d-565a-4729-acca-93af09aca72c','寄遠','柴援','宋','宋诗','song-poetry','','[]','別時指我堂前柳，柳色青時望子時。',32,'全唐诗/poet.song.79000.json','["別時指我堂前柳，柳色青時望子時。", "今日柳綿吹欲盡，尚憑書去說相思。"]'),
('9b127020-58ac-446c-9da7-d06b98ee3f9c','客舍','柴援','宋','宋诗','song-poetry','','[]','隻影寄空館，蕭然饑鶴姿。',24,'全唐诗/poet.song.79000.json','["隻影寄空館，蕭然饑鶴姿。", "秋風北窻來，問我歸何時。"]'),
('c1c7484a-51fa-4142-9d31-d06b80f2caf9','三學院二首  其一','李鞉','宋','宋诗','song-poetry','','[]','遠岫朝來更爽，孤雲徙倚長閑。',28,'全唐诗/poet.song.79000.json','["遠岫朝來更爽，孤雲徙倚長閑。", "飛出偶成霖雨，歸來依舊青山。"]'),
('305d1268-a8e8-4791-bbaf-dc3d1c8e6909','三學院二首  其二','李鞉','宋','宋诗','song-poetry','','[]','江橫水如带，楓落山爲屏。',120,'全唐诗/poet.song.79000.json','["江橫水如带，楓落山爲屏。", "高深自天險，豪邁由地靈。", "行個古道中，下馬坐郵亭。", "鶴棲必仙家，鳳儀豈堯庭。", "神仙事恍惚，誰實觀超昇。", "孫氏一時傑，父兄俱有聲。", "將軍垂紫髯，阿瞞眼亦青。", "周郎往視師，不數李與程。", "緬懷前哲人，耿耿在心扃。", "託宿就蕭寺，夢還神更清。"]'),
('30bb2226-ec79-4b49-9584-af53a9e4bc3a','寶林院巖香閣','李鞉','宋','宋诗','song-poetry','','[]','花到清明際，隨春渡虎溪。',48,'全唐诗/poet.song.79000.json','["花到清明際，隨春渡虎溪。", "勾牽木芍藥，流落古招提。", "獨喜孤芳在，何妨眾草齊。", "定知妃子意，不解謫仙題。"]'),
('122e432b-fb57-432f-b198-2226db3eef7e','送李去病郎中出使西蜀','李鞉','宋','宋诗','song-poetry','','[]','宗盟一派落三川，人物風流類謫。',63,'全唐诗/poet.song.79000.json','["宗盟一派落三川，人物風流類謫。", "自小飛聲燦星斗，至今揮翰起雲煙。", "過家徙倚東山外，弭節雍容錦水邊。", "信道儒冠真貴重，疾驅負弩令君先。"]'),
('c05912df-9874-4de4-877f-3faa19b8f695','和李公鞉寶林院巖香閣','釋則安','宋','宋诗','song-poetry','','[]','醉歌寒食夜，花照武陵溪。',48,'全唐诗/poet.song.79000.json','["醉歌寒食夜，花照武陵溪。", "吟鉢聊先擊，詩筒更遠提。", "影隨春色動，芳與國香齊。", "玉節重來賞，僧窻覓舊題。"]'),
('c3409ee0-9068-4b04-8b87-ffbc200a0050','雨轟漈','蔡佃','宋','宋诗','song-poetry','','[]','水流石激擬鳴雷，洞裏乾坤別有臺。',64,'全唐诗/poet.song.79000.json','["水流石激擬鳴雷，洞裏乾坤別有臺。", "玉舄扶風飛復下，瓊花带雨落還開。", "鐘聲敲斷白雲裊，樹影盤迴黄鶴來。", "笑道神仙無覓處，空留丹竈冷蒼苔。"]'),
('04402480-b36a-46bd-b254-bb224f9f81e8','豁然閣','蔡佃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','長風東南來，濁浪撓清鏡。',60,'全唐诗/poet.song.79000.json','["長風東南來，濁浪撓清鏡。", "小軒寂寞人，默視心境靜。", "扁舟暫淹留，思與孤鴻迥。", "洞庭眼中物，何必更乘興。", "頑石漫巑岏，終慚泗濱磬。"]'),
('8b03ab7b-5ddc-45b2-a09e-73b4d235c0db','舟入江陰集句','林震','宋','宋诗','song-poetry','','[]','疏疏蘆葦舊江天，何處風光最可憐。',64,'全唐诗/poet.song.79000.json','["疏疏蘆葦舊江天，何處風光最可憐。", "一带樓臺擎曉月，萬株楊柳拂晴煙。", "身閑暫覺塵埃遠，道在寧憂雨露偏。", "三頃湖田秋更熟，濁醪粗飯任吾年。"]'),
('d504e80d-e74e-410c-afaa-8010897adace','句','林震','宋','宋诗','song-poetry','','[]','青山有恨花初謝，流水無言草自春。',16,'全唐诗/poet.song.79000.json','["青山有恨花初謝，流水無言草自春。"]'),
('55e4ea13-7001-4ca3-9f26-36e53ab8141f','洗心泉','胡侃','宋','宋诗','song-poetry','','[]','巖根石溜自涓涓，一見塵勞頓灑然。',32,'全唐诗/poet.song.79000.json','["巖根石溜自涓涓，一見塵勞頓灑然。", "惟有開山老尊宿，無心可洗亦無泉。"]'),
('d7622c0d-81da-4263-90ed-5ce61c4565c2','望海亭','陳壽朋','宋','宋诗','song-poetry','','[]','謾指亭前柏，西來意自深。',48,'全唐诗/poet.song.79000.json','["謾指亭前柏，西來意自深。", "迷人終著景，達士了忘心。", "六葉傳真諦，微言振道林。", "法門應不二，來此默追尋。"]'),
('162e66da-8d0d-431e-97b7-7ae4fa109861','西軒','王孳','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','步躡霜莎入梵宮，一軒佳處屬支公。',64,'全唐诗/poet.song.79000.json','["步躡霜莎入梵宮，一軒佳處屬支公。", "剩開青瑣延明月，疏植修篁待好風。", "笠澤波聲春雨裏，洞庭山色夕陽中。", "江頭景物牢籠盡，欲寄琴尊此養蒙。"]'),
('78af016e-162c-4d49-a161-59f697fabde1','題房城驛','曾弼','宋','宋诗','song-poetry','','[]','萬山飛不出，有屈向誰伸。',24,'全唐诗/poet.song.79000.json','["萬山飛不出，有屈向誰伸。", "寄語絃歌宰，留心且爲民。"]'),
('7442beea-96ee-4bfc-ac60-8075c2fa431d','李伯紀丞相挽詩  其一','曾開','宋','宋诗','song-poetry','','[]','先帝收士，惟公最妙年。',48,'全唐诗/poet.song.79000.json','["先帝收士，惟公最妙年。", "清班依日月，讜論薄標雲天。", "終賴高名重，來扶大業全。", "誰提太史筆，臣主頌俱賢。"]'),
('1614b229-49a4-4bc7-b8a5-00a508191a81','李伯紀丞相挽詩  其二','曾開','宋','宋诗','song-poetry','','[]','太上初傳位，安危俛仰間。',48,'全唐诗/poet.song.79000.json','["太上初傳位，安危俛仰間。", "從容回萬乘，指顧復三關。", "漢北塵沙迥，閩中日月槳。", "誰知千載後，遺恨在燕山。"]'),
('59d37e9b-b984-4616-82a1-f00fdb030345','李伯紀丞相挽詩  其三','曾開','宋','宋诗','song-poetry','','[]','追數中興相，公居第一人。',48,'全唐诗/poet.song.79000.json','["追數中興相，公居第一人。", "初期從北伐，寧料久南巡。", "此日勞明主，他年憶舊臣。", "東都朝萬國，不復見簪紳。"]'),
('0284ef81-8800-48ea-ad5a-6479c7eed188','李伯紀丞相挽詩  其四','曾開','宋','宋诗','song-poetry','','[]','昔造東都第，斯文得典型。',48,'全唐诗/poet.song.79000.json','["昔造東都第，斯文得典型。", "謬蒙蕃下榻，親見鯉趨庭。", "雁序相先後，鴻飛獨杳冥。", "至今鸞鵠峙，梧竹養修翎。"]'),
('4c2f6552-0269-4a51-b380-c0073a6730e9','李伯紀丞相挽詩  其五','曾開','宋','宋诗','song-poetry','','[]','一別睢陽後，風霜十五年。',48,'全唐诗/poet.song.79000.json','["一別睢陽後，風霜十五年。", "勞生俱老矣，流涕獨潸然。", "丹井秋來就，心燈夜半傳。", "定應真不死，歸臥白雲邊。"]'),
('7ac07b43-97cc-43d3-bcfc-a56bd222f443','偈','曾開','宋','宋诗','song-poetry','','[]','咄哉瞎驢，叢林妖孽。',36,'全唐诗/poet.song.79000.json','["咄哉瞎驢，叢林妖孽。", "震地一聲，天機漏洩。", "有人更問意如何，拈起拂子劈口截。"]'),
('315de094-6ffb-4d5b-91c4-d9704901c0b9','句','曾開','宋','宋诗','song-poetry','','[]','翠幕管絃三市曉，畫堂煙雨五峰秋。',16,'全唐诗/poet.song.79000.json','["翠幕管絃三市曉，畫堂煙雨五峰秋。"]'),
('df03fb8f-d1a1-4884-92a6-e44c59c94c47','謝恩','彭路','宋','宋诗','song-poetry','','[]','聖主求賢軫念勞，臨軒策問萃時髦。',64,'全唐诗/poet.song.79000.json','["聖主求賢軫念勞，臨軒策問萃時髦。", "龍鱗日繞天顔近，螭首雲移帝座高。", "疏草披丹陳紫禁，宮花錫采光藍袍。", "自慚朽芥叨榮遇，報答能忘聖語褒。"]'),
('04c729e8-0822-454e-80ce-77162a83fa75','和彭路謝恩','崇寧翰林','宋','宋诗','song-poetry','','[]','一經曾守十年勞，振藻今爲曠世髦。',64,'全唐诗/poet.song.79000.json','["一經曾守十年勞，振藻今爲曠世髦。", "鳳閣風雲平地奮，龍門波浪捲天高。", "青錢聲重鳴金賦，紅杏香生茜錦袍。", "主聖臣賢當作頌，愧無椽筆繼王褒。"]'),
('3b688562-3455-403d-8848-2ee3a619fb80','駕幸太學','李階','宋','宋诗','song-poetry','','[]','天祐斯文賴表章，皇心眷眷事膠庠。',64,'全唐诗/poet.song.79000.json','["天祐斯文賴表章，皇心眷眷事膠庠。", "享嚴祖殿回龍馭，德警儒班肅鷺行。", "降輦詣祠追四聖，擁經求道舉三王。", "欲知盛美前無古，賢聖相逢在廟堂。"]'),
('72ed39f8-99a9-422a-ac85-a1e0f312fb56','命卜','徐存','宋','宋诗','song-poetry','','[]','我命還須我自推，細微那更問蓍龜。',32,'全唐诗/poet.song.79000.json','["我命還須我自推，細微那更問蓍龜。", "枯莖朽骨猶能兆，豈有靈臺自不知。"]'),
('d4a23b35-c97d-437e-befa-0e477ea32eef','題臨江軍驛舍二首  其一','江端友','宋','宋诗','song-poetry','','[]','李白當年謫夜旔，中原不復漢文章。',32,'全唐诗/poet.song.79000.json','["李白當年謫夜旔，中原不復漢文章。", "納官贖罪何人在，壯士悲歌淚兩行。"]'),
('fb47ff2a-8281-4434-8840-8e5e5fbc4150','題臨江軍驛舍二首  其二','江端友','宋','宋诗','song-poetry','','[]','晉公功業冠皇唐，吏部文章日月光。',32,'全唐诗/poet.song.79000.json','["晉公功業冠皇唐，吏部文章日月光。", "千載斷碑人膾炙，不知世有段文昌。"]'),
('d9c60ae7-6b60-45cf-bc03-5ff8e30d87dc','玉延行','江端友','宋','宋诗','song-poetry','','[]','觀文學士留都守，中常侍門如役走。',112,'全唐诗/poet.song.79000.json','["觀文學士留都守，中常侍門如役走。", "玉延厥篚二十五，謹書名銜細看醜。", "推而上之何止此，牢耶石邪猶八九。", "嗟哉膏血出生靈，割剝乃餉無須口。", "仲華拜衮雖有年，宋璟李鄘曾愧否。", "樂全見事何其微，義勇固應如此厚。", "翰林未用汝脫靴，不知何爲勤洗手。"]'),
('d186de7f-39ad-4567-96be-c9c786269136','牛酥行','江端友','宋','宋诗','song-poetry','','[]','有客有客官長安，牛酥百斤親自煎。',112,'全唐诗/poet.song.79000.json','["有客有客官長安，牛酥百斤親自煎。", "倍道奔馳少師府，望塵且欲迎歸年。", "守閽呼語不必出，已有人居第一先。", "其多乃復倍于此，台顔顧視初怡然。", "昨朝所獻雖第二，桶以純漆麗且堅。", "今君來遲數又少，青紙題封難勝前。", "持歸空慚遼東豕，努力明年趁頭市。"]'),
('4c9ddebc-5750-442c-bbd1-4cbbf9a74821','九日','江端友','宋','宋诗','song-poetry','','[]','萬里江河隔，傷心九日來。',48,'全唐诗/poet.song.79000.json','["萬里江河隔，傷心九日來。", "蓬驚秋日後，菊換故園開。", "楚欲圖周鼎，湯猶擊夏臺。", "東籬那一醉，塵爵恥虛罍。"]'),
('9ed2129f-156c-4255-bc63-3ef4e76c4d89','題清芬閣','江端友','宋','宋诗','song-poetry','','[]','淆名江上月，幽思嶺邊雲。',48,'全唐诗/poet.song.79000.json','["淆名江上月，幽思嶺邊雲。", "沒世無知己，陪祠未當勤。", "喪衾論邪正，詩律較銖分。", "端似太丘長，公卿見紀群。"]'),
('9da5f3c1-49da-40b0-a5c5-52c5845f29a7','句  其一','江端友','宋','宋诗','song-poetry','','[]','比年熒惑犯南斗，何日燕人祭北門。',16,'全唐诗/poet.song.79000.json','["比年熒惑犯南斗，何日燕人祭北門。"]'),
('210ebf49-eba1-4a86-a936-0ae0f828fd0f','句  其二','江端友','宋','宋诗','song-poetry','','[]','倉舒止用兒童計，亦自能知爾重輕。',16,'全唐诗/poet.song.79000.json','["倉舒止用兒童計，亦自能知爾重輕。"]'),
('db2661cc-86e3-42c5-8571-3b8cfdefdcf1','建炎丞相成國呂忠穆公退老堂  其一','王绹','宋','宋诗','song-poetry','','[]','尚父風猷襲後昆，復生賢相紹高門。',64,'全唐诗/poet.song.79000.json','["尚父風猷襲後昆，復生賢相紹高門。", "白麻懇避公孤貴，黄閣屢辭機務繁。", "再入經綸勞鼎鉉，乍從觴詠樂山樊。", "功名終始追前哲，美播青編望益尊。"]'),
('61c93322-e664-475e-99e7-3a47dcb126d0','建炎丞相成國呂忠穆公退老堂  其二','王绹','宋','宋诗','song-poetry','','[]','巨力曾扶國步安，功成猶未鬢毛斑。',64,'全唐诗/poet.song.79000.json','["巨力曾扶國步安，功成猶未鬢毛斑。", "天心正佑宋無極，人意詎容公久閑。", "裴令縱能娛綠野，謝公可是老東山。", "何當鼓櫂輕千里，款奉清談宴俎閑。"]'),
('6f6b95e5-a4ab-4565-8ef8-1ecf1893c4fd','春日書懷','胡安國','宋','宋诗','song-poetry','','[]','一氣本無息，春風花又開。',48,'全唐诗/poet.song.79000.json','["一氣本無息，春風花又開。", "景多閑後見，詩好靜中來。", "午枕莊周夢，東軒靖節盃。", "不須籬畔菊，能制暮齡頹。"]'),
('f8e1584f-62b1-4a16-bd24-eac850540c72','首夏言懷','胡安國','宋','宋诗','song-poetry','','[]','白日延清景，紅芳轉綠陰。',48,'全唐诗/poet.song.79000.json','["白日延清景，紅芳轉綠陰。", "川雲長淡蕩，魚鳥自高深。", "靜養中和氣，閑消忿慾心。", "此情雖不語，沙界總知音。"]'),
('3da7a33b-332c-4af6-9d73-32ad05df9715','重過丫頭巖思先大夫  其一','胡安國','宋','宋诗','song-poetry','','[]','道旁山色古猶今，綠鬢偏驚白髮侵。',32,'全唐诗/poet.song.79000.json','["道旁山色古猶今，綠鬢偏驚白髮侵。", "回想臨岐分袂處，更誰能會此時心。"]'),
('f617198b-655f-4e6c-8392-355cda63d066','重過丫頭巖思先大夫  其二','胡安國','宋','宋诗','song-poetry','','[]','慈顔何在杳難承，教子生來重一經。',32,'全唐诗/poet.song.79000.json','["慈顔何在杳難承，教子生來重一經。", "謾向人間拾青紫，豈勝衣綵日趨庭。"]'),
('62e8f21d-d8ba-4771-859c-e6162c7d89c5','黄石山','胡安國','宋','宋诗','song-poetry','','[]','鳳吹鸞輿向戚姬，滿朝無策定傾危。',32,'全唐诗/poet.song.79000.json','["鳳吹鸞輿向戚姬，滿朝無策定傾危。", "直須致得商山老，能遣君王意自移。"]'),
('cb4d6949-465c-4f78-82f1-ec545fae319c','過鳳林關','胡安國','宋','宋诗','song-poetry','','[]','馬首西南二十年，每經關左重留連。',64,'全唐诗/poet.song.79000.json','["馬首西南二十年，每經關左重留連。", "殷勤拂石臨流水，邂逅憑欄倚暮煙。", "千古物情吟不盡，四時風景畫難傳。", "何人可作隆中伴，待結比鄰買釣船。"]'),
('c4af42ce-c691-4a5b-a42c-d6071d7efbf0','奉次朱子發稧飲碧泉','胡安國','宋','宋诗','song-poetry','','[]','不牽春草詠池塘，且對山泉共舉觴。',64,'全唐诗/poet.song.79000.json','["不牽春草詠池塘，且對山泉共舉觴。", "碧玉涌波清見底，戲鱗依荇款成行。", "杯盤草草情逾厚，淡話平平味更長。", "亦有浯溪聳天石，待鐫佳頌壓元郎。"]'),
('a9881452-2b22-4431-bff6-6c092655517f','舟入荆江東赴建康','胡安國','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江渺渺接天浮，萬古朝宗日夜流。',64,'全唐诗/poet.song.79000.json','["長江渺渺接天浮，萬古朝宗日夜流。", "洲在尚傳鸚鵡賦，臺高應見鳳凰遊。", "路經赤壁懷公瑾，水到柴桑憶仲謀。", "白日幸無雲物蔽，好看澄景對高秋。"]'),
('f2f62d9f-6664-447d-a2d7-e23eb12c1ed8','元日','胡安國','宋','宋诗','song-poetry','','[]','競裝祓木餞餘寒，頌遂椒花上彩箋。',32,'全唐诗/poet.song.79000.json','["競裝祓木餞餘寒，頌遂椒花上彩箋。", "覽鏡自驚非昔貌，舉杯回喜得新年。"]'),
('3969dd3c-1099-42ab-ab0d-12d2187432c8','十二月立春','胡安國','宋','宋诗','song-poetry','','[]','未臨除夕氣先交，玉嶂朝來見日消。',63,'全唐诗/poet.song.79000.json','["未臨除夕氣先交，玉嶂朝來見日消。", "冰自解圍回木色，花能傳信滿梅梢。", "人家剪彩應書字，天仗迎春盡廣郊。", "北望寒雲魂夢斷，任從飛莫相招。"]'),
('5230249c-3dc5-4292-8803-53974a990e0b','牡丹秋開','胡安國','宋','宋诗','song-poetry','','[]','秀出群芳照碧欄，世間顔色比應難。',64,'全唐诗/poet.song.79000.json','["秀出群芳照碧欄，世間顔色比應難。", "曉來露採光先泛，晚得雲陰葉未殘。", "艷質易迷人競賞，道心無染興終閑。", "使君認取真消息，同向樽前笑裏看。"]'),
('4127c266-2a77-4166-abb8-61b597ebb386','雪','胡安國','宋','宋诗','song-poetry','','[]','彤雲無際朔風高，萬竅噓聲正怒號。',64,'全唐诗/poet.song.79000.json','["彤雲無際朔風高，萬竅噓聲正怒號。", "梅徑有香迷皓萼，漁舟堪畫壓洪濤。", "樵家束桂邀行祝，村館論錢吝薄醪。", "破臘莫嫌寒色□，會看禾黍滿東皋。"]'),
('02a9e7e8-f3c0-48fd-9310-3bc41c90d4e8','嚴陵釣臺','胡安國','宋','宋诗','song-poetry','','[]','歸隱桐江知幾春，靜看浮世一漚輕。',32,'全唐诗/poet.song.79000.json','["歸隱桐江知幾春，靜看浮世一漚輕。", "此心有處元無着，誤說持竿作釣名。"]'),
('ff773b8b-b456-42b1-81c8-1dca66a169ef','赤壁','胡安國','宋','宋诗','song-poetry','','[]','片語能令孫仲謀，氣如山涌劍橫秋。',32,'全唐诗/poet.song.79000.json','["片語能令孫仲謀，氣如山涌劍橫秋。", "莫言諸葛成何事，萬古忠言第一流。"]'),
('c15b885b-f9f2-4304-92c6-7c90fb905ff6','贈雲居僧明公五首  其一','胡安國','宋','宋诗','song-poetry','','[]','手握乾坤殺活機，縱橫施設在臨時。',32,'全唐诗/poet.song.79000.json','["手握乾坤殺活機，縱橫施設在臨時。", "滿堂兔馬非龍象，大用堂堂總不知。"]'),
('ea0ccfc3-2408-430d-8815-f530710fc142','贈雲居僧明公五首  其二','胡安國','宋','宋诗','song-poetry','','[]','踏遍江南春寺苔，野雲縱跡去還來。',32,'全唐诗/poet.song.79000.json','["踏遍江南春寺苔，野雲縱跡去還來。", "如今□□□峰頂，無法可傳心似灰。"]'),
('4e133136-c776-4e04-a172-73a362e0f1cf','贈雲居僧明公五首  其三','胡安國','宋','宋诗','song-poetry','','[]','祝融峰似在城天，萬古江山在目前。',32,'全唐诗/poet.song.79000.json','["祝融峰似在城天，萬古江山在目前。", "須信死心元不死，夜來明月又重圓。"]'),
('c3334c09-4d29-45d0-8f3e-9f88b7e5c4a2','贈雲居僧明公五首  其四','胡安國','宋','宋诗','song-poetry','','[]','明公從小便超群，佳句流傳繼碧雲。',32,'全唐诗/poet.song.79000.json','["明公從小便超群，佳句流傳繼碧雲。", "問道別來諸念息，定將何法退魔軍。"]'),
('6a0fed5e-a25a-4915-acd8-8bfcaded23d9','贈雲居僧明公五首  其五','胡安國','宋','宋诗','song-poetry','','[]','十年音信斷鴻鱗，夢想雲居頂上人。',32,'全唐诗/poet.song.79000.json','["十年音信斷鴻鱗，夢想雲居頂上人。", "香飯可能長自飽，也應分濟百千身。"]'),
('d7a0a4af-c9af-4cf4-81ef-bf187b6b2bc5','竹園書屋','胡安國','宋','宋诗','song-poetry','','[]','四壁無圖畫，推窻盡簡書。',24,'全唐诗/poet.song.79000.json','["四壁無圖畫，推窻盡簡書。", "真吾何所寄，深處樂如如。"]'),
('decd7e29-1734-4d41-9e35-b41fb5913b7a','題崔白喧晴圖','胡安國','宋','宋诗','song-poetry','','[]','黑頭禽笑白頭禽，頭白多因計慮深。',32,'全唐诗/poet.song.79000.json','["黑頭禽笑白頭禽，頭白多因計慮深。", "棲向柳條猶不穩，從風斜折更關心。"]'),
('dc11041a-1d02-4923-814e-b23a1176ff50','移居碧泉','胡安國','宋','宋诗','song-poetry','','[]','買山固是爲深幽，況有名泉例可求。',64,'全唐诗/poet.song.79000.json','["買山固是爲深幽，況有名泉例可求。", "短夢正須依白石，澹情好與結清流。", "庭栽疏竹客馴鶴，月滿前川寺補樓。", "十里鄉鄰漸相識，醉歌田舍即丹邱。"]'),
('dfdf918a-cbdd-4246-a4a5-ad1bc09774a4','句  其一','胡安國','宋','宋诗','song-poetry','','[]','愛日尚貪毛義檄，望雲長繞仲宣樓。',16,'全唐诗/poet.song.79000.json','["愛日尚貪毛義檄，望雲長繞仲宣樓。"]'),
('93c6d92a-96e3-4ff7-8959-f34a129df852','句  其二','胡安國','宋','宋诗','song-poetry','','[]','此邦若有誅茆地。',8,'全唐诗/poet.song.79000.json','["此邦若有誅茆地。"]'),
('d6d9af8c-f638-4013-9642-0cb114aa058d','離黄龍有作','釋惟尚','宋','宋诗','song-poetry','','[]','大袖長拖出祖關，蛟龍戰罷海濤閑。',32,'全唐诗/poet.song.79000.json','["大袖長拖出祖關，蛟龍戰罷海濤閑。", "寄言白首參玄者，休把虛空側點斑。"]'),
('a0a0a1a4-7c99-46a7-9e70-0b7dd578eab5','次韻答張無垢居士','釋惟尚','宋','宋诗','song-poetry','','[]','從來高價莫饒伊，百戰場中奮兩眉。',32,'全唐诗/poet.song.79000.json','["從來高價莫饒伊，百戰場中奮兩眉。", "奪角衝關群會也，叢林誰敢更相欺。"]'),
('2f815898-3bf4-4cea-b613-9e54d21335cd','呈覺印禪師偈','釋惟尚','宋','宋诗','song-poetry','','[]','須是南泉第一機，不知不覺驀頭錐。',32,'全唐诗/poet.song.79000.json','["須是南泉第一機，不知不覺驀頭錐。", "覿面若無青白眼，還如𮭗𮭗守空池。"]'),
('5224d98e-442f-4c42-ae24-ae4948d95162','偈','尼凈智','宋','宋诗','song-poetry','','[]','趙州舌頭連天，老婆眉光覆地。',28,'全唐诗/poet.song.79000.json','["趙州舌頭連天，老婆眉光覆地。", "分明勘破歸來，無限平人瞌睡。"]'),
('3e66e153-3e46-4c34-ae97-bb5483d07fa7','中秋雨下偈','釋慧蘭','宋','宋诗','song-poetry','','[]','家家啟戶待嬋娟，豈謂風雲翳碧天。',32,'全唐诗/poet.song.79000.json','["家家啟戶待嬋娟，豈謂風雲翳碧天。", "賴得箇中消息在，團團不動照三千。"]'),
('645a3ba3-d0e3-43c3-98ae-98c9f9d715dc','頌古 五位 其一','釋慧蘭','宋','宋诗','song-poetry','','[]','正中偏拈轉，虛空過那邊。',28,'全唐诗/poet.song.79000.json','["正中偏拈轉，虛空過那邊。", "夜半金雞生鐵卵，明明誰辨暗中圓。"]'),
('88b22c0a-cb99-4ea7-b7bd-5e4606175ab1','頌古 五位 其二','釋慧蘭','宋','宋诗','song-poetry','','[]','偏中正曉月，梳雲華弄影。',28,'全唐诗/poet.song.79000.json','["偏中正曉月，梳雲華弄影。", "石人驚起夢魂消，带雪烏雞回鳳嶺。"]'),
('6a1b3a90-5952-479c-84ca-09f3b4c0a2f4','頌古 五位 其三','釋慧蘭','宋','宋诗','song-poetry','','[]','正中來玉兔，團天耀九垓。',28,'全唐诗/poet.song.79000.json','["正中來玉兔，團天耀九垓。", "萬古碧潭無影像，紅爐焰裏雪華開。"]'),
('efa8128b-fe33-4310-8d91-ec26e8274736','頌古 五位 其四','釋慧蘭','宋','宋诗','song-poetry','','[]','兼中至錦縫，金針雙鎖備。',28,'全唐诗/poet.song.79000.json','["兼中至錦縫，金針雙鎖備。", "靴頭線綻足知音，有耳不臨流水流。"]'),
('61fb2564-9ae7-40e8-86fd-8ca167c54551','頌古 五位 其五','釋慧蘭','宋','宋诗','song-poetry','','[]','兼中到眼裏，雙瞳齊喝道。',28,'全唐诗/poet.song.79000.json','["兼中到眼裏，雙瞳齊喝道。", "少室山前鐵馬駒，三便喫盡無根艸。"]'),
('d2957683-abea-43d1-a347-b960d4f2a274','偈','釋樞','宋','宋诗','song-poetry','','[]','春將至，歲已暮。',67,'全唐诗/poet.song.79000.json','["春將至，歲已暮。", "思量古往今來，祇是箇般調度。", "凝眸昔日家風，下足舊時岐路。", "勸君休莫莽鹵，眨上眉毛須薦取。", "東村王老笑呵呵，此道今人棄如土。"]'),
('3b4f8fa4-b811-4a84-af00-6c2faf3c878d','偈二首  其一','釋楚明','宋','宋诗','song-poetry','','[]','出門見山水，入見見佛殿。',24,'全唐诗/poet.song.79000.json','["出門見山水，入見見佛殿。", "靈光觸處通，諸人何不薦。"]'),
('0ea19bd5-bf27-4a36-9a92-bcdd94b4b981','偈二首  其二','釋楚明','宋','宋诗','song-poetry','','[]','閻浮有大寶，見少得還稀。',24,'全唐诗/poet.song.79000.json','["閻浮有大寶，見少得還稀。", "若人將獻我，成佛一餉時。"]'),
('af3626c3-cb8f-4231-a141-62f68ed97286','偈','釋圓濟','宋','宋诗','song-poetry','','[]','雨過山青，雲開月白。',20,'全唐诗/poet.song.79000.json','["雨過山青，雲開月白。", "带雪寒松，搖風庭柏。"]'),
('f0e6e40a-aa52-43dc-99ef-a30a9741a66c','偈','尼文照','宋','宋诗','song-poetry','','[]','靈源不動，妙體何依。',48,'全唐诗/poet.song.79000.json','["靈源不動，妙體何依。", "歷歷孤明，是誰光彩。", "若道真如實際，大似好肉剜瘡。", "更作祖意商量，正是迷頭認影。"]'),
('17d85e04-cb8f-4c01-8fee-28b77f8c4718','偈','釋王大夫','宋','宋诗','song-poetry','','[]','壇山裏，日何長。',40,'全唐诗/poet.song.79000.json','["壇山裏，日何長。", "青松嶺，白雲鄉，吟鳥啼猿作道場。", "散髪采薇歌又笑，從教人道野夫狂。"]'),
('d1fdc864-b959-49f0-9c08-7ef345522ebb','石勒城','孫渤','宋','宋诗','song-poetry','','[]','巀峰山峽間，有地窄如掌。',96,'全唐诗/poet.song.79000.json','["巀峰山峽間，有地窄如掌。", "雖得百二謀，磽確非沃壤。", "胡雛姿相異，圖慮似不廣。", "如何蟻封微，欲作南面享。", "孤城出雲層，遺址尚千丈。", "我來一把酒，慷慨追昔往。", "崛起亦奇才，晉室方骯臟。", "敢與南陽公，逐鹿中原上。"]'),
('af6e976b-848c-4df4-95e0-e534577131da','東巖','張稟','宋','宋诗','song-poetry','','[]','資中佳處是東巖，只在重城百百間。',32,'全唐诗/poet.song.79000.json','["資中佳處是東巖，只在重城百百間。", "四座清風無俗景，我心渾似白雲閑。"]'),
('8e4ebb05-ce21-46d6-8c13-0829171d2d1e','魏壇觀','陳虛中','宋','宋诗','song-poetry','','[]','夫人在兮若冰雪，夫人去兮仙蹤滅。',32,'全唐诗/poet.song.79000.json','["夫人在兮若冰雪，夫人去兮仙蹤滅。", "可惜如今學道人，羅裙带上同心結。"]'),
('a58ebf2a-dfda-494f-8e52-baeeb5d83aae','法相院','束長孺','宋','宋诗','song-poetry','','[]','解鞍得枕畫堂空，萬慮消沉午夢中。',64,'全唐诗/poet.song.79000.json','["解鞍得枕畫堂空，萬慮消沉午夢中。", "莫說紅塵飛白日，且從綠竹借清風。", "壁排琬琰詩無敵，殿鎖丹青筆有功。", "又觸炎蒸出門去，此生真愧坐禪翁。"]'),
('6d439b35-9874-4227-a798-118b625624ec','題巨然平湖舟泊圖','李時雍','宋','宋诗','song-poetry','','[]','遙岑矗矗水潺潺，茆屋松風晝掩關。',32,'全唐诗/poet.song.79000.json','["遙岑矗矗水潺潺，茆屋松風晝掩關。", "落日鐘聲來遠寺，行人初向石橋還。"]'),
('353d2a4a-229b-4210-9670-3cfc5986b445','題趙千里臥雪圖','李時雍','宋','宋诗','song-poetry','','[]','疏林茅屋掩閑雲，瀑雪懸崖霽色新。',32,'全唐诗/poet.song.79000.json','["疏林茅屋掩閑雲，瀑雪懸崖霽色新。", "好是杜陵詩興逸，蹇驢隨意樂行春。"]'),
('9cf43dd9-fdb9-4893-8041-74ed6f1f757a','題逍遙栖禪寺','唐遘','宋','宋诗','song-poetry','','[]','圭峰大士翻經處，雅俗今猶說草堂。',64,'全唐诗/poet.song.79000.json','["圭峰大士翻經處，雅俗今猶說草堂。", "十頃筠篁環殿閣，百年松檜老風霜。", "臨溪洗鉢憐僧野，卷旆搜山意資藏。", "試取禪詮滌五慮，蕭然心地頓清涼。"]'),
('c75fe2e3-fcc5-41a5-9f78-dad882d3818e','詩一首','楊虔誠','宋','宋诗','song-poetry','','[]','身在層霄第幾峰，煙霞深處一巖空。',64,'全唐诗/poet.song.79000.json','["身在層霄第幾峰，煙霞深處一巖空。", "上方世界簷楹外，萬里山河指掌中。", "蟾桂影交巖桂影，天燈紅映佛燈紅。", "芒鞋竹杖登臨處，煞是蓬萊有路通。"]'),
('e3fd568a-d853-42da-a0d5-202319234540','天柱巖','黄永思','宋','宋诗','song-poetry','','[]','幾載翹瞻玉柱峰，興來登陟欲凌空。',64,'全唐诗/poet.song.79000.json','["幾載翹瞻玉柱峰，興來登陟欲凌空。", "半天風月出塵表，大地山河入望中。", "晝色暗分巖樹綠，春光都入澗花紅。", "夜穴依舊天燈見，心事從來造物通。"]'),
('60a4840d-6f20-4437-9330-91a5a6d4f102','靜軒','張伯昌','宋','宋诗','song-poetry','','[]','靈鷲峰寒碧玉堆，紅塵斷處小軒開。',32,'全唐诗/poet.song.79000.json','["靈鷲峰寒碧玉堆，紅塵斷處小軒開。", "忘言更覺諸緣盡，只有桃花點翠苔。"]'),
('e7cc0bc5-1b5b-4e7f-951e-dd86ca8c9df3','歸雲洞','曹元振','宋','宋诗','song-poetry','','[]','石洞興衰亦歪風時，因師移錫致雲飛。',34,'全唐诗/poet.song.79000.json','["石洞興衰亦歪風時，因師移錫致雲飛。", "雲心莫道全無著，廣漠解從師去復歸。"]'),
('d1f7d0d9-adb9-49e5-8356-5cbd4e182b81','和吳拭暑雪軒詩','孫竢','宋','宋诗','song-poetry','','[]','地僻宜逃暑，官曹幸頗閑。',48,'全唐诗/poet.song.79000.json','["地僻宜逃暑，官曹幸頗閑。", "虛傳力士擔，始信蜀妃山。", "嶺雪青霄畔，城煙密樹間。", "清談容款接，妙句獨難攀。"]'),
('ca82c630-cde5-4202-8c4c-f02fc91bf58b','和田望再賦暑雪軒','孫竢','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','懶性難堪俗事侵，倚空欄檻列青岑。',64,'全唐诗/poet.song.79000.json','["懶性難堪俗事侵，倚空欄檻列青岑。", "雲端白雪凝高嶺，郭外長江繞茂林。", "疏曠幸陪文字飲，喧樓安用管絃音。", "北窻一枕羲皇夢，卻快微微風動襟。"]'),
('f5f91668-cd45-4f32-a4f2-6d9d51f74e56','和周燾合江亭  其一','孫竢','宋','宋诗','song-poetry','','[]','炎夏江風冷欲冰，坐陪袁謝有餘清。',64,'全唐诗/poet.song.79000.json','["炎夏江風冷欲冰，坐陪袁謝有餘清。", "舊聞蜀地四時雨，今快岷山千里晴。", "旋切銀絲嘗鱠味，聊欹玉枕聽灘聲。", "晚來忽起扁舟興，更傍中流看月行。"]'),
('3b251f8a-06d0-4abe-8432-f4bfc421d6e0','和周燾合江亭  其二','孫竢','宋','宋诗','song-poetry','','[]','西南都會錦官城，持節來尋漢客星。',64,'全唐诗/poet.song.79000.json','["西南都會錦官城，持節來尋漢客星。", "去國謾追千里馬，還家擬泛一帆舲。", "公才磊落宜方面，我病荒疏冒使令。", "未許東山同笑傲，勝遊聊可上丹青。"]'),
('1ae75389-2289-49c3-b58f-0c1ea3da2823','題東湖二首  其一','張毣','宋','宋诗','song-poetry','','[]','解慍薰風拂面涼，藕花極目送清香。',32,'全唐诗/poet.song.79000.json','["解慍薰風拂面涼，藕花極目送清香。", "三千宮女青羅蓋，都作酡顔酒暈妝。"]'),
('4e75bcc9-7fd9-4b2f-9f17-090e7a801b1f','題東湖二首  其二','張毣','宋','宋诗','song-poetry','','[]','蜀錦誰將到海涯，水仙鋪作地行衣。',32,'全唐诗/poet.song.79000.json','["蜀錦誰將到海涯，水仙鋪作地行衣。", "回堤卻似元宵路，拋擲紅燈載月歸。"]'),
('00abcf41-f603-4e09-8486-14d32b6d28b3','建炎丞相成國呂忠穆公退老堂  其一','侯彭老','宋','宋诗','song-poetry','','[]','姓名已冠凌煙閣，杖屨初臨退老堂。',64,'全唐诗/poet.song.79000.json','["姓名已冠凌煙閣，杖屨初臨退老堂。", "任重晉公游綠野，放懷忠獻醉安陽。", "園林選勝規模遠，丘壑偷閑氣味長。", "借箸更資恢復策，始應歸此樂時康。"]'),
('84f6c14d-80e1-4165-b095-4710917851d8','建炎丞相成國呂忠穆公退老堂  其二','侯彭老','宋','宋诗','song-poetry','','[]','扶出離明一洗光，懔然忠義合穹蒼。',64,'全唐诗/poet.song.79000.json','["扶出離明一洗光，懔然忠義合穹蒼。", "天教世祖中興漢，人服汾陽再造唐。", "道大耕莘同至樂，功成釣渭踵遺芳。", "身爲天下安危寄，未許清閑事退藏。"]'),
('bcb4b7e3-25d8-4793-97f9-7eaaf6eb3f3d','人日立春','侯彭老','宋','宋诗','song-poetry','','[]','朝來煮菜往鞭牛，已覺江邊雪意休。',64,'全唐诗/poet.song.79000.json','["朝來煮菜往鞭牛，已覺江邊雪意休。", "習習東風收雨腳，暄暄曉日綻雲頭。", "尊前未放梅花老，鬢上先看柳带柔。", "及取春花時一醉，莫教沈瘦更清秋。"]'),
('24f5e090-6f43-4ab9-b1c5-32cdc400ae6d','句','侯彭老','宋','宋诗','song-poetry','','[]','清絕洗妖氛。',6,'全唐诗/poet.song.79000.json','["清絕洗妖氛。"]'),
('37627846-9fcc-47f7-aff5-5454f8e37f91','句','王叡','宋','宋诗','song-poetry','','[]','莫怨工人醜畫身，莫嫌明主遣和親。',32,'全唐诗/poet.song.79000.json','["莫怨工人醜畫身，莫嫌明主遣和親。", "當時若不嫁胡虜，祇是宮中一舞人。"]'),
('db8b3c78-90be-4a95-92c3-5e0ebe5c3752','頌','殊勝院僧','宋','宋诗','song-poetry','','[]','我頌光明經，自得三昧力。',47,'全唐诗/poet.song.79000.json','["我頌光明經，自得三昧力。", "舉起便周圓，何用高聲覓。", "一日三百部，日輪猶未昃見者總生疑，我自心堅實。"]'),
('acfaeede-394f-441e-8fbc-9e5ec5e79c89','蒙亭倡和長句','張洵','宋','宋诗','song-poetry','','[]','桂林山水冠衡湘，蒙亭正在灕水傍。',144,'全唐诗/poet.song.79000.json','["桂林山水冠衡湘，蒙亭正在灕水傍。", "清流洄洑眩波光，高崖古木爭蒼蒼。", "下有菱荷滿橫塘，面面風來面面香。", "新詩一詠酒一觴，爽氣渾如秋氣涼。", "酒闌巖下踞胡牀，汲泉煮茗沉煙長。", "從容談笑聲瑯瑯，水光山色增輝芒。", "東山蘭亭各一方，風流兼追謝與王。", "回頭塵事皆茫茫，爲計不若行樂良。", "恨我到此情難忘，遙指白雲思故鄉。"]'),
('374cc896-fcdf-4d31-9e9c-000f7abe0c9a','呈郡寮  其一','楊灝','宋','宋诗','song-poetry','','[]','道院由來不浪傳，兩衙封印日蕭然。',32,'全唐诗/poet.song.79000.json','["道院由來不浪傳，兩衙封印日蕭然。", "絕無爭訟煩刑禁，贏得工夫弄簡編。"]'),
('9d704716-7544-4bdc-97f8-4a757211af8f','呈郡寮  其二','楊灝','宋','宋诗','song-poetry','','[]','山連吳楚周遭起，水合湖湘洶涌來。',32,'全唐诗/poet.song.79000.json','["山連吳楚周遭起，水合湖湘洶涌來。", "千里風煙同樂國，萬家歌吹共春臺。"]'),
('1dee908f-a3b4-4b09-9f4e-53cb5587d3a8','呈郡寮  其三','楊灝','宋','宋诗','song-poetry','','[]','寒煙淡淡水茫茫，六代纔如一夢長。',64,'全唐诗/poet.song.79000.json','["寒煙淡淡水茫茫，六代纔如一夢長。", "風月何嘗異今古，江山不管不興亡。", "豪華事往人安在，歌舞臺傾徑就荒。", "陳跡依然無處問，野花幽草自芬芳。"]'),
('3671443e-2488-4885-b2ca-31e40d6e2421','詠蝦蟆','汴京輕薄子','宋','宋诗','song-poetry','','[]','佳名標上苑，窩窟近天清。',48,'全唐诗/poet.song.79000.json','["佳名標上苑，窩窟近天清。", "道士行爲氣，梢工打作更。", "嘉言呼舍弟，東美是家兄。", "莫向南方去，將君煮作羹。"]'),
('39a69e8d-c62b-42c4-b653-ec1c1321b258','詩一首','崇寧名賢','宋','宋诗','song-poetry','','[]','十家來負郭，四邑入提封。',24,'全唐诗/poet.song.79000.json','["十家來負郭，四邑入提封。", "雙水碧一色，群山青萬重。"]'),
('8a1cf190-e882-4db0-abc8-632223e0122e','賦陳虚中振芳堂','謝薖','宋','宋诗','song-poetry','','[]','青腰按節臨天關，幻成圭璧驚人寰。',128,'全唐诗/poet.song.79000.json','["青腰按節臨天關，幻成圭璧驚人寰。", "一朝忽起枯槁想，墮作人間冰雪顔。", "國香端擬避清絕，鳯車安得窺幽閑。", "雪中長疑肌起粟，挽住直恐乘風還。", "風流别乘似何遜，哦詩興健排江山。", "華堂燒燈呼客醉，况引玉頬依琱闌。", "廣平題賦工婉媚，杜陵索句愁飛翻。", "山人徑欲悟香寂，何當步繞横斜間。"]'),
('5fa4bdbc-f1eb-4225-b7a7-3f218778ef38','雙蓮閣','謝薖','宋','宋诗','song-poetry','','[]','水芝凝露披芳塘，淺粧濃畫争煌煌。',128,'全唐诗/poet.song.79000.json','["水芝凝露披芳塘，淺粧濃畫争煌煌。", "其間艶異不世出，連芳並蒂知何祥。", "有如一座兩殊色，盈盈植立漢昭陽。", "九回沉水不須沐，風生露洗皆生香。", "公如瑶林映紅粉，粲然一笑傾澄觴。", "故開華閣掛銀榜，大篇金薤垂琳琅。", "吾聞草木正瑞世，箑蒲扇暑芝生房。", "須煩丹青頋陸手，貎取絕艶歸明光。"]'),
('3b366125-2b4d-4771-86d3-39a8811c8a9a','三益齋','謝薖','宋','宋诗','song-poetry','','[]','元龍湖海豪，蓋代聲藉藉。',120,'全唐诗/poet.song.79000.json','["元龍湖海豪，蓋代聲藉藉。", "只今觀耳孫，才皆萬夫敵。", "叔兮美無度，伯也古遺直。", "當年種玉翁，十襲裹雙璧。", "期公垂天雲，佐郡試戢翼。", "尚開柴桑徑，引領望三益。", "嘗聞築燕臺，千里走樂劇。", "市骨捐千金，廐乘盡虎跡。", "公乃真好事，屣履見逢掖。", "定知子輿輩，一笑皆莫逆。"]'),
('8de4db91-df97-4951-b198-0b4991f2e2c1','顔魯公祠堂','謝薖','宋','宋诗','song-poetry','','[]','上皇御宇無長策，牧羊奴子孤恩澤。',144,'全唐诗/poet.song.79000.json','["上皇御宇無長策，牧羊奴子孤恩澤。", "銀莬分印屬兒曹，二十餘州盡陷賊。", "常山死守平原拒，公家兄弟聲名白。", "平原白首立班行，忠義凛凛真嚴霜。", "歷事四朝唯一節，當年舌舐中丞血。", "豈知丞相面如藍，貎雖夷易心巉岩。", "老臣何罪死虎口，到今誰爲祛其銜。", "臨風志士長悲吒，矧瞻遺像嚴祠下。", "未能立草迎送詞，一奠椒漿淚盈把。"]'),
('6fcc62f8-fd02-44ae-99a9-2e427d4c9826','十八學士寫真圖','謝薖','宋','宋诗','song-poetry','','[]','虬髯少年龍鳯姿，手提一劍平九維。',112,'全唐诗/poet.song.79000.json','["虬髯少年龍鳯姿，手提一劍平九維。", "瀛洲學士十八輩，如雕虎嘯清風隨。", "到今丰姿傳粉繪，皎如琪木參瓊枝。", "秦王功高蓋天下，脫略世故容小疵。", "数公不語意有在，敬宗流輩寧何知。", "倘收王魏文學舘，事如辰嬴當早諫。", "美哉貞觀猶有恨，洗蘇衆像一長嘆。"]'),
('b2b2aeea-916f-426d-9766-21ee11bf1b87','靜寄齋觀文忠公墨跡','謝薖','宋','宋诗','song-poetry','','[]','董何呼我顛倒裳，杖藜階西過王郎。',176,'全唐诗/poet.song.79000.json','["董何呼我顛倒裳，杖藜階西過王郎。", "郎君好事初舉觴，平頭奴子舁兩囊。", "開視文書浩搶攘，其間穅秕煩播颺。", "忽驚墨妙筵有光，問誰所書曰歐陽。", "而我盥水方取将，覽之三過神色揚。", "反嗟從來見未嘗，字體遒媚笔意剛。", "公爲文章軋子長，立朝義氣凛秋霜。", "借如春蚓縈行行，亦當珍之十襲藏。", "况工字畫乃如此，銀鈎金繩粲繭紙。", "公嘗臨池墨池水，尚言如船逆風使。", "後來誰評新麗體，出公一頭子蘇子。"]'),
('bba37563-cfc4-4262-accf-ab2e2d6a27bd','與諸友汲同樂泉烹黄蘗新芽','謝薖','宋','宋诗','song-poetry','','[]','尋山擬三餐，放箸欣一飽。',72,'全唐诗/poet.song.79000.json','["尋山擬三餐，放箸欣一飽。", "汲泉泣銅瓶，落磑砕鷹爪。", "長爲山中遊，頗與世路抝。", "矧此好古胸，茗椀得搜攪。", "風生覺泠泠，祛滯亦稍稍。", "夜深可無睡，澄潭数參昴。"]'),
('d3c642a8-e3c8-4607-bea4-7f7a8dfb5069','讀吕居仁詩','謝薖','宋','宋诗','song-poetry','','[]','吾宗宣城守，詩壓顔鮑輩。',168,'全唐诗/poet.song.79000.json','["吾宗宣城守，詩壓顔鮑輩。", "其間警拔句，江練與霞綺。", "居仁相家子，歛退若寒士。", "學道期日損，哦詩亦能事。", "自言得活法，尚恐宣城未。", "今晨開草堂，書帙亂無次。", "探囊得君詩，疾讀過三四。", "淺詩如蜜甜，中邊本無二。", "好詩初無奇，把玩久彌麗。", "有如菴摩勒，苦盡得甘味。", "徐侯南州傑，論文極根抵。", "讀君詩卷終，曰此有餘地。", "期君高無上，二謝以平視。", "要當掣鯨魚，豈但看翡翠。"]'),
('de6f1420-0f41-495a-b3ee-bf94fe17e642','王坦夫静寄齋','謝薖','宋','宋诗','song-poetry','','[]','狙猴在深山，騰踔不少停。',144,'全唐诗/poet.song.79000.json','["狙猴在深山，騰踔不少停。", "大龜藏神屋，縮首都無營。", "冥觀静躁異，洞見萬物情。", "吾聞子王子，總角遊帝城。", "歸來髩猶綠，閉關慕淵明。", "曲肱北窗下，風聲肅泠泠。", "夢覺忽驚起，猶疑車轂鳴。", "齋居屏萬慮，乃以靜寄名。", "是中得其趣，君門可長扃。", "倘知定能應，子冠定能纓。", "鏡以靜故明，水以静故平。", "兹言置座右，可配崔瑗銘。"]'),
('1771f5cd-8b84-4bba-a9b1-df81b178656e','示何之忱','謝薖','宋','宋诗','song-poetry','','[]','往年君别去，上馬愁凛冽。',180,'全唐诗/poet.song.79000.json','["往年君别去，上馬愁凛冽。", "今年見君面，揮汗驚執熱。", "吾曹雪點髩，忽忽值晚節。", "云何會心侣，乃作如許别。", "昨朝聞扣門，梳髪不暇結。", "開門問無恙，欲語聲屢咽。", "君家嬌小女，可念真玉雪。", "朝嬉繞君傍，忽作泡幻滅。", "念我溪堂老，誰能續此絕。", "嗟哉溪澗毛，瑣細不容擷。", "相逢顔未開，苦語心已折。", "吾人要解事，視世一蟻垤。", "共将煩惱緣，一付廣長舌。", "君歸数過我，不厭酒屢設。", "人生浪自苦，豈不愧前喆。"]'),
('57412050-c7d8-442b-8e7c-08343e822082','哭董彦孚','謝薖','宋','宋诗','song-poetry','','[]','川流日夜去，逝者乃如此。',144,'全唐诗/poet.song.79000.json','["川流日夜去，逝者乃如此。", "平時所知人，强半今爲鬼。", "頃者哭子兄，淚積垢未洗。", "寧知少日間，俄又哭董子。", "憶昨招君談，時維六月朏。", "君方以病告，一臥不復起。", "啓手無别言，慟哭長已矣。", "初君在童丱，警敏無與比。", "讀書五行下，大父嘗竊喜。", "謂當寄門户，竟以韋布死。", "死生事亦大，誰能獨免耳。", "願沾甘露味，倘悟無生理。"]'),
('f0246458-522a-49f4-8560-e503e0302199','歲将除因誦前賢粲字韻詩慨然有感次其韻請彦光同賦蓋予與彦光皆年三十九矣','謝薖','宋','宋诗','song-poetry','','[]','舂粮適百里，九十居其半。',192,'全唐诗/poet.song.79000.json','["舂粮適百里，九十居其半。", "駸駸入老境，競起末路嘆。", "在世無他能，聊以滑稽玩。", "所嗟金石交，契闊或星散。", "詩憶西堂語，酒藉南鄰伴。", "共爲終年醉，莫歌何時旦。", "文書謾遮眼，插架復盈案。", "四愁不堪擬，九歌僅能亂。", "發春只数日，故態期類盥。", "寧知性本慵，矧復肉亦緩。", "人猶樂新故，事止仍舊貫。", "酸寒孟生窮，歛退韓子懦。", "惜哉連城珍，不變三日炭。", "玉人可求見，何暇定舍舘。", "退藏亟聞道，飲水知冷暖。", "更當崇明德，不愧三英粲。"]'),
('a5fe7fbc-7963-42c7-be85-68ae92714b38','復用前韻示內','謝薖','宋','宋诗','song-poetry','','[]','嘗聞藁砧詞，破鏡喻月半。',192,'全唐诗/poet.song.79000.json','["嘗聞藁砧詞，破鏡喻月半。", "爲期望夫還，頋影興婦嘆。", "乃知同室處，一笑日可玩。", "所悲孩抱中，聚沬何易散。", "嘹然唯一雛，单棲若無伴。", "撫枕中夜吁，不寐常達旦。", "藜羮具一杯，日舉天隨案。", "還勝在板屋，秪使心曲亂。", "小鬟維槁項，聊可奉擲盥。", "每觀績麻手，捷急真不緩。", "娉婷或階楇，今古同一貫。", "頗知食薇清，凛凛可立懦。", "仍甘作詩窮，烏銀以喻炭。", "行看春日暄，婦事勤繭館。", "所求亦不奢，勿遣兒號暖。", "布衾幸無恙，不换角枕粲。"]'),
('f0129421-5c84-42b4-b5e3-f08850759794','送董彦速遊仙岩','謝薖','宋','宋诗','song-poetry','','[]','吾聞天竺峰，聳若在天上。',96,'全唐诗/poet.song.79000.json','["吾聞天竺峰，聳若在天上。", "峰前溪萬仞，激石吼寒浪。", "堂中老比丘，碧眼照林莾。", "徜徉君屢遊，局趣我思往。", "此行何所求，豈欲除二障。", "聞呼試回頭，未可踏折杖。", "茅檐燕寂地，山氣日夜爽。", "不斬凌霄藤，君歸藤自長。"]'),
('68ad46bb-9260-4610-8119-09827191d30a','寄題雲臥菴','謝薖','宋','宋诗','song-poetry','','[]','閒居不事事，枕簟信所便。',132,'全唐诗/poet.song.79000.json','["閒居不事事，枕簟信所便。", "臥形先臥心，心静形晏然。", "複壁非不完，加以甃石堅。", "其如方寸亂，一夕嘗屢遷。", "榮寵萃一門，寧免百慮煎。", "雖有水精屏，何由得安眠。", "章葉踏謡娘，連臂在榻前。", "何如山中人，編茅臥山巔。", "白雲宿簷間，對鏡心自捐。", "我亦遺垢氛，曲肱寄林泉。", "兹菴倘壽我，一睡要經年。"]'),
('186a3d0e-de15-439e-980e-a1bcafc2f66a','初夏觀園中草木','謝薖','宋','宋诗','song-poetry','','[]','翠葉蕃夏初，清陰勝花時。',156,'全唐诗/poet.song.79000.json','["翠葉蕃夏初，清陰勝花時。", "閉關軌長埽，步屧園屢窺。", "青青溪中蒲，移植井之湄。", "下有九節根，服食可不迷。", "往時手種桃，只今與簷齊。", "枝間有美實，少日将成蹊。", "採菊香滿襜，擷薺甘如飴。", "籜龍露新綠，椅梧長孫枝。", "觀身要若蕉，衞足當如葵。", "節憐孤筠直，惡戒蔓草滋。", "天津白玉郎，看花驚洛師。", "吾人守環堵，草木相娛嬉。", "逍遥各自適，慎勿相唐嗤。"]'),
('5316aef9-ec86-4f25-9553-16af77dda85b','次董彦速示輪老韻三首  其一','謝薖','宋','宋诗','song-poetry','','[]','法涌僧中鸞，孤絕翔千仞。',48,'全唐诗/poet.song.79000.json','["法涌僧中鸞，孤絕翔千仞。", "似聞天竺老，續此燈無盡。", "君遊千峰上，邂逅一笑哂。", "當知絕諸惡，如草已芟藴。"]'),
('88875bb5-8ab6-455e-8c2c-9d8e700c8e61','次董彦速示輪老韻三首  其二','謝薖','宋','宋诗','song-poetry','','[]','君如千里駒，但欲見鞭影。',48,'全唐诗/poet.song.79000.json','["君如千里駒，但欲見鞭影。", "既明才越都，未暮已燕境。", "適楚或北轅，空歎道里永。", "是中皆坦途，幽處試深省。"]'),
('8c03c0ec-58ab-46aa-b3de-46d2e9635686','次董彦速示輪老韻三首  其三','謝薖','宋','宋诗','song-poetry','','[]','黄花散若金，翠竹森如束。',48,'全唐诗/poet.song.79000.json','["黄花散若金，翠竹森如束。", "此還有妙義，機發同箭速。", "可憐鈍根士，每嗟力不足。", "須知日月疾，僅得羊胛熟。"]'),
('53600a21-172e-4b26-aa48-5bcb73b05363','食藕','謝薖','宋','宋诗','song-poetry','','[]','人憐淤泥上，出此萬朵蓮。',168,'全唐诗/poet.song.79000.json','["人憐淤泥上，出此萬朵蓮。", "須知淤泥中，有藕大如椽。", "本清凝冰雪，末艶方婵娟。", "玲瓏衆竅通，蚴蟉数節連。", "甘寒固不数，却暑最所便。", "髯奴來城市，負籠至我前。", "開緘尚带泥，未嚼先垂涎。", "霍霍摩霜刀，雷雷挹澗泉。", "切玉墮冷冽，已覺沉疴痊。", "芰寔閗角紫，鴻頭剥珠圓。", "秋盤薦此果，頓使二物捐。", "念此湼不緇，餘品莫爭妍。", "而能豁憂思，令我心歡然。", "奇功更耐老，合作飛行仙。"]'),
('d1fc0ee5-9c36-4455-b5a7-b429a0139e92','翠雲道中觀穫','謝薖','宋','宋诗','song-poetry','','[]','代田誰爲西漢議，耐旱幸有占城禾。',64,'全唐诗/poet.song.79000.json','["代田誰爲西漢議，耐旱幸有占城禾。", "揮鐮正見八月穫，拾穗遥憐一老歌。", "爲言使君驅五馬，北陌東阡餉耕者。", "汝曹力穡更當勤，慎勿惰遊辜使君。"]'),
('3932010b-0a7f-43d0-855e-f0db8e0ecc2d','喜劉世基至作詩留之','謝薖','宋','宋诗','song-poetry','','[]','君家飛猿西，我寄躍馬北。',240,'全唐诗/poet.song.79000.json','["君家飛猿西，我寄躍馬北。", "躍馬望飛猿，渺若千山隔。", "十載一會面，一年三寄書。", "書中無剩語，只有問何如。", "去年秋風初，君馬秣雲臥。", "鶴立望君來，因鞭不我過。", "今年薰風後，取道凌雲來。", "解鞍愒我廬，握手慰我懷。", "胸中所藴藏，言下皆傾倒。", "挽留莫怱怱，索去還草草。", "堂有鶴髪母，室有蓬首妻。", "屋前虎豹怒，屋後鼯鼪啼。", "遠遊縱未歸，旅寓安得久。", "三年勞夢魂，一日接盃酒。", "君歸太早計，此樂未易辭。", "人事雖好乖，興盡當語離。", "壮時須摩厲，老矣但跛挈。", "荃蘭本同芳，霜雪有一節。", "君哦飛猿句，我和躍馬詩。", "它時兩相寄，抑亦慰相思。"]'),
('3067eedf-088f-404b-b5f6-89d3cbe7dc54','中秋示座客','謝薖','宋','宋诗','song-poetry','','[]','去年中秋時，我病起復仆。',168,'全唐诗/poet.song.79000.json','["去年中秋時，我病起復仆。", "苦遭水帝子，百計推不去。", "床前客問病，草草壺觴具。", "酬献呼稚子，應答煩老嫗。", "今年幸强健，佳節欣會遇。", "况有座上客，蕭散如鷗鷺。", "尊前清興發，豈数青蚊聚。", "南山又朝隮，晚雨細如霧。", "難追阿連玩，徒咏希逸賦。", "陰晴天下同，吾事亦何預。", "不須淵有珠，遑恤食無免。", "人無百中秋，對月復幾度。", "幸逢方外交，姑樂酒中趣。", "君看清夜徂，草上已多露。"]'),
('fd00a3a7-92c8-41db-8002-41762ecb1662','雨後秋山','謝薖','宋','宋诗','song-poetry','','[]','宿雲散曾陰，秀色還疊障。',84,'全唐诗/poet.song.79000.json','["宿雲散曾陰，秀色還疊障。", "如将螺子綠，畫作長蛾樣。", "光浮竹木杪，影落簷楹上。", "何人妙盤礴，淡墨寫屏嶂。", "五絃豈須撫，衆響亦清亮。", "我病不出遊，素壁倚藤杖。", "舉觴酹郡峰，歲晚一相訪。"]'),
('bbd5aa11-86a9-4803-baf8-93edc4682b07','種松','謝薖','宋','宋诗','song-poetry','','[]','清晨課僕奴，遶舍誅蒿蓬。',120,'全唐诗/poet.song.79000.json','["清晨課僕奴，遶舍誅蒿蓬。", "身非郭槖駝，學作種樹翁。", "胡不種杞柳，但種青青松。", "念汝受命獨，勁氣凌三冬。", "明年見汝生，何年矯蒼龍。", "種德亦吾願，穆如松上風。", "安知百載後，無人思角弓。", "麦陰行可賴，不必荒茅中。", "唯當護以棘，養視如嬰童。", "此法豈浪傳，聞諸玉局公。"]'),
('059e237d-e4e8-40a5-8192-48ad0598597c','同董彦光陳妙音遊安樂寺分韻  其一','謝薖','宋','宋诗','song-poetry','','[]','着鞭蒼崖陰，下馬古寺門。',60,'全唐诗/poet.song.79000.json','["着鞭蒼崖陰，下馬古寺門。", "老僧乞食去，獨瞻無上尊。", "相将二玉人，盤礴共一罇。", "境静悟塵垢，林香識蘭孫。", "何年缽羅老，同訪花柳村。"]'),
('a8a4264c-0f13-4028-890f-be5f319928d4','同董彦光陳妙音遊安樂寺分韻  其二','謝薖','宋','宋诗','song-poetry','','[]','鳥能貫珠歌，花能折腰舞。',60,'全唐诗/poet.song.79000.json','["鳥能貫珠歌，花能折腰舞。", "老人如帝江，識此真律吕。", "撃節復長謡，急觴猶插羽。", "春風已趣装，行樂更幾許。", "吾人但取醉，何必浪自苦。"]'),
('265e8374-beff-4429-8aba-f17ee9db745a','聞彦光田舍遇火幾焚其廪','謝薖','宋','宋诗','song-poetry','','[]','睡龍未覺山澤枯，其誰濡幙待不虞。',144,'全唐诗/poet.song.79000.json','["睡龍未覺山澤枯，其誰濡幙待不虞。", "炎官弭節飛廉怒，小屋旋徹大屋塗。", "鬱攸飛空百鳥噪，煇赫照樹騰猿呼。", "綠林灰燼一瞬耳，况乃田父蝸牛廬。", "天公似惜詩人癯，約束風伯爲回車。", "百神救廪鳥工往，不待綆缶澆焚如。", "尚令太痩逢飯顆，幸未饑死同侏儒。", "怪奇敢追陸渾韻，弔賀不必參元書。", "作詩嘲誚供一笑，逢人舉似應胡盧。"]'),
('e78b8c28-d2b5-44e7-b3a5-d9240da14f9c','許巨源送笋','謝薖','宋','宋诗','song-poetry','','[]','君家遶屋青琅玕，驚雷裂地千兵攅。',117,'全唐诗/poet.song.79000.json','["君家遶屋青琅玕，驚雷裂地千兵攅。", "入山長鑱不汝赦，日獲玉版登君盤。", "有餘鼠壤幸分似，憐我羮稀筯易寬。", "厨人取給晝餔膳，頓使齒頬生甘寒。", "韭葅薤苗豈復数，{炙火=肉}美似覺無貛貛。", "嘗聞幽士愛風竹，忍嘬其子吾何觀。", "願君養成四時葉，他時犯雪同君看。"]'),
('058ab403-5f88-4662-9c10-c58ea53b1a8b','灌園','謝薖','宋','宋诗','song-poetry','','[]','春初韭爭妍，秋末菘更好。',108,'全唐诗/poet.song.79000.json','["春初韭爭妍，秋末菘更好。", "嗟我喜蔬食，如人嗜羊棗。", "何嘗厭滋味，政自樂枯槁。", "念彼蝡蠢蟲，性命欲自保。", "變相驚蜊異，将糖嫌蟹躁。", "故于園日涉，蒔此可食草。", "邇來秋雨餘，三畝淨如掃。", "畦丁猶浸灌，小甕亦自抱。", "問許機事忘，何如漢陰老。"]'),
('5c825fb3-ea31-450a-baef-17f76d9f95aa','題頋凱之醉道士圖','謝薖','宋','宋诗','song-poetry','','[]','虎頭癡絕自不癡，丹青妙處手得之。',112,'全唐诗/poet.song.79000.json','["虎頭癡絕自不癡，丹青妙處手得之。", "石巖戱畫幼輿了，酒狂更貎黄冠師。", "一人坐睡真被酒，二人杯杓不停手。", "一人回面愁不釂，二人直視開口笑。", "上有醉墨書者誰，翰林手題獨酌詩。", "題詩真識醉時味，畫圖如寫詩中意。", "珍藏不换一斛珠，李詩頋笔今世無。"]'),
('7e28358d-bf61-4438-9711-d4b81fff486d','題文與可畫竹','謝薖','宋','宋诗','song-poetry','','[]','我昔居西園，手植竹数箇。',122,'全唐诗/poet.song.79000.json','["我昔居西園，手植竹数箇。", "凜然如德友，節行不敢破。", "朝吟玩霜枝，夜聞蕭瑟清。", "風吹一旦忽不見，似覺塵土污人衣。", "朅來翠雲麓，日唯見山不見竹。", "雖云山氣日夕佳，尚恐無竹令人俗。", "昨得與可畫，自歸塵壁掛。", "門開風動之，如枉故人駕。", "對山看畫信不惡，何人更覓揚州鶴。"]'),
('8c0774e2-0968-4d3f-93c4-6d3bc1b30ca3','寄孫子稷','謝薖','宋','宋诗','song-poetry','','[]','我家大馮君，清詩跨陰何。',132,'全唐诗/poet.song.79000.json','["我家大馮君，清詩跨陰何。", "尤工婕妤怨，不愧青草歌。", "後生遊其門，玉石例琢磨。", "是中知味少，莫辨白黑鵝。", "獨聞子孫子，鏘然應鸞和。", "君嘗喜其似，謂可同臼科。", "劍池佳山水，清漣映嵯峨。", "孫子居山間，新詩日吟哦。", "探囊肯投我，有篇未爲多。", "論文定何時，一醉金叵羅。", "更當期皓首，共理釣魚簑。"]'),
('d08ee610-4133-417c-aebc-528791971196','登同樂亭飲泉','謝薖','宋','宋诗','song-poetry','','[]','何人愛斯泉，結搆亭上屋。',72,'全唐诗/poet.song.79000.json','["何人愛斯泉，結搆亭上屋。", "空亭何所有，冷氣宜三伏。", "泠泠石甃淨，鬚眉真可矚。", "欲飲無樽罍，挹彼纔盈掬。", "何時近亭居，更種亭畔菊。", "日飲潭中甘，庶用稽死錄。"]'),
('3628f08c-3fba-4907-9932-957df13b900b','吳民載棄意堂','謝薖','宋','宋诗','song-poetry','','[]','此身聚沫無堅强，斧工伐性藥腐膓。',120,'全唐诗/poet.song.79000.json','["此身聚沫無堅强，斧工伐性藥腐膓。", "寸田蕪穢尺宅荒，玉石落落不滿房。", "黄婆居中補四方，焦勞亦坐意所藏。", "土如磽瘠草不芳，令人槁項馘亦黄。", "世人紛紛各膏肓，我以妙語名斯堂。", "期君得意觀濠梁，從渠婪酣狠如羊。", "君自放意無何鄉，一洗痼疾生天光，漆園發藥君得嘗。"]'),
('f73d6c9a-1ba1-47cd-aba8-08c84ff0ffc7','次董彦光乞米韻','謝薖','宋','宋诗','song-poetry','','[]','董侯朝饑雷殷腹，咄嗟無人羞豆粥。',64,'全唐诗/poet.song.79000.json','["董侯朝饑雷殷腹，咄嗟無人羞豆粥。", "杜陵太瘦緣作詩，玉川辛勤坐憎俗。", "細君截髪恐未暇，有弟能令餉君粟。", "不妨更就乞檳榔，他日金柈供一斛。"]'),
('1aa27709-302c-4807-9aad-f5f8d7e2689c','分韻招無逸兄得益字','謝薖','宋','宋诗','song-poetry','','[]','長懷烏衣遊，親姓何戚戚。',144,'全唐诗/poet.song.79000.json','["長懷烏衣遊，親姓何戚戚。", "吾曹乃其後，何不迨往迹。", "向來鴻雁影，曠若參辰隔。", "沉思不可見，佇立久悽惻。", "去年霜霰中，送别衢路側。", "今年冬風至，猶未見顔色。", "念我如楚囚，欲往終未得。", "倘能爲我來，不遠道里百。", "要觀衡茅下，有此座上客。", "新釀秋已熟，老菊寒尚拆。", "彌年心拂鬱，可以一笑釋。", "仍當戒後乘，聯翩載三益。"]'),
('533560ac-bf3b-4075-8323-33c5870a0728','翠雲分韻得禪字','謝薖','宋','宋诗','song-poetry','','[]','杖履信所適，溪流忽濺濺。',156,'全唐诗/poet.song.79000.json','["杖履信所適，溪流忽濺濺。", "行入武陵村，偶入桃花源。", "劃然見華屋，佛界開青蓮。", "匆匆伊蒲饌，一餉腹果然。", "同遊得吾黨，曠達真能賢。", "董何韻俱勝，欲拍諸阮肩。", "兩王亦豪舉，一擲常萬錢。", "周郎秀眉宇，要是佳少年。", "衆中兀老子，少味亦寡言。", "困眠借僧榻，自嘲邊腹便。", "平時所懷人，磊落星辰懸。", "會合不易得，兹遊豈非天。", "重來恐寡伴，獨訪祖師禅。"]'),
('36f82c9d-bc73-49d8-a447-b45371427630','次劉世基韻','謝薖','宋','宋诗','song-poetry','','[]','兒時窺豹見一斑，晚學一技千金殚。',224,'全唐诗/poet.song.79000.json','["兒時窺豹見一斑，晚學一技千金殚。", "齋房芝草不竝秀，且餐秋菊紉春蘭。", "無心時共白雲出，忘機日對沙鷗閒。", "窮人與世各異調，敢望一唱仍三嘆。", "昨來卜居向巖邑，玉川破屋纔数間。", "朝看爽氣出遠岫，夜聽遶舍鳴清湍。", "幾回欲棹酒船去，賀老不見空稽山。", "劉郎好事肯過我，入門矯矯真翔鸞。", "平生飲客愁腐死，望君復來酒今旨。", "君如止酒要談道，同酌寒泉淨無滓。", "哦詩雖復落君後，强學猶将效矉里。", "懸知吾廬不落莫，有客同盤飯葵藿。", "已呼摻手縫錦囊，更遣長鬚具芒屩。", "相携踏遍翠雲峰，得助溪山應有作。"]'),
('c6270942-33d9-4556-968b-a5f67d661205','王摩詰四時山水圖','謝薖','宋','宋诗','song-poetry','','[]','欲知摩詰詩中畫，桃紅柳綠皆摹寫。',128,'全唐诗/poet.song.79000.json','["欲知摩詰詩中畫，桃紅柳綠皆摹寫。", "更含宿雨带春烟，一叚風光生筆下。", "欲觀摩詰畫中詩，小幅短短作四時。", "山平水遠含變態，是中有句無人知。", "此公盤礴萬物表，胸中炯炯秋空曉。", "戱磨淡墨汙絹素，世上丹青擅場少。", "何人乞與輞川圖，装成小軸四時俱。", "壁間仍題六字句，人言雙絕古今無。"]'),
('f1391170-3ede-4f6f-b506-12629488213a','同陳虚中洪駒父登擬峴臺觀水漲','謝薖','宋','宋诗','song-poetry','','[]','雨聲何浪浪，溪流勢洶洶。',144,'全唐诗/poet.song.79000.json','["雨聲何浪浪，溪流勢洶洶。", "莽蒼兩涘間，不辨馬牛風。", "翻疑坤軸裂，渺與天河通。", "林杪露寸碧，濁浪奔蛟龍。", "櫓摇扁舟下，袖手閒篙工。", "疏烟媚晚霽，飛雲带歸鴻。", "境物復可寫，妙手無僧崇。", "登兹百尺臺，令人豁奇胸。", "罇開河南守，坐有西山洪。", "遊目託遠懷，平水念禹功。", "視河不治行，他日望兩公。", "吾儕何所樂，白着臥船篷。"]'),
('10afba43-5ef4-4453-af25-bef502e5a2c9','送邑尉朱登仕告老歸華亭用玉局老仙寄王慶源韻','謝薖','宋','宋诗','song-poetry','','[]','君不能黄冠還鄉乞鑑湖，又不能拏舟送米煩胡奴。',166,'全唐诗/poet.song.79000.json','["君不能黄冠還鄉乞鑑湖，又不能拏舟送米煩胡奴。", "白頭真負平生志，妙年毫端敵萬夫。", "向來惡少虎負嵎，職當疾走編其鬚。", "袴鞾不是老者事，腰間羽箭吾初無。", "揮盃勸影古寺底，日有野老争携壺。", "頗遭官長勸歸歟，婦能右擯兒左扶。", "但令妻病足鹿脯，何憂兒寒止熨襦。", "蓴絲作羮塩未下，鱸鱠切玉秋不癯。", "華亭自昔託鶴唳，蕙帳後夜聞猿呼。", "不羡人間冶容子，團圓十五正當壚。"]'),
('18556323-6233-4adc-93c9-3f1f237b2971','晏如堂詩','謝薖','宋','宋诗','song-poetry','','[]','西都執戟郎，田少家無儲。',210,'全唐诗/poet.song.79000.json','["西都執戟郎，田少家無儲。", "雖云貧賤不戚戚，著書防患何多虞。", "柴桑避俗翁，寝迹安吾廬。", "如何尚作貧士詠，更賦楚調長嗟吁。", "乃知兩賢蒿目憂世患，不如先生無目自晏如。", "朝哦詩千首，暮對酒一壺。", "木蘭能歌作行雨，但聞龐婆時誦園田居。", "閑携笻竹自索塗，醉或起舞嗔人扶。", "幅巾深衣端可畫，每嘆伯時何在無人圖。", "往日山陽徐仲車，不聞世事唯躭書。", "使君早興合堂坐，誇今弹古定自娛。", "徐能開口論事以難客，君當書空作字以曉徐。", "吾知二人可同傳，不知紬書太史今誰歟。"]'),
('b3e5a3f1-2385-4bb0-bd94-8c6f951f6ec5','題吕隆禮詩後','謝薖','宋','宋诗','song-poetry','','[]','岐山鳯多雛，鳴必中律吕。',84,'全唐诗/poet.song.79000.json','["岐山鳯多雛，鳴必中律吕。", "乃知忠厚家，要作謙退語。", "申公二世後，有子筆甚武。", "四公如日月，映照萬萬古。", "此郎膽如斗，一筆要連拄。", "不知秦陳輩，渠欲置何許。", "他年品斯人，戰國一豪舉。"]'),
('73db392a-cc72-4b9f-9f96-29d87a3e54f1','次洪駒父遊明水韻','謝薖','宋','宋诗','song-poetry','','[]','薖也學耐辱，况負三宜休。',204,'全唐诗/poet.song.79000.json','["薖也學耐辱，况負三宜休。", "頗有幼輿風，自許壑與丘。", "仙境想方丈，山形懷不周。", "如何在眼山，未暇着屐遊。", "蓊鬰明水峰，爽氣常不收。", "遜公釋門老，苦節無匹儔。", "食訖自灌畦，挈水端若抽。", "到今巾屐在，迹勝境亦幽。", "嘗評左轓賢，當從古人求。", "從政獨何有，未說賜與由。", "勸耕遍阡陌，民歌殖田疇。", "幽尋到山寺，弭節聊滯留。", "衆賓各文采，粲粲五楘輈。", "賦詩雜流麗，如柳春映溝。", "何必打兩槳，歌舞催莫愁。", "聞風我滋悅，尋勝行且謀。", "朝遊可暮返，豈曰山川悠。"]'),
('bdc3875d-16f8-46d0-8cd3-85f155512166','咏二疏','謝薖','宋','宋诗','song-poetry','','[]','辯如懸河陸大夫，不畏嫚罵談詩書。',165,'全唐诗/poet.song.79000.json','["辯如懸河陸大夫，不畏嫚罵談詩書。", "歸來分槖養群雛，隨從歌舞樂有餘。", "兩疏高蹈要齊驅，長揖儲君歸里閭。", "願爲羽翼還商於，豈願飛刀繪生魚。", "揮金延客以自娛，子孫勤力舊田廬。", "同時異代多不如，高明長遭鬼揶揄。", "平明爭入七香車，華屋擬用黄金塗。", "壮心雖在迫桑榆，長歌擊碎玉唾壺。", "宦成名立盍歸歟，江湖之士可胥疏。", "君不見渠家父子並轡出，東都于今粉繪寫爲圖。"]'),
('bbefd48c-6952-4d1b-a685-4c3f20a29432','集庵摩勒園會者十人以它年五君詠山王一時数爲韻得時字','謝薖','宋','宋诗','song-poetry','','[]','生涯水中萍，漂蕩信所之。',132,'全唐诗/poet.song.79000.json','["生涯水中萍，漂蕩信所之。", "十年餬其口，不食故園葵。", "思歸同越鳥，長是巢南枝。", "祭竈郭北隅，小屋如雞棲。", "園開十肘地，草木方華滋。", "紅榴媚夕陽，初篁摇輕颸。", "招我賞心舊，於焉持酒巵。", "合離如日月，果有弦望時。", "詩壇失老将，一鼓氣已衰。", "賴我如虎賁，典刑猶在兹。", "相歡且盡醉，莫詠驪駒詩。"]'),
('467ff6bd-d523-43b7-bc26-99b8e583ac3c','李成德作二筆几以其一見遺云得樣于郄子中家并示長句輙次其韻奉酬','謝薖','宋','宋诗','song-poetry','','[]','琴不安絃製奇古，可憐不入文房譜。',128,'全唐诗/poet.song.79000.json','["琴不安絃製奇古，可憐不入文房譜。", "鼠鬚龍尾玉蟾蜍，與汝俱成會心侣。", "誰能好事爲品題，端效廣微亡輒補。", "謫仙傳樣桂林家，以暗投人吾竊取。", "我書太俗如墨豬，下慚羅趙何足数。", "蒙公厚貺試臨池，一字不成如畫虎。", "欲報初無青玉案，哦詩况乏驚人語。", "凈鋪滑薄待君來，慎莫踟蹰畏今雨。"]'),
('eeff5aa6-6821-4050-b8bf-d842e32fddab','李成德復用前韻見貽亦次奉和','謝薖','宋','宋诗','song-poetry','','[]','蔡家筆法擅今古，楷書尤誇荔支譜。',128,'全唐诗/poet.song.79000.json','["蔡家筆法擅今古，楷書尤誇荔支譜。", "後來誰筆最通神，要與渠伊爲伴侣。", "只今書學貴瘦硬，弟子員闕誰可補。", "君持此几要投人，字畫不工那得取。", "山人俗書如俗馬，骨少肉多今不數。", "當君此贈恐不堪，大似無功饗鹽虎。", "新詩繼作苦難和，只賞君房妙言語。", "嗟予老矣亦懶書，留與兒曹寫時雨。"]'),
('3555041d-0b02-4f30-be0a-f49fda42becf','次韻郄子中所藏筆几','謝薖','宋','宋诗','song-poetry','','[]','聞君文史三冬足，家居未奏三千牘。',128,'全唐诗/poet.song.79000.json','["聞君文史三冬足，家居未奏三千牘。", "明窗棐几靜無塵，筆研清幽真不俗。", "小琴承臂筆縱横，章草真行隨所欲。", "家藏敝帚将何用，時人尚作千金畜。", "此雖奇物君不惜，似把隋珠當魚目。", "小童傳觀許見貽，與君杯酒初相屬。", "吾詩戱作異香山，唐衢雖見何由哭。", "見公真玩爲君賦，銅缽聲終字盈幅。"]'),
('75f714ea-7c5f-47eb-88cf-c04d64ea7257','朱端甫以畫牛一紙遺李成德成德以示予爲賦長韻','謝薖','宋','宋诗','song-poetry','','[]','畫牛蹄角四十八，楮生塵昏僅可閱。',96,'全唐诗/poet.song.79000.json','["畫牛蹄角四十八，楮生塵昏僅可閱。", "頭頭露地各逍遥，不愁牽車喘見月。", "舐筆和墨誰氏子，定自道人非畫史。", "把鼻牽回得真牧，信手摹成妙如此。", "朱公自成老斵輪，不惜是牛持贈君。", "願君成誦石鞏語，更将此畫同參取。"]'),
('4b74b2b3-f386-4221-94da-3ce13318f06c','次韻李成德謝人惠墨牛','謝薖','宋','宋诗','song-poetry','','[]','君不見八百里誇王氏駁，常敇家童瑩蹄角。',163,'全唐诗/poet.song.79000.json','["君不見八百里誇王氏駁，常敇家童瑩蹄角。", "綺襦紈袴競奢豪，臥席不安愁禍作。", "何如傳寶墨牛圖，不飾青黄如素樸。", "向來奇畫購千金，宜在蘭臺天椂閣。", "兩牛方鬬未雌雄，或奔而從或小却。", "其餘三四亦殊絕，或如虎臥鶴俛啄。", "滕王蛺蝶東丹馬，嘉陵山水青田鶴。", "如将優劣比人材，長文何必慚文若。", "人言愛畫亦一癖，被野牛羊何用貎。", "是家持論果非耶，煩君試爲評其略。"]'),
('6f6db64a-f2f2-4e19-a034-852e331cafb4','午日','謝薖','宋','宋诗','song-poetry','','[]','今晨定何祥，桃柳各映户。',101,'全唐诗/poet.song.79000.json','["今晨定何祥，桃柳各映户。", "粉團高氣薰，鵝{炙火=肉}椒菜覆。", "朝餐隨土風，盃酒晚來具。", "綵絲纒祭筒，畫楫誇競渡。", "楚人哀怨情，正以屈子故。", "當年葬魚腹，蓋坐入宫妬。", "榮華一時好，放逐千載慕。", "得失吾不知，持杯自欣豫。"]'),
('79c026b9-2340-4bad-ab60-4dd886e2360e','成德不面逾月僕以病暑未能出謁輙和所寄藁字韻詩奉寄兼柬子中','謝薖','宋','宋诗','song-poetry','','[]','門前蓬藋無人埽，客去墻陰藜莧老。',208,'全唐诗/poet.song.79000.json','["門前蓬藋無人埽，客去墻陰藜莧老。", "我家城北君城南，相憶何其挂懷抱。", "不聞叔寶方外談，澄也何因令絕倒。", "知君不作避暑飲，閉門亦深荒徑草。", "鉤章棘句日吟哦，玉軸牙籤時探討。", "邇來聞草鹿脯帖，盛湘十日虛蘋藻。", "掺掺丸藥恐不免，俗客縱譏何足道。", "恨我猶嫌褦襶嘲，不敢熱行唯夢到。", "君收奇功翰墨林，筆陣可埽龍駒島。", "願言不學司馬公，萬事逢人盡稱好。", "我詩燕石初不如，浪欲珍爲夜光寶。", "殘暑促装行造請，曉來凉氣迎秋早。", "定邀鄰舍廣文公，同聽誦詩傾腹藁。"]'),
('916d0bd0-a864-4a3e-8f4e-af5d3bc5b287','碧筩','謝薖','宋','宋诗','song-poetry','','[]','君不見韓潮州，銀作飲醆誇工倕。',158,'全唐诗/poet.song.79000.json','["君不見韓潮州，銀作飲醆誇工倕。", "鐫花鏤松太瑣碎，何言豪士亦爾爲。", "又不見六一翁，嘗吟鸚鵡紅螺詩。", "華堂一釂豈不樂，清歌勸酒須蛾眉。", "吾儕山人寧有此，競折圓荷爲飲器。", "細傾初作露珠圓，滿引忽驚雲液碎。", "鼻中寂寂聞妙香，舌本徐徐識真味。", "採蓮當殽花當妓，豈有登臨百金費。", "安得城西十頃塘，水光容裔暑風凉。", "時引碧筩如象鼻，仍看翠蓋立霓裳。"]'),
('f9a64fe6-8500-4d94-9529-9919197ae219','感白髮','謝薖','宋','宋诗','song-poetry','','[]','吾年昔始冠，已有一髪白。',144,'全唐诗/poet.song.79000.json','["吾年昔始冠，已有一髪白。", "作賦數百言，嘲罵等戱劇。", "只今尋舊作，一字不復憶。", "恍然如夢寐，了不見往迹。", "但有髩間絲，冉冉如堪織。", "南方地平濕，壮歲多老色。", "行年四十二，髪鬒那容惜。", "洗蘇将拔白，諱老嗟何益。", "一染復星星，此語記阿客。", "人生光景促，倐忽如敲石。", "詩成亦寤語，感嘆初無得。", "後應不識今，今已不識昔。"]'),
('0071d96c-fe6a-4b39-bee7-2c8d0e446540','秋日登鳴玉亭','謝薖','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山路秋陽何赫赫，山亭凄冷多秋色。',64,'全唐诗/poet.song.79000.json','["山路秋陽何赫赫，山亭凄冷多秋色。", "豈惟醒耳玉淙琤，照眼光寒如練白。", "舊聞瀑布垂雲間，怳疑銀河墮天關。", "西望香爐不得往，箇中元有小廬山。"]'),
('f1df4413-7ea2-4ae2-afdd-8fc40c81ace3','次董彦孚韻兼簡之南','謝薖','宋','宋诗','song-poetry','','[]','大門江南英，詩名重當時。',144,'全唐诗/poet.song.79000.json','["大門江南英，詩名重當時。", "兒時得其藁，同輩争誦之。", "不及拜諸門，常恨生苦遲。", "只今諸孫子，籍甚皆能詩。", "大篇每投我，孰非黄絹辭。", "我詩不成句，落筆爲衆嗤。", "如人食土炭，嗜好終不移。", "君何獨賞味，與衆真異馳。", "相望巷南北，不面令我思。", "歌聲亦若哭，此意誰當知。", "阿大一門傑，相爲塵外期。", "風流竹林會，應許仲容隨。"]'),
('1cb4043e-2a9b-4930-a532-37b027e3fc79','次韻之南讀彦光詩有作','謝薖','宋','宋诗','song-poetry','','[]','君家父子俱能詩，天遣俶鳥鳴春時。',64,'全唐诗/poet.song.79000.json','["君家父子俱能詩，天遣俶鳥鳴春時。", "文窮抵掌定不免，齊竽不學君何疑。", "平生說詩喙三尺，只今蹇吃成期期。", "願君高處古無上，抑以自驚無邪思。"]'),
('157f05ff-943c-4cb2-bc70-a9ed568df4c1','有懷覺範上人','謝薖','宋','宋诗','song-poetry','','[]','道人心與貌俱古，哦詩不復效等伍。',112,'全唐诗/poet.song.79000.json','["道人心與貌俱古，哦詩不復效等伍。", "清疑仙掌露華墜，新似秋空玉鈎吐。", "要将餘事付風騷，已悟玄機窺佛祖。", "泐潭老子乳於菟，果在叢林嘯風雨。", "何當埽室祗樹園，夜看金盆聽軟語。", "我雖不是龐德公，懶駕柴車入城府。", "公如歸結白蓮社，留我山邊一廛許。"]'),
('ee0826fd-db93-4ae5-a392-bfd36c5ee575','次韻彦光睡起病目','謝薖','宋','宋诗','song-poetry','','[]','蝶夢遊揚臥碧紗，知君不賞玉釵斜。',64,'全唐诗/poet.song.79000.json','["蝶夢遊揚臥碧紗，知君不賞玉釵斜。", "夢回起坐有佳思，亂觸牙籤書五車。", "黑蝇着眼君勿嗟，學道乃得青蓮華。", "商略此言當過我，樵青竹裏爲煎茶。"]'),
('796128e9-d41a-4fbc-83d2-91990e813570','喜汪叔野見過','謝薖','宋','宋诗','song-poetry','','[]','大汪權奇汗血駒，小汪連翩鸑鷟雛。',176,'全唐诗/poet.song.79000.json','["大汪權奇汗血駒，小汪連翩鸑鷟雛。", "垂頭未遇伯樂頋，覽輝将下朝陽梧。", "豈知青衫埋朽壤，更令斑髩困泥塗。", "喜君翩翩過我廬，握手借問今何如。", "若云難遂白髪志，朅來翻作青衿徒。", "急呼歡伯置座側，解顔談笑聊相娛。", "語及阿兄平日事，往往屑涕長欷歔。", "怪君長不滿六尺，高譚似是膽滿軀。", "且寬是事飲此醑，逢人但作鞏囁嚅。", "苦留君住騎勿驅，明朝酒盡爲君酤。", "更闌月落起浩嘆，四面宿鳥鳴相呼。"]'),
('aeb7df80-8177-44aa-9baf-d748fe33c093','追和柳子厚二詩 讀書','謝薖','宋','宋诗','song-poetry','','[]','吾生後淵明，頗亦念黄虞。',168,'全唐诗/poet.song.79000.json','["吾生後淵明，頗亦念黄虞。", "要知千載外，所學非殊塗。", "兀坐對聖賢，撫卷一長吁。", "彼智自明哲，惟狂益昏逾。", "一源同濫觴，派别乃差殊。", "我觀載籍中，世事何所無。", "癡人不識古，謂與古人俱。", "相望何遥遥，清都視積蘇。", "咄此不可獻，諷誦聊相愉。", "嗟哉子柳子，文章蓋群儒。", "速進自貽戚，南冠成縶拘。", "天孫不與巧，溪神亦爲愚。", "讀書雖滿腹，何曾救饑劬。", "乃知伾文輩，要路難齊驅。"]'),
('728d5851-8038-4e53-a049-5846e2e4816a','追和柳子厚二詩 飲酒','謝薖','宋','宋诗','song-poetry','','[]','世故不料理，萬事付一樽。',96,'全唐诗/poet.song.79000.json','["世故不料理，萬事付一樽。", "呼賓陳肴蔌，乃爾不惮頻。", "秩筵初嚴冷，稍稍笑語喧。", "有如鄒子律，能回寒谷温。", "朱顔挽不住，雪髩日夜煩。", "人生行樂耳，惲也亦至言。", "哀哉獨醒人，顦顇拾蘭蓀。", "寧知阿堵中，端有妙理存。"]'),
('e5f52fa8-0d99-4659-ba8c-24c819d02964','寄題朱氏小隱園','謝薖','宋','宋诗','song-poetry','','[]','吾聞滑稽兒，避世向金馬。',168,'全唐诗/poet.song.79000.json','["吾聞滑稽兒，避世向金馬。", "刈草吉雲鄊，探鳯芳城野。", "斯人玩世耳，豈必蒿廬下。", "墻東本儈牛，君平蓋卜者。", "朝市亦堪隱，山林實瀟洒。", "君居占深源，境物粲可寫。", "老檜上干雲，孫桐已拱把。", "雨窗修竹響，風磴寒泉瀉。", "此翁少年日，射巧如注瓦。", "百金装寶刀，千金買流赭。", "晚歌紫芝曲，情性妙陶冶。", "蒲履穀皮巾，何取綬若若。", "嗟予亦曠蕩，與世自藞苴。", "方期訪桃源，更欲結蓮社。"]'),
('7e22e2ef-e520-4296-8c03-408aaa52f094','次韻董之南見贈','謝薖','宋','宋诗','song-poetry','','[]','章甫不入越，夏蟲多拘時。',144,'全唐诗/poet.song.79000.json','["章甫不入越，夏蟲多拘時。", "生無適俗韻，舉世誰知之。", "鍾嶸不並世，無人識丘遲。", "雖有落花句，知爲何等詩。", "如逢賀賓客，方歎烏棲辭。", "我初出險語，俗子争唐嗤。", "俛眉欲從事，復恐遭文移。", "亦知適楚車，安可從北馳。", "董家名父子，平生所懷思。", "雖云識面晚，相聞已相知。", "君詩有古意，且結皓首期。", "端能啖杞菊，時復過天隨。"]'),
('2d013cb7-db5a-40f4-ac3c-fa605cdb7f9c','陳循中求賦高麗墨詩爲作長句','謝薖','宋','宋诗','song-poetry','','[]','老松收煙琢玄玉，可試洮州鴨頭綠。',64,'全唐诗/poet.song.79000.json','["老松收煙琢玄玉，可試洮州鴨頭綠。", "來從萬里古樂浪，傳到麻源第三谷。", "要須岱郡鹿角膠，擣成方解土炭嘲。", "請君摩硏寫新作，一弄潺湲吊康樂。"]'),
('d3772ed9-6194-4ab5-aafd-7e3ee67f3e83','竹友軒','謝薖','宋','宋诗','song-poetry','','[]','畏夏苦執熱，開軒除鬱蒸。',168,'全唐诗/poet.song.79000.json','["畏夏苦執熱，開軒除鬱蒸。", "簷前鳥雀喧，朝旭上朱甍。", "席間裁函丈，詩書浩縱横。", "槃礴環堵間，幽獨懷友生。", "古人在黄卷，千載使我傾。", "出門窺物變，草木各鮮榮。", "青青墻東竹，見汝忽眼明。", "愛玩不能忘，移根傍軒楹。", "俯仰與竹俱，定交見深情。", "不是無朋友，此君冰玉清。", "風吹萬籟響，寒梢韻竽笙。", "我獨哦其間，詩作秋蟲鳴。", "琅玕亦有實，期汝向秋成。", "鳯凰何時來，翽翽翔我庭。"]'),
('892c6ca9-e4d1-4c23-aa3f-bda5839d7f27','貫時軒','謝薖','宋','宋诗','song-poetry','','[]','舊時王子猷，愛竹僅成癖。',132,'全唐诗/poet.song.79000.json','["舊時王子猷，愛竹僅成癖。", "斯人向千載，論世心莫逆。", "吾軒謐竹友，寓意比三益。", "俗士舊雨來，今雨定掃迹。", "城北有陳侯，眉宇初未識。", "似聞臭味同，炯炯見胸臆。", "願言登子軒，哦句呼阿客。", "看君陰森下，玉潤映連璧。", "龍吟秋夜永，臥聽風摵摵。", "或當命柴車，獨咏此君側。", "興盡悠然反，誰能煖君席。"]'),
('f09114e5-1629-4743-9478-40a7a25b6429','讀荘子內篇','謝薖','宋','宋诗','song-poetry','','[]','經春十日雨，却掃門無車。',144,'全唐诗/poet.song.79000.json','["經春十日雨，却掃門無車。", "伏枕夢鳴轂，淙琤行溜渠。", "端坐發深省，妙香浮素裾。", "盥濯披陳編，諷誦臨前除。", "陳編爲何誰，漆園傲吏書。", "奇辭通諔詭，空語極虚無。", "得意榮辱境，脫身憂患餘。", "胸中灌頂句，身上如意珠。", "逍遥有妙處，領略歸一途。", "塵影閱千世，風波連九區。", "投足寄其間，鼎鼎一何愚。", "儻同蓬蒿鷃，勿笑溟海魚。"]'),
('97834174-952a-427c-8092-f180d1f6e551','陶淵明寫真圖','謝薖','宋','宋诗','song-poetry','','[]','淵明歸去潯陽曲，杖藜蒲鞋巾一幅。',224,'全唐诗/poet.song.79000.json','["淵明歸去潯陽曲，杖藜蒲鞋巾一幅。", "陰陰老樹囀黄鶯，艶艶東籬粲霜菊。", "世紛無盡過眼空，生事不豐隨意足。", "廟廊之姿老蓬蓽，環堵蕭條僅容膝。", "大兒頑鈍懶詩書，小兒嬌癡愛梨栗。", "老妻日暮荷鋤歸，欣然一笑共蝸室。", "哦詩未遣愁肝腎，醉裏呼兒供紙筆。", "時時得句輒寫之，五言平淡用一律。", "田家酒熟夜打門，頭上自有漉酒巾。", "老農時問桑麻長，提壺挈榼來相親。", "一尊徑醉北窗臥，蕭然自謂羲皇人。", "此公聞道窮亦樂，容貌不枯似丹渥。", "儒林紛紛隨溷濁，山林高義久寂寞。", "假令九原今可作，舉公藍輿也不惡。"]'),
('693b6231-9caf-4c74-99b9-b5fa6ed9568a','斸苓軒','謝薖','宋','宋诗','song-poetry','','[]','萬鍾辭屠羊，五鼎貪主父。',132,'全唐诗/poet.song.79000.json','["萬鍾辭屠羊，五鼎貪主父。", "是間多毒腊，可茹亦可吐。", "緬懷陶隱居，朝服挂神武。", "餌苓期卻老，曠蕩適林莾。", "我家城西偏，有地一廛許。", "開軒俛長松，倒影廕庭廡。", "嵌空宿龍蛇，晻曖藏霧雨。", "流脂入地脉，凝結歲月古。", "長鑱白木柄，生事聊付汝。", "想彼塵外人，遲暮肯同煮。", "但當稍兔絲，敢望擘麟脯。"]'),
('66532aed-581b-4614-a2cb-f07f5aa32340','約諸人遊羅坊觀','謝薖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','陽夏吾鼻祖，人物傾九州。',192,'全唐诗/poet.song.79000.json','["陽夏吾鼻祖，人物傾九州。", "間携東山妓，文靖極風流。", "屐齒步飛磴，快哉康樂遊。", "耳孫牛馬走，闒惰無匹儔。", "但有愛山趣，尚能繼前修。", "頗厭城市塵，拘縶如楚囚。", "朅來龍泉上，杖履隨沙鷗。", "幽尋風露靜，江月動金虯。", "青山带長江，佳氣日夕浮。", "旁有列仙家，丹楼連飛樓。", "琴書静無華，竹樹煩更幽。", "約我雲霞交，兹遊及清秋。", "朱絃蕩塵襟，芳尊寫牢愁。", "道士如彌明，長頸高結喉。", "初無石鼎句，嶮怪壓劉侯。", "從渠倚壁睡，吾屬足冥搜。"]'),
('eb282990-59b2-4d5e-8bc8-d63d168c1e80','無逸病目以詩戱問','謝薖','宋','宋诗','song-poetry','','[]','六根無牢强，萬事有戕敗。',120,'全唐诗/poet.song.79000.json','["六根無牢强，萬事有戕敗。", "丹白豈不佳，能令眼根壞。", "溪堂老居士，學道入三昧。", "空花結空果，過眼了無礙。", "偶然幻翳侵，惱此清淨界。", "道人不易得，定爲天所愛。", "恐君墮塵劫，豫比小懲戒。", "病眸點空青，勿作兒女態。", "爲君禱于天，君病立當瘥。", "未忘覷詩書，不敢窺粉黛。"]'),
('fbab9bb2-3db3-4669-91c2-f0ac0681e0e6','題戴崧石鼎聯句圖','謝薖','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡山道士熊豹姿，夜過劉生逢說詩。',176,'全唐诗/poet.song.79000.json','["衡山道士熊豹姿，夜過劉生逢說詩。", "止于座隅初莫識，口不能言心自知。", "坐中清逸校書郎，新有詩聲誰過之。", "豈知老子殊不淺，可但逐鬼囚蛟螭。", "須臾指鼎出佳句，脱略凡韻生新奇。", "二生得句不敢吐，鳴聲强作秋蟲悲。", "愯如窘兔避鷹隼，懔如敗将收旌旗。", "借問舐筆摹者誰，定是盤礴真畫師。", "退之斯文有妙處，丹青寫盡初無遺。", "彌明學道如不死，應在衡山深處栖。", "端能過我挑詩敵，與君周旋吾敢辭。"]'),
('37537b22-253b-4e85-a000-a930d574c201','讀葛洪傳','謝薖','宋','宋诗','song-poetry','','[]','葛洪鍊丹砂，却老得遐壽。',60,'全唐诗/poet.song.79000.json','["葛洪鍊丹砂，却老得遐壽。", "鶴髪安在哉，岩穴遺井舊。", "勞生亦何爲，荏苒度昏晝。", "煌煌崑丘芝，未暇擷三秀。", "寄謝浮丘翁，何由挹其袖。"]'),
('9a713322-6d9b-4194-9daf-e5a532d3f452','讀三都賦','謝薖','宋','宋诗','song-poetry','','[]','漢遭陽九運，無復見中興。',96,'全唐诗/poet.song.79000.json','["漢遭陽九運，無復見中興。", "不聞黄屋處，郊野蔽旗旌。", "三人已成虎，况阻三國兵。", "揚塵日月暗，喋血郊原腥。", "作都雖云美，其如九鼎輕。", "十年翰墨手，摸寫費丹青。", "人與骨俱朽，山川空炳霛。", "吾懷鮑明遠，寂莫賦蕪城。"]'),
('9e87e387-0ecc-4dfb-9d94-05bf047e156d','田父招飲不赴','謝薖','宋','宋诗','song-poetry','','[]','萬錢供食如嚼蠟，百壺載酒如飲水。',112,'全唐诗/poet.song.79000.json','["萬錢供食如嚼蠟，百壺載酒如飲水。", "要知自古窮達人，脱略世味皆如此。", "經旬不逢南鄰伴，曲肱聊寄北窗底。", "田父剥喙扣我門，頗應昨夜燈花喜。", "殷勤攬衣謝父老，陶令愛酒今朝止。", "伏雌可殺葵可羮，他日薄飯招鄰里。", "吾君恭儉似文帝，勿爲酒醪傷穀米。"]'),
('cb1b0cdd-52c1-4f91-94e4-c696993b33d0','喜雨','謝薖','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','涉冬無一雨，玄冥阻驕陽。',144,'全唐诗/poet.song.79000.json','["涉冬無一雨，玄冥阻驕陽。", "上田塵沙飛，下田蒲稗荒。", "鋤犁不入土，龍具挂壁墻。", "村居巷無井，抱甕汲長江。", "汲多恐流絕，無以飲牛羊。", "昨宵天意動，浮雲霾月光。", "洒然潤物功，洗蘇及枯楊。", "先帝劍弓冷，小臣涕淚滂。", "屬聞建中號，謳歌騰路傍。", "雨從膏澤沛，風與和氣翔。", "山林獨何幸，預喜霑稻粱。", "尚能賦時雨，激烈歌阜康。"]'),
('99cb8f98-6be1-4406-8c02-978d89918797','余賦野香亭前木犀花二小詩盛稱此花之妙而江迪彞賦梅花詩以反之往返唱和十數篇二花優劣未决故復長韻示之','謝薖','宋','宋诗','song-poetry','','[]','君不見杜陵布衾冷如鐡，朝來米盡炊煙絕。',147,'全唐诗/poet.song.79000.json','["君不見杜陵布衾冷如鐡，朝來米盡炊煙絕。", "偶然乘興江上行，無奈被花惱不徹。", "城南陋巷在江侯，讀書蒲團生蟣虱。", "吟成少陵七字詩，酷愛梅花似冰雪。", "竹友道人端可嗤，頷髭如棘手如龜。", "從來口業洗未盡，醉吐狂辭歌木犀。", "賞花自是少年事，出口未覺吾儕癡。", "我今束縛喙三尺，勿與世俗争妍媸。", "空花遍世不礙眼，淡如雲水老禅師。"]'),
('1fcab63f-c9dc-44bb-b596-ed73f9c5c088','寄題王立之賦歸堂','謝薖','宋','宋诗','song-poetry','','[]','小官五斗米，達官五鼎食。',96,'全唐诗/poet.song.79000.json','["小官五斗米，達官五鼎食。", "均有懷禄心，細大各封殖。", "疾驅挽不還，此輩車轂擊。", "王侯生綺紈，雅意在山澤。", "頗賦歸去來，作堂慰休息。", "似聞一尊酒，醉眼分青白。", "何時上君堂，酌酒話疇昔。", "和君五字句，想望柴桑陌。"]'),
('19bba12d-68b4-40dc-bbf1-15d4bda5417a','亦愛軒','謝薖','宋','宋诗','song-poetry','','[]','漆園遊濠梁，得意鯈魚樂。',96,'全唐诗/poet.song.79000.json','["漆園遊濠梁，得意鯈魚樂。", "淵明愛吾廬，感彼衆鳥託。", "兩賢俱達道，妙處要商略。", "夫子誰與歸，潛也如可作。", "柴桑久無人，兹道竟寥落。", "頗能誦其詩，尚友亦不惡。", "世路多艱險，君軒可槃礴。", "但恐君出遊，蕭朱綬若若。"]'),
('101916f8-2010-4c7f-8dbe-3aa42c7920f9','求定齋','謝薖','宋','宋诗','song-poetry','','[]','吾觀大梁城，九衢塵暗天。',96,'全唐诗/poet.song.79000.json','["吾觀大梁城，九衢塵暗天。", "蠻觸日交争，夔蚿互相憐。", "此心如慈幡，裊裊風中懸。", "王子閉門臥，守心長縛禅。", "能定乃能應，如鏡别醜姸。", "吾豈匏瓜哉，孔子有至言。", "君看日月行，亦若磨蟻旋。", "涪翁已發藥，此句不用傳。"]'),
('0628b0b6-3f56-41e4-b023-987074727a2c','寄饒次守','謝薖','宋','宋诗','song-poetry','','[]','我初丱角時，聞有饒進父。',288,'全唐诗/poet.song.79000.json','["我初丱角時，聞有饒進父。", "破衣下里舍，應書不得舉。", "要是磊落人，白眼看法度。", "吹笙弹箜篌，餘事能律吕。", "市人惡少年，往往争笑侮。", "掉頭出里門，徒步大梁去。", "蒯緱謁王公，敝貂走風雨。", "十年不還鄉，無人問死所。", "客從北方來，喜氣滿眉宇。", "探懷出君詩，字字粲璣珇。", "筆蹤入顔掦，句法窺李杜。", "奇偉可畏人，我輩誰比数。", "借問從誰遊，一一英俊侣。", "我家阿夷兄，詩有春草句。", "說君不離口，恨我識君暮。", "帝城十二衢，素衣染黄土。", "食貧出無車，羈旅亦良苦。", "束書早歸來，隻雞祭墳墓。", "况聞霍将軍，尚有陳氏母。", "銅山鬱嵯峨，其下原膴膴。", "我思結茆舍，带經學農圃。", "他日如買鄰，定可連墻住。", "頗聞君卜昏，我亦未有婦。", "要如子柳子，各娶老農女。"]'),
('0bb97c02-6e83-46d8-b3eb-64e8233d1e51','讀潘邠老廬山紀行詩','謝薖','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','杜陵骨已朽，潘子今似之。',108,'全唐诗/poet.song.79000.json','["杜陵骨已朽，潘子今似之。", "欻觀廬山作，乃類北征詩。", "是家好男子，札翰非凡兒。", "阿耶有新句，把筆如畫錐。", "此詩落吾手，三復喜可知。", "有才如長卿，武帝思同時。", "不令歌天馬，亦合賦靈芝。", "胡爲鬂已凋，但作愁苦辭。", "錦囊勿妄發，恐爲俗子嗤。"]'),
('be487746-3b94-4e67-b98f-8e98e71ca141','汲古齋','謝薖','宋','宋诗','song-poetry','','[]','人言曲誤周郎頋，豈謂周郎真好古。',128,'全唐诗/poet.song.79000.json','["人言曲誤周郎頋，豈謂周郎真好古。", "長歌短調各風流，說盡心招及眉語。", "頗聞汲古用修綆，乃知餘事工律吕。", "君軀三尺膽如斗，欲窺唐虞探鄒魯。", "頃來長安闊畫眉，時人半額相媚嫵。", "天姿潔白惡丹鉛，獨有溪頭浣紗女。", "要知學者用心處，不追時好乃如許。", "君家有井千尺深，容我時攀轆轤否。"]'),
('517db4b8-ba4f-4675-8ba8-1630e371867c','寄李商老','謝薖','宋','宋诗','song-poetry','','[]','所思定何方，渺然羌山麓。',216,'全唐诗/poet.song.79000.json','["所思定何方，渺然羌山麓。", "别來經一年，不寄書一幅。", "憶在元真館，與君同飲缸。", "論文久未去，夜雪打寒窗。", "明朝款君門，箯輿踏殘雪。", "尊前聽君談，意氣排凛冽。", "雪中兩相過，把酒俱留連。", "豈同剡溪去，興盡回酒船。", "今年走東吳，無復相邂逅。", "遭回行路難，歸已三月後。", "逢君所知人，頗嘗問君安。", "猶聞臥苫塊，毁棘今欒欒。", "君家所嬌兒，聞已去懷抱。", "昔我嘗見之，瑶環實娟好。", "我歸臥衡門，愁君亦如君。", "淋雨子桑病，敝冠原憲貧。", "此懷其誰語，思君何能已。", "寄聲勞苦君，兼問兩季子。"]'),
('aedc162e-09a5-4cb5-844d-19b307c025d1','集菴摩勒園觀李伯時畫陽關圖以不能捨餘習偶被世人知爲韻得人字賦六言','謝薖','宋','宋诗','song-poetry','','[]','摩詰句中有眼，龍眠筆下通神。',56,'全唐诗/poet.song.79000.json','["摩詰句中有眼，龍眠筆下通神。", "佳篇與畫張本，短紙爲詩寫真。", "渭城偶落吾手，小圃傳觀衆賓。", "坐上宴如居士，暗中摸索離人。"]'),
('cbf48dce-1207-4ec7-b016-225ccb9f986e','次韻董彦速送珍上座還漳江','謝薖','宋','宋诗','song-poetry','','[]','阿師身小膽能大，文字寧追權可遊。',64,'全唐诗/poet.song.79000.json','["阿師身小膽能大，文字寧追權可遊。", "尋山紅葉半旬雨，過我黄花三徑秋。", "隨處龐公雖有偈，他年支遁恐難酬。", "經行若箇門風是，聞說漳江似趙州。"]'),
('28d5bad0-a0ff-4e8e-848c-f82d2205da83','招李成德','謝薖','宋','宋诗','song-poetry','','[]','妙年英偉定楩柟，老大如樗百不堪。',64,'全唐诗/poet.song.79000.json','["妙年英偉定楩柟，老大如樗百不堪。", "黍飯奠孤元伯約，山夫豈有德公談。", "棋無多算愧三北，詩要重論窺二南。", "只恐尋芳嗟較晚，夜來風蘂落毵毵。"]'),
('aa20407c-2ad4-4ce5-90f2-40e59310e6d5','採金櫻子','謝薖','宋','宋诗','song-poetry','','[]','三月花如薝蔔香，霜中採實似金黄。',32,'全唐诗/poet.song.79000.json','["三月花如薝蔔香，霜中採實似金黄。", "煎成風味亦不淺，潤色猶煩頋建康。"]'),
('fc6f9c94-7e34-4b3c-9bcf-cf2080bb7f42','讀何易于傳','謝薖','宋','宋诗','song-poetry','','[]','吏皆愁死自焚詔，農正勤耕身挽船。',32,'全唐诗/poet.song.79000.json','["吏皆愁死自焚詔，農正勤耕身挽船。", "墨綬紛紛滿天下，不知誰拍此渠肩。"]'),
('0f2ef652-ecb5-41fb-b23d-a4e7625ffe6a','讀嚴子陵祠堂記','謝薖','宋','宋诗','song-poetry','','[]','羊裘不見釣臺傾，山到臺邊分外青。',64,'全唐诗/poet.song.79000.json','["羊裘不見釣臺傾，山到臺邊分外青。", "天上故人新黼黻，身前萬事一笭箵。", "章侯筆法逼秦相，范子文章原易經。", "圖畫名臣久磨滅，此碑千古粲繁星。"]'),
('b259421e-7342-4a3b-acbd-4dcb112048dd','觀漁二首  其一','謝薖','宋','宋诗','song-poetry','','[]','腹腴端可飽新歡，柳貫霜鱗照眼寒。',32,'全唐诗/poet.song.79000.json','["腹腴端可飽新歡，柳貫霜鱗照眼寒。", "莫惜寶刀煩玉腕，要看飛雪下金盤。"]'),
('efd3dbc5-d626-420d-b253-f0a68de3627a','觀漁二首  其二','謝薖','宋','宋诗','song-poetry','','[]','活我波間雙鯉魚，待傳千里故人書。',32,'全唐诗/poet.song.79000.json','["活我波間雙鯉魚，待傳千里故人書。", "嬌蛾莫道留君掃，怕捲珠簾總不如。"]'),
('b880283b-2718-490e-8a63-9ccbddc2b262','潘邠老嘗作詩云滿城風雨近重陽邠老亡後無逸兄用此句足成四篇今兹重陽只数日風兩不止凄然有懷作二絕句念泉下二人不再作不覺流涕覆面也  其一','謝薖','宋','宋诗','song-poetry','','[]','地下修文兩玉人，清詩傳世墨猶新。',32,'全唐诗/poet.song.79000.json','["地下修文兩玉人，清詩傳世墨猶新。", "却因風雨重陽近，獨立蒼茫淚一巾。"]'),
('b050799e-de3c-4a6d-8f50-e3bcc2f88ac6','潘邠老嘗作詩云滿城風雨近重陽邠老亡後無逸兄用此句足成四篇今兹重陽只数日風兩不止凄然有懷作二絕句念泉下二人不再作不覺流涕覆面也  其二','謝薖','宋','宋诗','song-poetry','','[]','阿兄温潤玉介導，我友淡薄朱絲絃。',32,'全唐诗/poet.song.79000.json','["阿兄温潤玉介導，我友淡薄朱絲絃。", "只疑蝉蛻遊人世，醉插茱茰若箇邊。"]'),
('b43d13f0-2e28-4f37-a471-7c1e402ae36d','隱居','謝薖','宋','宋诗','song-poetry','','[]','清時甘小隱，卜築在山阿。',48,'全唐诗/poet.song.79000.json','["清時甘小隱，卜築在山阿。", "家有傳蚕室，機如凌行婆。", "閒看斬猫話，羞作扣牛歌。", "不出又三月，柴門生薜蘿。"]'),
('dc52a0ba-6e3d-4761-840d-e1179a3d4ce1','秋日登擬峴臺二首  其一','謝薖','宋','宋诗','song-poetry','','[]','步上溪邊百尺臺，斬新秋色正傷懷。',32,'全唐诗/poet.song.79000.json','["步上溪邊百尺臺，斬新秋色正傷懷。", "千屏翳繞碧雲合，一字傾欹鴻雁來。"]'),
('893ce8ec-05f7-44bd-a7cd-e4fd48ea5381','秋日登擬峴臺二首  其二','謝薖','宋','宋诗','song-poetry','','[]','徘徊欣與賞心同，讀遍碑詞字字工。',32,'全唐诗/poet.song.79000.json','["徘徊欣與賞心同，讀遍碑詞字字工。", "共歎黄壚封白壁，一時悲淚洒秋風。"]'),
('f8d11464-0612-42ee-9c90-e56993bcccf4','秋暑','謝薖','宋','宋诗','song-poetry','','[]','秋暑不可奈，秋風殊未來。',48,'全唐诗/poet.song.79000.json','["秋暑不可奈，秋風殊未來。", "何時疏畫扇，無處覓凉臺。", "誰謂月離畢，空驚山殷雷。", "愁聞老農語，南畝半黄埃。"]'),
('365afa4b-4fb9-4ab4-90bb-8d40ef85dc04','寄汪信民二首  其一','謝薖','宋','宋诗','song-poetry','','[]','泮水傳經老，蓬山佐著才。',48,'全唐诗/poet.song.79000.json','["泮水傳經老，蓬山佐著才。", "宦遊思引去，禄飬可歸來。", "要路眼誰白，浮雲心自灰。", "少年馬何駛，君馬獨虺隤。"]'),
('e8f7341d-d844-4776-a44c-b84747bebbb8','寄汪信民二首  其二','謝薖','宋','宋诗','song-poetry','','[]','繫纜符離日，君行殊未歸。',48,'全唐诗/poet.song.79000.json','["繫纜符離日，君行殊未歸。", "寄書問毫杜，有夢向江西。", "不見揮犀柄，頓驚響馬蹄。", "殷勤具雞黍，多謝德公妻。"]'),
('06345b72-4eb4-4baa-9e20-154f5d4b1275','喜董彦速自仙巖歸','謝薖','宋','宋诗','song-poetry','','[]','鉢囊高掛同僧夏，遠寄巖門一把茅。',64,'全唐诗/poet.song.79000.json','["鉢囊高掛同僧夏，遠寄巖門一把茅。", "地僻狙猴長作伴，食貧蕨筍不充庖。", "瘦藤拄下萬峰頂，野鶴來歸千歲巢。", "點檢篋中詩幾首，蒼頭時遣爲君抄。"]'),
('053c6bfe-b5e2-4fa5-b2de-cb71df9759d2','莫莫堂新竹','謝薖','宋','宋诗','song-poetry','','[]','僻寂漏茅屋，蕭梢新竹枝。',48,'全唐诗/poet.song.79000.json','["僻寂漏茅屋，蕭梢新竹枝。", "徑迷人不到，蔭密鳥還知。", "綠色蔥蔥換，薰風細細吹。", "即看柯葉老，不受歲寒欺。"]'),
('87dfca51-0520-46cf-8464-c6a9c04cab68','夏夜對月','謝薖','宋','宋诗','song-poetry','','[]','掃月追凉清夜分，是間風露别乾坤。',64,'全唐诗/poet.song.79000.json','["掃月追凉清夜分，是間風露别乾坤。", "山林畏佳地多籟，雲漢昭回天不言。", "平野極瞻南紀闊，稀星遥拱北辰尊。", "時平萬里無兵革，静愛雞鳴犬吠村。"]'),
('a28cf739-1869-4126-b722-a5e5fc83f1f2','煎甖粟湯二首  其一','謝薖','宋','宋诗','song-poetry','','[]','萬粒勻圓剖甖子，作湯和蜜味尤宜。',32,'全唐诗/poet.song.79000.json','["萬粒勻圓剖甖子，作湯和蜜味尤宜。", "中年强飯却丹石，安用咄嗟成淖糜。"]'),
('a8a3657c-ee41-4c56-a504-55f7c482e652','煎甖粟湯二首  其二','謝薖','宋','宋诗','song-poetry','','[]','松黄浮椀色蒸栗，初味餘甘如苦荼。',32,'全唐诗/poet.song.79000.json','["松黄浮椀色蒸栗，初味餘甘如苦荼。", "粉粟爲湯兩奇絕，甚甘純白勝醍醐。"]'),
('71924439-867d-4a17-9d0e-201bcabe2166','問劉世基疾','謝薖','宋','宋诗','song-poetry','','[]','君如寒涕懶瓉師，如何久苦造化兒。',64,'全唐诗/poet.song.79000.json','["君如寒涕懶瓉師，如何久苦造化兒。", "清漳嬰疾古所歎，淋雨裹飯今其誰。", "探囊苦乏萬金藥，歷眼疇爲三世醫。", "他年上疏恐不免，細君莫念眠牛衣。"]'),
('ca159107-506c-4ff9-b1fe-79a0cefb9a39','蔡師直畫山水研屏二首  其一','謝薖','宋','宋诗','song-poetry','','[]','畫翁元勝斵輪扁，喻子丹青如有神。',32,'全唐诗/poet.song.79000.json','["畫翁元勝斵輪扁，喻子丹青如有神。", "平遠還堪助詩思，故疑摩詰是前身。"]'),
('bf4ff2b9-7554-4d94-a9a2-d056174108b0','蔡師直畫山水研屏二首  其二','謝薖','宋','宋诗','song-poetry','','[]','淡墨江山作小屏，碧紗煙裏護寒泓。',32,'全唐诗/poet.song.79000.json','["淡墨江山作小屏，碧紗煙裏護寒泓。", "蟾蜍寫盡看倒影，身在山陰佳處行。"]'),
('81584236-9f17-4f1b-8169-2434dbf2e0bc','觀棋','謝薖','宋','宋诗','song-poetry','','[]','客憇茂林晚，風生凉簟秋。',48,'全唐诗/poet.song.79000.json','["客憇茂林晚，風生凉簟秋。", "縱横飛碎玉，勝敗决中流。", "北叟暫亡馬，西風還覆舟。", "誰能關許事，寓目且忘憂。"]'),
('049bbbbd-c6de-47a6-bcc7-79c0b2ca89f2','喜晴','謝薖','宋','宋诗','song-poetry','','[]','十日江村烟雨濛，曉來初快日升東。',64,'全唐诗/poet.song.79000.json','["十日江村烟雨濛，曉來初快日升東。", "挼莎蕉葉展新綠，縱臾榴花開晚紅。", "得句又從山色裏，發機渾在鳥聲中。", "披衣出户眄四野，好在良苗懷晚風。"]'),
('a80671c1-d2e3-4a5b-b091-214edaf251e4','和李智伯病中書事四首  其一','謝薖','宋','宋诗','song-poetry','','[]','多病過嗟蒲柳弱，故交聞似曙星疏。',32,'全唐诗/poet.song.79000.json','["多病過嗟蒲柳弱，故交聞似曙星疏。", "逢人休問金篦術，殺簡宜希石室書。"]'),
('eec4d442-9f16-4377-bb97-5c029aa5a0dc','和李智伯病中書事四首  其二','謝薖','宋','宋诗','song-poetry','','[]','訓釋雖工非世好，風流未減已形枯。',32,'全唐诗/poet.song.79000.json','["訓釋雖工非世好，風流未減已形枯。", "固知商也真無罪，豈謂穹穹不可呼。"]'),
('de5d9bb4-ba0e-4c48-90d3-8010bdee0f0c','和李智伯病中書事四首  其三','謝薖','宋','宋诗','song-poetry','','[]','應知露肘貧堪忍，只有哦詩興未疏。',32,'全唐诗/poet.song.79000.json','["應知露肘貧堪忍，只有哦詩興未疏。", "莫遣木蘭當户織，須煩阿買八分書。"]'),
('ea197991-31bc-45a5-b477-f76abe6d4471','和李智伯病中書事四首  其四','謝薖','宋','宋诗','song-poetry','','[]','老去驚詩筆退，愁生唯怕酒腸枯。',31,'全唐诗/poet.song.79000.json','["老去驚詩筆退，愁生唯怕酒腸枯。", "尊前學得新翻曲，早晚揮盃幸見呼。"]'),
('87b9cfc3-7cad-4345-a784-6baefef3af13','春寒','謝薖','宋','宋诗','song-poetry','','[]','冉冉雲生嶺，翻翻雨决渠。',48,'全唐诗/poet.song.79000.json','["冉冉雲生嶺，翻翻雨决渠。", "畏寒成墐户，惡濕問生魚。", "始愜春衫薄，俄驚團扇疏。", "天憐憔悴骨，莫遣峭風梳。"]'),
('7dff25d4-071f-46de-8c64-97282d6ddb8a','送香與董彦速二首  其一','謝薖','宋','宋诗','song-poetry','','[]','侯莎新補蔚宗傳，藿燥詹粘疑可憎。',32,'全唐诗/poet.song.79000.json','["侯莎新補蔚宗傳，藿燥詹粘疑可憎。", "試炷博山元不俗，小奩分供在家僧。"]'),
('a554d0a3-7166-4432-851e-6c4b7b0eadae','送香與董彦速二首  其二','謝薖','宋','宋诗','song-poetry','','[]','窗間一炷結趺坐，萬象森前應眼明。',32,'全唐诗/poet.song.79000.json','["窗間一炷結趺坐，萬象森前應眼明。", "不印香嚴薰未歇，何妨人誚太僧生。"]'),
('0371fa32-9650-4ba3-a8c7-b0c6fc9c3e48','暮春久雨','謝薖','宋','宋诗','song-poetry','','[]','季月何多雨，經旬不見山。',48,'全唐诗/poet.song.79000.json','["季月何多雨，經旬不見山。", "雲師工蔽塞，羲馭久間關。", "水已澤中滿，寒應天際還。", "壞墻憂盗入，只益髩毛斑。"]'),
('e3daea19-cd68-4857-bd3f-2c81b1fd7a79','晚春書事二首  其一','謝薖','宋','宋诗','song-poetry','','[]','春來畏病不飲酒，孤負山南山北花。',64,'全唐诗/poet.song.79000.json','["春來畏病不飲酒，孤負山南山北花。", "有客款門驚剥啄，無人追韻得車斜。", "獨酬砌下二三子，豈憶城南韋杜家。", "不畏詩窮嫌水厄，時時搜句煮新芽。"]'),
('534b4343-123c-4d31-bcb3-624e56bd620c','晚春書事二首  其二','謝薖','宋','宋诗','song-poetry','','[]','未曾留客十觴醉，已是飛花三月時。',64,'全唐诗/poet.song.79000.json','["未曾留客十觴醉，已是飛花三月時。", "忽悟病來真老矣，倘逢聖處亦中之。", "眼前用意半乾沒，世上忘形皆白癡。", "誰似陶翁有名酒，呼兒覓紙又題詩。"]'),
('a3a6118a-995b-46b9-9ea2-ac43e0d8f51d','和陳虛中與吕少逸唱酬口號','謝薖','宋','宋诗','song-poetry','','[]','霏霏玉唾勝三語，灔灔金荷傾十分。',64,'全唐诗/poet.song.79000.json','["霏霏玉唾勝三語，灔灔金荷傾十分。", "簷外催詩疑有雨，林間張幄豈須裙。", "臨溪尚憶童時釣，問俗仍寬柱後文。", "珍重兩公新句麗，落花依草競紛紛。"]'),
('ca55dc52-06ca-42d5-840c-4f472b3c8542','螢火','謝薖','宋','宋诗','song-poetry','','[]','日出知何許，宵行有底忙。',48,'全唐诗/poet.song.79000.json','["日出知何許，宵行有底忙。", "自疑緣寸草，不敢近扶桑。", "瑣碎豈堪数，神奇安得長。", "微風迹未掃，更待九秋霜。"]'),
('6ba708b6-3d54-4178-8cec-d32700d362a1','七夕書事','謝薖','宋','宋诗','song-poetry','','[]','燒燭留今夕，銜杯憶故年。',48,'全唐诗/poet.song.79000.json','["燒燭留今夕，銜杯憶故年。", "風前失二士，句裏問三玄。", "隨分瓜蔬設，占星古老傳。", "不須文乞巧，只有直如絃。"]'),
('822f7618-6764-47c8-a811-a0c6316731ec','朱濠州挽詞二首  其一','謝薖','宋','宋诗','song-poetry','','[]','俊軼金閨彦，風流粉署郎。',48,'全唐诗/poet.song.79000.json','["俊軼金閨彦，風流粉署郎。", "憂民形玉色，治郡輟鵷行。", "籍甚聞前席，居然歎掩芒。", "何人殺青簡，惠政在濠梁。"]'),
('b78077ef-8821-48d0-9dfb-f66cdd64272a','朱濠州挽詞二首  其二','謝薖','宋','宋诗','song-poetry','','[]','公才真霹靂，令德故從容。',48,'全唐诗/poet.song.79000.json','["公才真霹靂，令德故從容。", "未錫九環带，俄傾千丈松。", "清香銷燕寝，遺札陋登封。", "身後纍纍印，紆青已二龍。"]'),
('fde7afb6-197d-4bbb-b94c-886905d9d4ec','哭無逸兄三首  其一','謝薖','宋','宋诗','song-poetry','','[]','久客思鄉社，長歌去國門。',48,'全唐诗/poet.song.79000.json','["久客思鄉社，長歌去國門。", "還家未偃息，樹旐忽飛翻。", "苦淚不勝滴，悲懷誰與論。", "平生急難處，愁絕望鴒原。"]'),
('678654b8-7a56-4c51-8886-165b7adf93b2','哭無逸兄三首  其二','謝薖','宋','宋诗','song-poetry','','[]','文章不用世，歲忽值龍蛇。',48,'全唐诗/poet.song.79000.json','["文章不用世，歲忽值龍蛇。", "遽使賢人隕，長興志士嗟。", "有兒纔句讀，無地可桑麻。", "賴有興元尹，能賙孟氏家。"]'),
('7116c6ab-1c1a-45c7-a48f-e128f9540dde','哭無逸兄三首  其三','謝薖','宋','宋诗','song-poetry','','[]','溪堂載酒地，無復故人車。',48,'全唐诗/poet.song.79000.json','["溪堂載酒地，無復故人車。", "敗壁龍衣委，荒畦馬齒疏。", "凄凉閉關賦，淪落廣微書。", "但有清風在，時時爲掃除。"]'),
('dafcd138-0a11-453d-8813-bbabd1c548a6','題于逢辰畫','謝薖','宋','宋诗','song-poetry','','[]','踏遍江南岸，歸來試解衣。',48,'全唐诗/poet.song.79000.json','["踏遍江南岸，歸來試解衣。", "誰言物外賞，不與筆端爲。", "石带蒼苔瘦，風凋折葦稀。", "令人清興發，欲問釣魚磯。"]'),
('87f3aa97-9ce9-4e3e-b25a-02ef4e4ed6ce','戱咏石榴晚開二首  其一','謝薖','宋','宋诗','song-poetry','','[]','靡靡江蘺只喚愁，眼前何物可忘憂。',32,'全唐诗/poet.song.79000.json','["靡靡江蘺只喚愁，眼前何物可忘憂。", "楝花淨盡綠陰滿，纔見一枝安石榴。"]'),
('95a36c33-ad1c-4faf-9a45-43602c1c7a3c','戱咏石榴晚開二首  其二','謝薖','宋','宋诗','song-poetry','','[]','無復幽姿淡淡粧，胭脂深染薄羅裳。',32,'全唐诗/poet.song.79000.json','["無復幽姿淡淡粧，胭脂深染薄羅裳。", "芙容影裏避三舍，石竹叢中許擅場。"]'),
('ec849b25-51d4-43fe-95ef-87ab081de3aa','端午即事','謝薖','宋','宋诗','song-poetry','','[]','卯飲緣佳節，昌陽薦一巵。',48,'全唐诗/poet.song.79000.json','["卯飲緣佳節，昌陽薦一巵。", "兒諮射團事，妻誦賜衣詩。", "懶檢三閭傳，争纒五綵絲。", "平生幾端午，隨分作兒嬉。"]'),
('be4885ba-03bb-4949-8cf7-ee74b27a17fb','書李元亮真牧堂賦後','謝薖','宋','宋诗','song-poetry','','[]','揮翰眼中元亮，牧牛何處癯仙。',28,'全唐诗/poet.song.79000.json','["揮翰眼中元亮，牧牛何處癯仙。", "公擇如今不冺，當家諸子俱賢。"]'),
('87866207-222c-468c-ae3a-ed43f17d3101','題陳陽樹石二首  其一','謝薖','宋','宋诗','song-poetry','','[]','寒藤骨数百尺，枯木大七八圍。',28,'全唐诗/poet.song.79000.json','["寒藤骨数百尺，枯木大七八圍。", "挽取到公奇石，俱還数幅寒溪。"]'),
('b585e58d-2950-42af-84a9-2938b1ec9869','題陳陽樹石二首  其二','謝薖','宋','宋诗','song-poetry','','[]','解寫枯松潤石，陳陽筆意名家。',28,'全唐诗/poet.song.79000.json','["解寫枯松潤石，陳陽筆意名家。", "弟子蔡規今老，古人王宰何加。"]'),
('f6f9e198-4ce1-439b-b156-bac13d5eeb83','哭汪信民二首  其一','謝薖','宋','宋诗','song-poetry','','[]','竟欲遊梁苑，聊甘食楚萍。',48,'全唐诗/poet.song.79000.json','["竟欲遊梁苑，聊甘食楚萍。", "談經謝紈袴，植髪愬槐庭。", "着鏡髩毛改，横空煙霧冥。", "誰評貞曜謚，更謁退之銘。"]'),
('a7b11f72-6222-47ec-8d25-4c07a09222b0','哭汪信民二首  其二','謝薖','宋','宋诗','song-poetry','','[]','徐穉生何陋，袁宏輩豈如。',48,'全唐诗/poet.song.79000.json','["徐穉生何陋，袁宏輩豈如。", "誰知十斛水，中有百金魚。", "肘見貧非病，疽成憤不攄。", "銘旌返南國，寥落正愁予。"]'),
('d0f0682b-39c8-4581-a120-c72aebd1c342','杞菊','謝薖','宋','宋诗','song-poetry','','[]','雨洗幽叢清客襟，厨人採掇獨何心。',32,'全唐诗/poet.song.79000.json','["雨洗幽叢清客襟，厨人採掇獨何心。", "根苗扶老或名杖，蓓蕾舒黄無数金。"]'),
('3f255c8f-6085-4205-b4d1-fbfa506c2147','絡緯','謝薖','宋','宋诗','song-poetry','','[]','聒人長向井邊啼，在宇丁寧戒授衣。',32,'全唐诗/poet.song.79000.json','["聒人長向井邊啼，在宇丁寧戒授衣。", "織素盡輸官事了，秋來工女正投機。"]'),
('36011691-8a8e-4c1a-830e-b0eb22c4465d','倦夜','謝薖','宋','宋诗','song-poetry','','[]','山月斜臨帳，山風細拂裳。',48,'全唐诗/poet.song.79000.json','["山月斜臨帳，山風細拂裳。", "蕭蕭碧煙静，炯炯白間凉。", "境寂萬緣息，心灰千慮亡。", "無端催曙鳥，底事厭宵長。"]'),
('1eb6acfb-3b70-490b-a272-c1b78635aacc','喜董之南歸','謝薖','宋','宋诗','song-poetry','','[]','乾鵲飛翻噪晚林，阿南歸騎果駸駸。',64,'全唐诗/poet.song.79000.json','["乾鵲飛翻噪晚林，阿南歸騎果駸駸。", "青衫黄綬霑新命，白石清泉是素心。", "金鑷多情洗雙鬂，葛巾從此避華簪。", "來年往獻東巡頌，今日聊爲梁父吟。"]'),
('5941cee4-4449-42b7-9190-efa1440bc5db','懷祥首座','謝薖','宋','宋诗','song-poetry','','[]','師在羌廬西復東，無心還似鳥飛空。',64,'全唐诗/poet.song.79000.json','["師在羌廬西復東，無心還似鳥飛空。", "月鈎雲幙今何處，禅板蒲團只眼中。", "未悟竹間鳴瓦礫，擬隨童子問鈴風。", "前身倘是胡居士，打破虛空對沼公。"]'),
('3144cf9b-cfe8-4a2b-b807-d081b6e86e80','寄李商老兼簡文若季弓','謝薖','宋','宋诗','song-poetry','','[]','有客春來傳尺書，書詞字字敵瓊琚。',64,'全唐诗/poet.song.79000.json','["有客春來傳尺書，書詞字字敵瓊琚。", "經時伏枕沉綿甚，異縣論交消息疏。", "物外高情想三鳯，眼中何物當雙魚。", "遥知小弟凄凉意，騎省歸來正望廬。"]'),
('e9118d87-f98b-4344-b2b7-d027e13eb3eb','晝臥二首  其一','謝薖','宋','宋诗','song-poetry','','[]','書魔纔挽睡魔推，鼻息俄驚吼怒雷。',32,'全唐诗/poet.song.79000.json','["書魔纔挽睡魔推，鼻息俄驚吼怒雷。", "夢到逍遥大庭館，不堪簷外鳥驚回。"]'),
('49ff7942-2e43-421b-b905-6a2cbfb51a34','晝臥二首  其二','謝薖','宋','宋诗','song-poetry','','[]','剥剥啄啄無俗客，清清泠泠多好風。',32,'全唐诗/poet.song.79000.json','["剥剥啄啄無俗客，清清泠泠多好風。", "一枕本無憂樂累，何須遊宦大槐宫。"]'),
('e1c99625-ea87-4d5e-99cb-b59b4577dee0','青精飯三首  其一','謝薖','宋','宋诗','song-poetry','','[]','霍山王鄧兩真隱，駕鶴乘雲飛九天。',32,'全唐诗/poet.song.79000.json','["霍山王鄧兩真隱，駕鶴乘雲飛九天。", "當時服餌定何物，同飯青精三十年。"]'),
('426a7407-4ce8-42cb-b4e4-48cdf4fa4f98','青精飯三首  其二','謝薖','宋','宋诗','song-poetry','','[]','從來見說青精飯，晚遇真人隱訣中。',32,'全唐诗/poet.song.79000.json','["從來見說青精飯，晚遇真人隱訣中。", "長恨聞名不相識，那知俚俗號烏桐。"]'),
('38a7ea9a-262a-4030-9c3b-862468c35c41','青精飯三首  其三','謝薖','宋','宋诗','song-poetry','','[]','南人雖號烏桐飯，過熟翻成作淖糜。',32,'全唐诗/poet.song.79000.json','["南人雖號烏桐飯，過熟翻成作淖糜。", "太極真人方未試，茅山道士寄何遲。"]'),
('2df7268e-f53c-40f7-9f75-667306b50ea7','送酒與晏如居士二首  其一','謝薖','宋','宋诗','song-poetry','','[]','南人釀酒詫深紅，注瓦真成琥珀濃。',32,'全唐诗/poet.song.79000.json','["南人釀酒詫深紅，注瓦真成琥珀濃。", "與藥相投莫宜此，急分多病晏如翁。"]'),
('835b948f-6b14-43bb-bccd-1f85a71abadc','送酒與晏如居士二首  其二','謝薖','宋','宋诗','song-poetry','','[]','此翁寧把春償酒，醉插姚黄更乞花。',32,'全唐诗/poet.song.79000.json','["此翁寧把春償酒，醉插姚黄更乞花。", "多病只今猶解飲，細傾聊爲遣生涯。"]'),
('0b7ff6fd-95a8-4a98-8910-9d593aacc70a','示李商老兄弟','謝薖','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','月夜宜披宫錦袍，定知公輩豈蓬嵩。',64,'全唐诗/poet.song.79000.json','["月夜宜披宫錦袍，定知公輩豈蓬嵩。", "文如修水波瀾闊，人與廬山意氣高。", "伯氏最於三虎怒，凡兒何翅九牛毛。", "相逢徑欲倒家釀，莫厭尊前持蟹螯。"]'),
('43c731ba-b6e4-4ccb-9fb9-4e45987aaa71','夏日遊南湖','謝薖','宋','宋诗','song-poetry','','[]','麴塵裙與草爭綠，象鼻筩輕瓊作盃。',32,'全唐诗/poet.song.79000.json','["麴塵裙與草爭綠，象鼻筩輕瓊作盃。", "可惜小舟横兩槳，無人催送莫愁來。"]'),
('29b1ebcb-f006-4c2b-8751-63488e7e0c8b','咏金來禽','謝薖','宋','宋诗','song-poetry','','[]','枝上離離金弹丸，宜隨玉食薦金盤。',32,'全唐诗/poet.song.79000.json','["枝上離離金弹丸，宜隨玉食薦金盤。", "從來物以遠爲貴，酷愛閩中荔子丹。"]'),
('74fd9f05-2c22-4eae-bdfa-aa656f92f2a3','書懷','謝薖','宋','宋诗','song-poetry','','[]','賴有書遮眼，初無客就談。',48,'全唐诗/poet.song.79000.json','["賴有書遮眼，初無客就談。", "身閒唯取醉，髪短僅勝簪。", "學僻今何用，囊空寶不貪。", "老師行駐錫，凖擬問前三。"]'),
('a4c99494-8539-4048-9357-916512adccf6','次李商老端字韻','謝薖','宋','宋诗','song-poetry','','[]','胸中磊磊夜光寒，霹靂驚飛在舌端。',64,'全唐诗/poet.song.79000.json','["胸中磊磊夜光寒，霹靂驚飛在舌端。", "夢去幽尋遶山麓，詩來喜色上門闌。", "四時更運不停軌，萬物並流皆疾湍。", "兩髩凋零壮心在，忍窮懷抱若爲寬。"]'),
('f83d836a-5707-4a11-91fc-54fc3398261a','招汪叔野','謝薖','宋','宋诗','song-poetry','','[]','夜語僧窗雪載塗，别來夏木又扶疏。',64,'全唐诗/poet.song.79000.json','["夜語僧窗雪載塗，别來夏木又扶疏。", "兩牛鳴處地非遠，萬竹陰邊吾所廬。", "兒能竊聽從忘簟，子盍徐行可當車。", "莫訝南鄰狂處士，掺撾傾坐一軒渠。"]'),
('b9b555f2-1582-4c82-ac9e-b2b267cf8fd0','投贈通守陳虛中','謝薖','宋','宋诗','song-poetry','','[]','前驅負弩斾旌忙，凛凛寒風挟曉霜。',64,'全唐诗/poet.song.79000.json','["前驅負弩斾旌忙，凛凛寒風挟曉霜。", "人道奸藏有三穴，公知民病極千瘡。", "摇毫端是霹靂手，抵几還驚鳬鶩行。", "莫向琳宫坐閒冷，太阿何事匣中藏。"]'),
('ea4a8b0a-0320-4043-830f-3b111359b1b6','晚晴步塘上','謝薖','宋','宋诗','song-poetry','','[]','漫踏斜陽堤上行，偶逢白叟問年登。',32,'全唐诗/poet.song.79000.json','["漫踏斜陽堤上行，偶逢白叟問年登。", "去年禾乾龜兆拆，今年雨多禾耳生。"]'),
('0ac698f0-1011-4134-803d-0a15f8eaa830','鳴鳩','謝薖','宋','宋诗','song-poetry','','[]','雲陰解盡却殘暉，屋上鳴鳩喚婦歸。',32,'全唐诗/poet.song.79000.json','["雲陰解盡却殘暉，屋上鳴鳩喚婦歸。", "不見池塘煙雨裏，鴛鴦相並濕紅衣。"]'),
('f80ee1c5-2af5-43dc-bd3c-3dd3cb805d1b','聞吕居仁病未差覓使寄問','謝薖','宋','宋诗','song-poetry','','[]','消渴文園苦病多，蕭條子美臥江沱。',64,'全唐诗/poet.song.79000.json','["消渴文園苦病多，蕭條子美臥江沱。", "士窮不遇古如此，天實欲爲人謂何。", "忠義名家本申許，文章秀氣望岷峨。", "期君鍊玉煮白石，色比嬰童何啻過。"]'),
('1b77b211-1381-4a95-8544-a9bfd0489494','種竹','謝薖','宋','宋诗','song-poetry','','[]','闢地種修竹，得方緣秘經。',48,'全唐诗/poet.song.79000.json','["闢地種修竹，得方緣秘經。", "成陰向北宇，倒影落中庭。", "直取內含素，豈唯枝鬬青。", "龍鍾玉川子，猶擬抱添丁。"]'),
('b4f2f317-ab28-4068-af23-321021e8c797','次韻季智伯寄茶報酒三解  其一','謝薖','宋','宋诗','song-poetry','','[]','歡伯風流可解憂，疑君此外更無求。',32,'全唐诗/poet.song.79000.json','["歡伯風流可解憂，疑君此外更無求。", "揀芽投我真抛却，不是能詩薛許州。"]'),
('784e6279-de0b-45a9-b434-b4da3be8b1b8','次韻季智伯寄茶報酒三解  其二','謝薖','宋','宋诗','song-poetry','','[]','二生相逢妾換馬，我今真成酒易茶。',32,'全唐诗/poet.song.79000.json','["二生相逢妾換馬，我今真成酒易茶。", "腐腸銷膏亦可戒，與子服霧飱朝霞。"]'),
('a1aca6b4-fea2-417a-9f59-ad70f67de9b6','次韻季智伯寄茶報酒三解  其三','謝薖','宋','宋诗','song-poetry','','[]','君如張籍學古淡，麗處往往凌陰何。',32,'全唐诗/poet.song.79000.json','["君如張籍學古淡，麗處往往凌陰何。", "長句短章時寄我，爲君翻入竹枝歌。"]'),
('237ccefa-f1fc-4a61-8cb5-c897cb4f83d3','懷鍾陵舊遊','謝薖','宋','宋诗','song-poetry','','[]','五年三度過鍾陵，馬上春風醉夢醒。',64,'全唐诗/poet.song.79000.json','["五年三度過鍾陵，馬上春風醉夢醒。", "南浦江波迷眼綠，東湖煙柳半天青。", "從來地域歎卑薄，怪底山川終炳靈。", "又見徐家有高士，他年重作聘君亭。"]'),
('c99fd917-aec1-4596-8620-e981f143686e','湯泉泉在法水寺後','謝薖','宋','宋诗','song-poetry','','[]','亂泉如沸出灣環，餘燠猶霑野寺間。',32,'全唐诗/poet.song.79000.json','["亂泉如沸出灣環，餘燠猶霑野寺間。", "但與山僧洗塵垢，還勝漲膩在驪山。"]'),
('c2a8d0b2-4034-49ab-a036-6ce11d7e27ee','食蟹四首  其一','謝薖','宋','宋诗','song-poetry','','[]','端爲懷黄取醢烹，豈緣多足恣旁横。',32,'全唐诗/poet.song.79000.json','["端爲懷黄取醢烹，豈緣多足恣旁横。", "焚臍未用集鼠輩，椎髓方嫌太瘦生。"]'),
('b9d2c567-1739-4be6-954d-9b37a16507cc','食蟹四首  其二','謝薖','宋','宋诗','song-poetry','','[]','分付厨人苦見嫌，十臍元有九臍尖。',32,'全唐诗/poet.song.79000.json','["分付厨人苦見嫌，十臍元有九臍尖。", "要知其中未必有，輸與蛤蜊如蜜甜。"]'),
('b7aedaef-1ab0-49e6-be92-3092a49dc6d0','食蟹四首  其三','謝薖','宋','宋诗','song-poetry','','[]','論功直與酒盃同，何事生憎在水中。',32,'全唐诗/poet.song.79000.json','["論功直與酒盃同，何事生憎在水中。", "不使落湯頻下箸，終令骨醉耐春風。"]'),
('5d0e5876-32d3-41de-ab43-55da6e386970','食蟹四首  其四','謝薖','宋','宋诗','song-poetry','','[]','有國嘗憂以味亡，須知有毒味中藏。',32,'全唐诗/poet.song.79000.json','["有國嘗憂以味亡，須知有毒味中藏。", "誰能不累口腹事，莫趁秋風銜稻芒。"]'),
('cf47d42d-1942-4971-b3e7-029872fde3da','以牛膽漬槐子送董之南二首  其一','謝薖','宋','宋诗','song-poetry','','[]','雪霜無賴點君鬢，五十龍鍾成老翁。',32,'全唐诗/poet.song.79000.json','["雪霜無賴點君鬢，五十龍鍾成老翁。", "急分槐實要腦滿，佇見頭青雙頰紅。"]'),
('ff376af0-3120-40be-8941-38462216893e','以牛膽漬槐子送董之南二首  其二','謝薖','宋','宋诗','song-poetry','','[]','解牛得膽大如斗，投以元槐功更加。',32,'全唐诗/poet.song.79000.json','["解牛得膽大如斗，投以元槐功更加。", "來歲青袍映綠髪，不妨看盡九衢花。"]'),
('bdb0b4e8-8d98-4523-84f4-dedf1cb0271c','送王坦夫由淮南入京','謝薖','宋','宋诗','song-poetry','','[]','王郎乘興上扁舟，数遣書來寫我憂。',64,'全唐诗/poet.song.79000.json','["王郎乘興上扁舟，数遣書來寫我憂。", "奏牘三千待金馬，卷簾十里夢楊州。", "桃花水漲理歸檝，蓮葉盃香消客愁。", "白髪倚門長望子，細君應賦大刀頭。"]'),
('8319bffd-e024-4185-bb3a-99acd85c1513','遊安樂寺陳妙音載酒','謝薖','宋','宋诗','song-poetry','','[]','遶郭尋春未見花，不知春在梵王家。',64,'全唐诗/poet.song.79000.json','["遶郭尋春未見花，不知春在梵王家。", "林間新翠張裙幄，席上殘紅當臉霞。", "興逸持杯睨雲漢，飲酣揮翰走龍蛇。", "主人不是陳驚座，投轄歸時日已斜。"]'),
('7c92799c-7612-40d8-a3c8-21e4cc33fabc','聞無逸兄下第歸','謝薖','宋','宋诗','song-poetry','','[]','豐林分首各消魂，兄弟傷離况玉昆。',64,'全唐诗/poet.song.79000.json','["豐林分首各消魂，兄弟傷離况玉昆。", "初謂過都留虎脊，又令點額向龍門。", "往聞淮北雪花大，歸值江南梅雨昏。", "欲寄短書無别語，年來花柳自村村。"]'),
('0050062e-eae3-4e92-beb3-1ef998835daa','李簿家有侍兒妙麗善歌舞諸人惜其死爲賦詩予亦賦二首  其一','謝薖','宋','宋诗','song-poetry','','[]','草頭朝泣露漙漙，樵歌暮歸丘隴寒。',32,'全唐诗/poet.song.79000.json','["草頭朝泣露漙漙，樵歌暮歸丘隴寒。", "當時座上客半醉，琵琶不許近簾弹。"]'),
('93c1938c-7a90-41bb-b2ff-0791d80c818b','李簿家有侍兒妙麗善歌舞諸人惜其死爲賦詩予亦賦二首  其二','謝薖','宋','宋诗','song-poetry','','[]','郎子風流栖枳鸞，枳上单棲泣夜闌。',32,'全唐诗/poet.song.79000.json','["郎子風流栖枳鸞，枳上单棲泣夜闌。", "窗前邂逅一笑粲，夢中猶作在時看。"]'),
('943d7c12-cb5d-40f7-a49a-dd4c17fa63bc','久旱喜雨','謝薖','宋','宋诗','song-poetry','','[]','誰言旱魃虐，敢奪雨師權。',48,'全唐诗/poet.song.79000.json','["誰言旱魃虐，敢奪雨師權。", "瀰漫溪流漲，瀾翻屋霤懸。", "占年豐䆉稏，快意滌柈筵。", "疏懶知何幸，茅齋穩晝眠。"]'),
('1a0c3142-651f-4598-9f59-12701c575e8b','植菊','謝薖','宋','宋诗','song-poetry','','[]','憔悴靈均老，蕭條子美醒。',48,'全唐诗/poet.song.79000.json','["憔悴靈均老，蕭條子美醒。", "餐英謀自潔，摘蘂恨猶青。", "事往成今古，人亡尚典刑。", "鄙夫今白髪，賴汝制頽齡。"]'),
('a48af53f-f99a-4054-9ee4-7758e6e86057','有懷如璧道人二首  其一','謝薖','宋','宋诗','song-poetry','','[]','道人詩思瀉江湍，乞食侯門鋏屢弹。',32,'全唐诗/poet.song.79000.json','["道人詩思瀉江湍，乞食侯門鋏屢弹。", "鋪褐臥雲何處去，不應投老累儒冠。"]'),
('8afe7763-4f7f-4544-a2d4-919d572cd923','有懷如璧道人二首  其二','謝薖','宋','宋诗','song-poetry','','[]','每憶詩人賈閬仙，投冠去學祖師禅。',32,'全唐诗/poet.song.79000.json','["每憶詩人賈閬仙，投冠去學祖師禅。", "塵埃不染心如鏡，妙句何妨與世傳。"]'),
('501d7c6b-b8de-4321-938a-b78af1285a25','寄王立之二首  其一','謝薖','宋','宋诗','song-poetry','','[]','坎壈修門裏，蕭條處士廬。',48,'全唐诗/poet.song.79000.json','["坎壈修門裏，蕭條處士廬。", "憎人玉川子，憤世竹林書。", "家有來禽帖，門無載酒車。", "諸公生死隔，不是故人疏。"]'),
('5f1966f1-5246-4c3a-abf0-1d891d72be5b','寄王立之二首  其二','謝薖','宋','宋诗','song-poetry','','[]','舌本初傳强，仍聞右臂枯。',48,'全唐诗/poet.song.79000.json','["舌本初傳强，仍聞右臂枯。", "經春一旬臥，見客二兒扶。", "吾道何寥閴，夫君合洗蘇。", "世無湔浣手，藥味且時需。"]'),
('d1488f49-bd7e-49ed-88d6-6c98c6c72e72','贈别董彦速四首  其一','謝薖','宋','宋诗','song-poetry','','[]','人間底處異蘧廬，莫莫堂中豈定居。',32,'全唐诗/poet.song.79000.json','["人間底處異蘧廬，莫莫堂中豈定居。", "我尚滯留君去速，荒園三畝夢歸歟。"]'),
('1058f8b5-7aa4-42ba-b68e-74b319fea7c2','贈别董彦速四首  其二','謝薖','宋','宋诗','song-poetry','','[]','多謝清風日掃庭，與君同種菊青青。',32,'全唐诗/poet.song.79000.json','["多謝清風日掃庭，與君同種菊青青。", "開花爛熳君何在，莫忘蕭條我獨醒。"]'),
('ed4c1d0c-81af-46b5-8e5d-a2b3ea8a073e','贈别董彦速四首  其三','謝薖','宋','宋诗','song-poetry','','[]','欣同衆鳥託吾廬，投杖行當欲索居。',32,'全唐诗/poet.song.79000.json','["欣同衆鳥託吾廬，投杖行當欲索居。", "不是酸寒孟東野，吾言能聽果誰歟。"]'),
('6d03ef70-a1a5-4aa2-8315-60961b01491e','贈别董彦速四首  其四','謝薖','宋','宋诗','song-poetry','','[]','機事都捐憶大庭，茅簷相對眼俱青。',32,'全唐诗/poet.song.79000.json','["機事都捐憶大庭，茅簷相對眼俱青。", "期君别後文章健，往弔沅湘屈子醒。"]'),
('d91dedf1-800a-4936-a3a4-60b2dadc445f','次韻無逸兄見寄','謝薖','宋','宋诗','song-poetry','','[]','憔悴誰能賦大招，會将菌桂雜申椒。',64,'全唐诗/poet.song.79000.json','["憔悴誰能賦大招，會将菌桂雜申椒。", "巷南鄰里頻相過，水北山人詎可邀。", "細酌敢謀長袖舞，苦吟空咏寸岑遥。", "耕耘賴有陶潛婦，不羡孫郎對大橋。"]'),
('b143e196-860e-4ffc-bdda-735d407fdf8f','次汪信民寄無逸韻','謝薖','宋','宋诗','song-poetry','','[]','詩翁索莫閉門居，珍重山陽信不疏。',64,'全唐诗/poet.song.79000.json','["詩翁索莫閉門居，珍重山陽信不疏。", "但報七言當玉案，何須千里駕柴車。", "樂天官滿應歸早，揚子家貧只晏如。", "他日往來隨二老，共甘盂飯與盤蔬。"]'),
('ce197c43-8c2e-4ead-a98b-75707dbc5d12','送酥魚頭醤菜與何之忱三首  其一','謝薖','宋','宋诗','song-poetry','','[]','和蜜煎膏學甕酥，兒誇甘味比醍醐。',32,'全唐诗/poet.song.79000.json','["和蜜煎膏學甕酥，兒誇甘味比醍醐。", "老夫舌本不知味，强解嘲爲羊酪奴。"]'),
('cb63948c-392b-408b-bba8-547fc64f0e8b','送酥魚頭醤菜與何之忱三首  其二','謝薖','宋','宋诗','song-poetry','','[]','放浪三江又五湖，頭顱見醢亦何辜。',32,'全唐诗/poet.song.79000.json','["放浪三江又五湖，頭顱見醢亦何辜。", "世無剛者不用覆，往侑一觴隨蜜酥。"]'),
('b4dd0e3f-0603-4d84-ba98-2b93f5436e56','送酥魚頭醤菜與何之忱三首  其三','謝薖','宋','宋诗','song-poetry','','[]','甕底寒蔬冬作葅，春來把酒必時須。',32,'全唐诗/poet.song.79000.json','["甕底寒蔬冬作葅，春來把酒必時須。", "庾郎鮭菜二十七，還得何郎下箸無。"]'),
('c0392dc1-551e-4287-ba40-e5e103a3f47c','立夏日作四絕  其一','謝薖','宋','宋诗','song-poetry','','[]','雨脚連雲苦未收，曉驚池面日光流。',32,'全唐诗/poet.song.79000.json','["雨脚連雲苦未收，曉驚池面日光流。", "田家甑裏封蛛網，即漸歌謡麦有秋。"]'),
('f44eacfe-a1b3-45d0-965c-50a92ab09b12','立夏日作四絕  其二','謝薖','宋','宋诗','song-poetry','','[]','小簟含風六尺牀，竹奴從此合專房。',32,'全唐诗/poet.song.79000.json','["小簟含風六尺牀，竹奴從此合專房。", "吾身匏落都無用，占得山間一味凉。"]'),
('5affa67e-5dec-4d92-afbb-df078846a7c4','立夏日作四絕  其三','謝薖','宋','宋诗','song-poetry','','[]','熨得絺衣一番新，幅巾輕軟最宜人。',32,'全唐诗/poet.song.79000.json','["熨得絺衣一番新，幅巾輕軟最宜人。", "花時氣暖長愁夏，竹裏風微又勝春。"]'),
('dd64ad07-13d2-4ea8-9490-615d3f0228fb','立夏日作四絕  其四','謝薖','宋','宋诗','song-poetry','','[]','學作蒲葵扇未工，手揮聊有古人風。',32,'全唐诗/poet.song.79000.json','["學作蒲葵扇未工，手揮聊有古人風。", "君王别用機中練，定被南來長飬功。"]'),
('ffadcb98-e539-41d1-85eb-39a358d18302','寄劉世基用世基寄之忱韻','謝薖','宋','宋诗','song-poetry','','[]','斵堊誰能鼻不傷，虎賁何取似中郎。',64,'全唐诗/poet.song.79000.json','["斵堊誰能鼻不傷，虎賁何取似中郎。", "吾人身健間何闊，昨日書來喜欲狂。", "華屋不存長念昔，金蛇雖在莫干梁。", "幾時燒燭留君語，更向東窗置一牀。"]'),
('19a10d8b-4666-4410-8375-824f2df771d3','招李商老兄弟時聞權守陳公留之未聽其來','謝薖','宋','宋诗','song-poetry','','[]','十年不見令兄弟，眉宇長懷元紫芝。',64,'全唐诗/poet.song.79000.json','["十年不見令兄弟，眉宇長懷元紫芝。", "栩栩夢魂成獨往，翩翩書札慰相思。", "求船貨馬事應速，酌醴焚魚吾豈辭。", "政恐孟公投轄飲，惜君高論解人頤。"]'),
('1381033d-8c59-4bb3-b6f5-156ba5addc0f','次劉世基韻','謝薖','宋','宋诗','song-poetry','','[]','孔世已傳三十八，諸孫猶自見長身。',64,'全唐诗/poet.song.79000.json','["孔世已傳三十八，諸孫猶自見長身。", "試将後謝追前謝，豈料今人愧古人。", "華子岡頭千疊秀，劉郎詩律一朝新。", "吾家碧澗紅泉句，聊欲煩君作後塵。"]'),
('46583856-55af-4184-a5a2-05c5d8d2eb00','用前韻和董彦速','謝薖','宋','宋诗','song-poetry','','[]','得句可傳千古意，搜奇攻苦百年身。',64,'全唐诗/poet.song.79000.json','["得句可傳千古意，搜奇攻苦百年身。", "河梁贈别初無對，錦里吟春復有人。", "我已汗顔驚手縮，君猶瓊樹賞朝新。", "從今習氣須磨盡，二字唯當悟客塵。"]'),
('0741e170-e531-4364-a65f-604a9abd327b','夏日書事二首  其一','謝薖','宋','宋诗','song-poetry','','[]','蒼虬蟠礎濕生雲，翠竹摇風水有紋。',32,'全唐诗/poet.song.79000.json','["蒼虬蟠礎濕生雲，翠竹摇風水有紋。", "凉臥北窗呼不省，蟲飛遶髩夢中聞。"]'),
('e0fe15b7-f308-4b23-8fe8-f19a181f95c5','夏日書事二首  其二','謝薖','宋','宋诗','song-poetry','','[]','雲峰矗立駐金鴉，夢斷槐宫影未斜。',32,'全唐诗/poet.song.79000.json','["雲峰矗立駐金鴉，夢斷槐宫影未斜。", "屏翳御風遊不返，南山空轉阿香車。"]'),
('37fc8075-800b-4cea-845f-76649084346d','余嘗會李商老於海昏識吕居仁於符離今已五六年矣偶見二公倡和詩各次其韻一首 寄商老','謝薖','宋','宋诗','song-poetry','','[]','憶昔逢君夜雪中，高談未了酒尊空。',64,'全唐诗/poet.song.79000.json','["憶昔逢君夜雪中，高談未了酒尊空。", "清漣綠篠今輸我，白璧黄金政負公。", "渭水流清終異濁，池花變碧舊寧紅。", "欲評此意君何在，長是蒼茫立晚風。"]'),
('2a83cb06-e4b4-43dc-a1ad-f764466605d0','余嘗會李商老於海昏識吕居仁於符離今已五六年矣偶見二公倡和詩各次其韻一首 寄居仁','謝薖','宋','宋诗','song-poetry','','[]','維舟濁汴偶相逢，弹鋏歸來四壁空。',64,'全唐诗/poet.song.79000.json','["維舟濁汴偶相逢，弹鋏歸來四壁空。", "耕道十年常九潦，謀身一國自三公。", "似聞諷諭能知白，豈但詩詞要比紅。", "申國凛然生氣在，故知郎子有家風。"]'),
('ef0eafcc-2a45-4656-9365-5fb46e4c4720','玉茗花二首  其一','謝薖','宋','宋诗','song-poetry','','[]','佳園昨夜變春容，清曉驚開玉一叢。',64,'全唐诗/poet.song.79000.json','["佳園昨夜變春容，清曉驚開玉一叢。", "素質定欺雲液白，淺籹羞退鶴翎紅。", "似聞金谷初無種，欲畫鵝溪恐未工。", "底事餘花避三舍，孤高元有史君風。"]'),
('c1d02fc4-f56e-4f58-a102-6be46adba7f9','玉茗花二首  其二','謝薖','宋','宋诗','song-poetry','','[]','騷人浪說麻源谷，本在風流刾史家。',64,'全唐诗/poet.song.79000.json','["騷人浪說麻源谷，本在風流刾史家。", "直與瑶林共高徹，可須梅影闘横斜。", "芳尊莫待紅粧賞，幽艶長令烈士嗟。", "凴仗邊鸞折枝手，應宜展障玉鴉叉。"]'),
('fe75bec8-edf2-4e71-b810-c82eaf68811b','謾成','謝薖','宋','宋诗','song-poetry','','[]','年來任運學騰騰，愛酒還同醉李僧。',64,'全唐诗/poet.song.79000.json','["年來任運學騰騰，愛酒還同醉李僧。", "痛飲亡何緣客至，時奇不惜遶村行。", "簷間燕雀新聲好，門外池塘春水生。", "曉起坐窗無一事，捲書南望見高稜。"]'),
('f81fab60-b25e-48b0-aa30-c6fd141c88c3','飲酒示坐客','謝薖','宋','宋诗','song-poetry','','[]','身前不吝作蟲臂，身後何須留豹皮。',64,'全唐诗/poet.song.79000.json','["身前不吝作蟲臂，身後何須留豹皮。", "劬勞母氏生育我，造化小兒經紀之。", "牙籌在手彼爲得，塊石支頭吾所師。", "偶逢名酒輒徑醉，兒童拍手云公癡。"]'),
('9cb8c1e8-a029-4bfe-b125-0ae5864cace1','和李智伯金石臺不見舊題之作  其一','謝薖','宋','宋诗','song-poetry','','[]','瘞鶴書蹤逸少齊，華陽長使後人迷。',32,'全唐诗/poet.song.79000.json','["瘞鶴書蹤逸少齊，華陽長使後人迷。", "姓名不得芙蓉手，何用全牛捧硯題。"]'),
('f7c1075f-10e6-463f-a858-671134c52ecb','和李智伯金石臺不見舊題之作  其二','謝薖','宋','宋诗','song-poetry','','[]','復憶高人張季鷹，每将杯酒勝榮名。',32,'全唐诗/poet.song.79000.json','["復憶高人張季鷹，每将杯酒勝榮名。", "登臨叔子緣何事，湮滅無聞一愴情。"]'),
('e2566d58-a280-4da7-b04b-16d1ea70c588','悼亡三首  其一','謝薖','宋','宋诗','song-poetry','','[]','舊聞林下趣，既見即心降。',48,'全唐诗/poet.song.79000.json','["舊聞林下趣，既見即心降。", "月冷同秋夢，燈寒對夜窗。", "孰知身是幻，深念涕如江。", "仰嘆朝飛雉，微禽亦有雙。"]'),
('a0ca8575-2636-48de-8dde-7bb67520e9e7','悼亡三首  其二','謝薖','宋','宋诗','song-poetry','','[]','三公吾豈敢，寧爲忍饑寒。',48,'全唐诗/poet.song.79000.json','["三公吾豈敢，寧爲忍饑寒。", "擬聽笭箵雨，潛悲苜蓿盤。", "煙雲昏壁月，霜露殞香蘭。", "佇立東風泣，忘情良獨難。"]'),
('6ba62dcf-5390-4587-8f03-a11cd3ece210','悼亡三首  其三','謝薖','宋','宋诗','song-poetry','','[]','去作三泉隔，來歸二載餘。',48,'全唐诗/poet.song.79000.json','["去作三泉隔，來歸二載餘。", "臨風還念汝，傷女更憐渠。", "憔悴衣圍减，漂零鬢髪疏。", "吾今多病久，誰付茂陵書。"]'),
('c9fcbe5a-700f-43df-a402-3192d03cc4c4','呈無逸兄','謝薖','宋','宋诗','song-poetry','','[]','漢儒章句文勝質，魯國衣冠實愧名。',64,'全唐诗/poet.song.79000.json','["漢儒章句文勝質，魯國衣冠實愧名。", "但遣詩書長在眼，可令聲利苦關情。", "咄嗟苟飲有時辦，夢想溪堂何日成。", "舟泊寒沙臥明月，此期終欲與君盟。"]'),
('2242c337-5d23-4e90-95a2-49c5ca333a66','示舍弟','謝薖','宋','宋诗','song-poetry','','[]','蕭然環堵獨何有，自謂過人唯一丘。',64,'全唐诗/poet.song.79000.json','["蕭然環堵獨何有，自謂過人唯一丘。", "野性定爲滄海客，妙齡須寄道山遊。", "江寒沙静鶺鴒晚，雲闊天低鴻雁秋。", "休歎烏衣成往事，一尊相對且忘憂。"]'),
('9b3228f4-126a-4c32-a914-7554981b0475','寄桃鄰居士','謝薖','宋','宋诗','song-poetry','','[]','桃鄰野客無消息，寄食招提豈定居。',64,'全唐诗/poet.song.79000.json','["桃鄰野客無消息，寄食招提豈定居。", "倘有龐公知德撡，何須程鄭識相如。", "食魚他日勞弹鋏，舐痔今人剩得車。", "流落生涯俱寂寞，因風時遣一行書。"]'),
('6d2c7efe-0f6f-4ddf-a8a5-4929d030b944','寄無逸四首  其一','謝薖','宋','宋诗','song-poetry','','[]','三足祥烏曾集冠，平生菽水奉親歡。',32,'全唐诗/poet.song.79000.json','["三足祥烏曾集冠，平生菽水奉親歡。", "從今五鼎應無補，不可奈何君自寬。"]'),
('8a2585f7-77ae-4266-a3ab-14f973940959','寄無逸四首  其二','謝薖','宋','宋诗','song-poetry','','[]','聞說潘郎窘食貧，何年會面慰艱勤。',32,'全唐诗/poet.song.79000.json','["聞說潘郎窘食貧，何年會面慰艱勤。", "北風如有齊安便，爲報相思頻夢君。"]'),
('2b102849-467d-4423-a4b7-5e76d25cda88','寄無逸四首  其三','謝薖','宋','宋诗','song-poetry','','[]','故園風物長如舊，松柏參天六月凉。',32,'全唐诗/poet.song.79000.json','["故園風物長如舊，松柏參天六月凉。", "岑寂北窗風雨夜，獨吟詩句遶胡牀。"]'),
('2df84190-ae65-4eaa-8a72-8c728e0ecd41','寄無逸四首  其四','謝薖','宋','宋诗','song-poetry','','[]','浩蕩漳江瀉碧漪，西山清絕助新詩。',32,'全唐诗/poet.song.79000.json','["浩蕩漳江瀉碧漪，西山清絕助新詩。", "好因歸雁傳佳句，要見羊何共和之。"]'),
('b8738d9e-da3f-401d-9d3b-f6eb557104b9','觀李伯時陽關圖二首  其一','謝薖','宋','宋诗','song-poetry','','[]','坐對丹青傷别離，淚和朝雨想頻揮。',32,'全唐诗/poet.song.79000.json','["坐對丹青傷别離，淚和朝雨想頻揮。", "道邊垂柳年年在，看盡行人長不歸。"]'),
('a2882a76-33df-4ae3-a25c-093ecd035904','觀李伯時陽關圖二首  其二','謝薖','宋','宋诗','song-poetry','','[]','春草春波傷底事，青青柳色最消魂。',32,'全唐诗/poet.song.79000.json','["春草春波傷底事，青青柳色最消魂。", "龍眠自有離家恨，貎得陽關煙雨昏。"]'),
('2b428825-cb60-4957-8d26-c2511d48b66c','秋興','謝薖','宋','宋诗','song-poetry','','[]','雨隔千山暮，風驚一葉秋。',48,'全唐诗/poet.song.79000.json','["雨隔千山暮，風驚一葉秋。", "朱顔傷露槿，青眼賴沙鷗。", "畏酒遊揚夢，因詩點染愁。", "有懷誰與語，多病獨登樓。"]'),
('13a7147c-192a-43be-9b4b-edc7197783df','聽曹道士弹琴二首  其一','謝薖','宋','宋诗','song-poetry','','[]','淡泊綵絃誰與聽，試開塵匣寫幽情。',32,'全唐诗/poet.song.79000.json','["淡泊綵絃誰與聽，試開塵匣寫幽情。", "琴中自有無窮怨，弹出離騷意外聲。"]'),
('25247a34-4df4-45ce-9e73-a10bbffb5f7f','聽曹道士弹琴二首  其二','謝薖','宋','宋诗','song-poetry','','[]','小窗疏箔列仙家，弹盡遺音晚景斜。',32,'全唐诗/poet.song.79000.json','["小窗疏箔列仙家，弹盡遺音晚景斜。", "賀老當年定場屋，虛将妙曲付琵琶。"]'),
('b2356138-9208-42ee-8cf2-988aaab9c413','寒食出郊','謝薖','宋','宋诗','song-poetry','','[]','水晴鷗弄影，沙軟馬驚塵。',48,'全唐诗/poet.song.79000.json','["水晴鷗弄影，沙軟馬驚塵。", "密竹斜侵徑，幽花亂逼人。", "深行聽格磔，倦憇倚輪囷。", "往事悲青塜，年年芳草新。"]'),
('4a461409-e1f0-4d4a-8174-b7e6b3cd8845','寄洪鴻父二首','謝薖','宋','宋诗','song-poetry','','[]','兒時訪道漳江上，燕雀群中見阿鴻。',64,'全唐诗/poet.song.79000.json','["兒時訪道漳江上，燕雀群中見阿鴻。", "南浦飛雲看畫棟，北窗欹枕颯凉風。", "讀書長憶登山勝，作尉聊甘食薺窮。", "想見咏懷非一首，鈎章棘句定能工。"]'),
('a0457521-6bdb-4f4a-a5f8-a27e99613703','有懷潘子真','謝薖','宋','宋诗','song-poetry','','[]','冲和菴裏潘居士，旅食京城久不還。',64,'全唐诗/poet.song.79000.json','["冲和菴裏潘居士，旅食京城久不還。", "玉唾銀鉤長在眼，瑤林琪樹未承顔。", "大門曾是鄭嚴輩，吾子却居夷惠間。", "想見紅塵車馬底，夢魂隨雁過西山。"]'),
('d41997dc-bee6-4bb0-bbae-717c1e476d04','食菜','謝薖','宋','宋诗','song-poetry','','[]','道人真是伊蒲塞，頓頓園蔬入饌來。',64,'全唐诗/poet.song.79000.json','["道人真是伊蒲塞，頓頓園蔬入饌來。", "紫芥寒葅參薤韭，黄橙苦酒伴鹽梅。", "蒸豚不羡貯人乳，飯豆亦能羮芋魁。", "但恐酪奴不解事，攪令枵腹轉春雷。"]'),
('29a8fac1-0fc6-4ec8-89e4-e9a5ba0b955d','暮春二首  其一','謝薖','宋','宋诗','song-poetry','','[]','溜渠鳴玉雨成霖，春草池塘數尺深。',32,'全唐诗/poet.song.79000.json','["溜渠鳴玉雨成霖，春草池塘數尺深。", "後院落花人不到，無聊獨下海棠陰。"]'),
('76e4aaaa-0db9-4444-9141-6f87e1b6b2bf','暮春二首  其二','謝薖','宋','宋诗','song-poetry','','[]','晚雨墻東暗綠槐，清陰庭院鎻莓苔。',32,'全唐诗/poet.song.79000.json','["晚雨墻東暗綠槐，清陰庭院鎻莓苔。", "委堦紅藥将春去，貼水青荷與夏來。"]'),
('8193006d-949d-4891-8b63-358185edb0e1','春日黄梅花二首  其一','謝薖','宋','宋诗','song-poetry','','[]','臘梅初與雪争妍，素艶寒香亦可憐。',32,'全唐诗/poet.song.79000.json','["臘梅初與雪争妍，素艶寒香亦可憐。", "政使北風吹得盡，一枝金蓓始嫣然。"]'),
('4e90fef9-c20a-49c4-bbaf-22c4fc42ec08','春日黄梅花二首  其二','謝薖','宋','宋诗','song-poetry','','[]','傍人如笑不勝姸，曾是尋芳向臘前。',32,'全唐诗/poet.song.79000.json','["傍人如笑不勝姸，曾是尋芳向臘前。", "縱使遊蜂能拂掠，含酸結子爲誰圓。"]'),
('48db10a7-3b69-4d98-aad8-15e588b1ad34','梅花四首  其一','謝薖','宋','宋诗','song-poetry','','[]','姑射神遊閱九關，水精宫殿不勝寒。',32,'全唐诗/poet.song.79000.json','["姑射神遊閱九關，水精宫殿不勝寒。", "下窺人世生塵想，故作梅花與俗看。"]'),
('d144af57-dea1-462c-b2b6-e5eb69c0b054','梅花四首  其二','謝薖','宋','宋诗','song-poetry','','[]','清曉微開淺淺黄，蕭疏無奈北風凉。',32,'全唐诗/poet.song.79000.json','["清曉微開淺淺黄，蕭疏無奈北風凉。", "幽姿不許人窺見，故向寒林度暗香。"]'),
('00dc8513-f6d0-4012-9565-a18945c1ad2d','梅花四首  其三','謝薖','宋','宋诗','song-poetry','','[]','薔薇露染玉肌香，疏影寒光照野塘。',32,'全唐诗/poet.song.79000.json','["薔薇露染玉肌香，疏影寒光照野塘。", "長使詩人動幽興，不妨桃李鬭春粧。"]'),
('4bf53631-c131-4ae4-a6d1-8c1c0fcf9c8b','梅花四首  其四','謝薖','宋','宋诗','song-poetry','','[]','冷香零亂點寒莎，眼底愁生萬種多。',32,'全唐诗/poet.song.79000.json','["冷香零亂點寒莎，眼底愁生萬種多。", "收拾餘芳無處惜，只傳佳句似陰何。"]'),
('c606be1f-d844-4a4e-a59a-3a3b6efbeeff','送都仲獻','謝薖','宋','宋诗','song-poetry','','[]','酒曹懷璧暫投閒，俄許朱轓未賜環。',64,'全唐诗/poet.song.79000.json','["酒曹懷璧暫投閒，俄許朱轓未賜環。", "殿閣凉生應在眼，宫門騶唱合趨班。", "鳯皇觀德翔千仞，虎豹窺人礙九關。", "只恐蒼生傾望久，未容投紱老家山。"]'),
('411f01d2-df96-4dd1-8e01-01df735a55fe','寄題長沙高善時醉月堂','謝薖','宋','宋诗','song-poetry','','[]','亂山岑秀繞湘墳，君築茅堂底處村。',64,'全唐诗/poet.song.79000.json','["亂山岑秀繞湘墳，君築茅堂底處村。", "蠻國戈矛真夢幻，醉鄉風露别乾坤。", "平生不負南樓興，何日能同北海尊。", "聊欲揮毫書楚些，凴君招取獨醒魂。"]'),
('fdc120a5-fa4d-4fe6-8d53-ca3d50245d43','與江君佐遊五福寺觀竹二首  其一','謝薖','宋','宋诗','song-poetry','','[]','老子平生與竹群，清風洒濯勝三熏。',32,'全唐诗/poet.song.79000.json','["老子平生與竹群，清風洒濯勝三熏。", "江郎定自興不淺，共打僧門尋此君。"]'),
('0d207843-32e0-4fa9-840a-103ef7cd222d','與江君佐遊五福寺觀竹二首  其二','謝薖','宋','宋诗','song-poetry','','[]','小池環插碧琅玕，氣韻蕭梢六月寒。',32,'全唐诗/poet.song.79000.json','["小池環插碧琅玕，氣韻蕭梢六月寒。", "一夜清霜群木落，獨留孤節與君看。"]'),
('7ebe9943-64e0-4d51-ae5a-28427d5bdade','吳彩鸞寫真','謝薖','宋','宋诗','song-poetry','','[]','天上鳯皇難獨宿，人間翡翠本雙棲。',32,'全唐诗/poet.song.79000.json','["天上鳯皇難獨宿，人間翡翠本雙棲。", "丹青不共文蕭共，誰遣雉東迷雀西。"]'),
('efc455e6-3163-4e84-9a4e-6d619310db77','戱咏鼠鬚筆','謝薖','宋','宋诗','song-poetry','','[]','編須将取蝟毛磔，裁管縳成雞距長。',32,'全唐诗/poet.song.79000.json','["編須将取蝟毛磔，裁管縳成雞距長。", "誰言鼠鬚不足齒，也復論功翰墨場。"]'),
('25199cdf-f490-4bbb-8a71-216d15bcaa81','山間四首  其一','謝薖','宋','宋诗','song-poetry','','[]','籬落秋花未得霜，嫣然一笑媚秋陽。',32,'全唐诗/poet.song.79000.json','["籬落秋花未得霜，嫣然一笑媚秋陽。", "可人風味撩詩興，不記姚家宫樣黄。"]'),
('204f0c59-b275-40fc-af58-c6811e904ab4','山間四首  其二','謝薖','宋','宋诗','song-poetry','','[]','野老緣岡拾墮樵，溪童收網度横橋。',32,'全唐诗/poet.song.79000.json','["野老緣岡拾墮樵，溪童收網度横橋。", "高懷盡在行歌裏，豈信人間有市朝。"]'),
('30f62092-e514-4c8b-95b0-691517e09739','山間四首  其三','謝薖','宋','宋诗','song-poetry','','[]','未羡顔生樂一簞，一簞懸磬若爲歡。',32,'全唐诗/poet.song.79000.json','["未羡顔生樂一簞，一簞懸磬若爲歡。", "有田如使揚雄足，亦學前賢在澗槃。"]'),
('e67cd6cb-4288-44bc-8d43-4a7f3181cd80','山間四首  其四','謝薖','宋','宋诗','song-poetry','','[]','舉案齊眉老孟光，隱居無計可須忙。',32,'全唐诗/poet.song.79000.json','["舉案齊眉老孟光，隱居無計可須忙。", "殘年但使糟床注，亦付生涯與醉鄉。"]'),
('50fdc834-3ef5-46e9-87ee-84ff29ee8732','移松二首  其一','謝薖','宋','宋诗','song-poetry','','[]','古貎蒼髯十八公，巍巍獨出衆材中。',32,'全唐诗/poet.song.79000.json','["古貎蒼髯十八公，巍巍獨出衆材中。", "朝來挽致茅堂下，爲我商量送好風。"]'),
('0190e501-773f-454e-ac14-32000311f366','移松二首  其二','謝薖','宋','宋诗','song-poetry','','[]','河出崑崙派九州，屹然砥柱立中流。',32,'全唐诗/poet.song.79000.json','["河出崑崙派九州，屹然砥柱立中流。", "蒼松若比丘山重，豈但回頭費萬牛。"]'),
('908c605a-d8ae-4908-b176-8238c351284a','次韻吳民載告别覓酒二首  其一','謝薖','宋','宋诗','song-poetry','','[]','君詩起予者，百遍爲君開。',48,'全唐诗/poet.song.79000.json','["君詩起予者，百遍爲君開。", "世俗唯何甚，予心不可諧。", "獨思南去楚，衆欲北之回。", "何處可休影，期君歸去來。"]'),
('e2f475dd-a5e1-44e3-a14a-af2bc192f12e','次韻吳民載告别覓酒二首  其二','謝薖','宋','宋诗','song-poetry','','[]','齊下老從事，相逢青眼開。',48,'全唐诗/poet.song.79000.json','["齊下老從事，相逢青眼開。", "有朋方悃款，得汝更詼諧。", "老興此非淺，後車君與回。", "嘉蔬實空甒，併遣木奴來。"]'),
('25c4a14d-58ba-464d-8aef-4e9845c7764a','偶書二首  其一','謝薖','宋','宋诗','song-poetry','','[]','大儒讀書如布穀，小兒據几如王孫。',32,'全唐诗/poet.song.79000.json','["大儒讀書如布穀，小兒據几如王孫。", "道人竟日無一事，臥看前江煙雨昏。"]'),
('4caedfad-7ba4-4cc4-8eef-579fae71e7e0','偶書二首  其二','謝薖','宋','宋诗','song-poetry','','[]','平生蹇吃不解語，終日坐窗從客嘲。',32,'全唐诗/poet.song.79000.json','["平生蹇吃不解語，終日坐窗從客嘲。", "它年若使登要路，定被人譏無口匏。"]'),
('005905b7-0209-49e0-bb95-f99772372878','題陳先生華山高臥圖','謝薖','宋','宋诗','song-poetry','','[]','落葉開花秋復春，睡中榮悴豈關身。',32,'全唐诗/poet.song.79000.json','["落葉開花秋復春，睡中榮悴豈關身。", "那知五起雞三唱，亦有寒窗不寐人。"]'),
('ef36636a-34d6-4bb9-b23c-32dd54b55a01','和董彦光立春日二首  其一','謝薖','宋','宋诗','song-poetry','','[]','梅蕊飛翻柳色新，雪泥乾盡已成塵。',64,'全唐诗/poet.song.79000.json','["梅蕊飛翻柳色新，雪泥乾盡已成塵。", "愁看節物獨驚眼，醉吐詩詞君可人。", "藜杖應門原憲病，鸘裘貰酒茂陵貧。", "朝來似有飛揚意，可但無情草木春。"]'),
('4e25ea8b-e8f8-4910-a315-18fdb3e2dc4d','和董彦光立春日二首  其二','謝薖','宋','宋诗','song-poetry','','[]','交情自昔白頭新，富貴移人或望塵。',64,'全唐诗/poet.song.79000.json','["交情自昔白頭新，富貴移人或望塵。", "頋我喜求方外士，得君端是眼中人。", "謫仙詩富舊無敵，東野囊空今不貧。", "已遣掺掺縫古錦，共捜佳句賞新春。"]'),
('88e63518-49dc-4648-8bf4-04b41b139017','彦光示詩有釋氏之語復次韻','謝薖','宋','宋诗','song-poetry','','[]','歷眼浮榮逐日新，誰知澄寂本非塵。',64,'全唐诗/poet.song.79000.json','["歷眼浮榮逐日新，誰知澄寂本非塵。", "吾曹例作區中士，此味全輸世外人。", "空裏華生均是病，衣中寶在却憂貧。", "是間枯淡君姑置，且辦芳尊醉早春。"]'),
('05da9c4d-927b-473f-a399-f00741139a11','何之忱用前韻示詩復次韻','謝薖','宋','宋诗','song-poetry','','[]','揚子牢愁更美新，賈生悲鵩在承塵。',64,'全唐诗/poet.song.79000.json','["揚子牢愁更美新，賈生悲鵩在承塵。", "忘懷久已栽萱草，行樂尤欣見玉人。", "邂逅題詩聊可意，平生嗜酒豈憂貧。", "明年剩作顛茫計，劇飲狂歌莫負春。"]'),
('fc5881ea-2bd5-495c-be55-c0233aa274dc','從陳妙音覓酒二首  其一','謝薖','宋','宋诗','song-poetry','','[]','雪窗癡坐撥寒灰，萬斛清愁掃不開。',32,'全唐诗/poet.song.79000.json','["雪窗癡坐撥寒灰，萬斛清愁掃不開。", "排遣此懷将底物，凴君催送麴生來。"]'),
('7a188a12-7dcc-4d7d-b623-f150d7db550e','從陳妙音覓酒二首  其二','謝薖','宋','宋诗','song-poetry','','[]','長恐閨人抱頸羞，何當更脱鷫鸘裘。',32,'全唐诗/poet.song.79000.json','["長恐閨人抱頸羞，何當更脱鷫鸘裘。", "試煩郎子傾家釀，不用平原老督郵。"]'),
('cc13621e-7466-4ed8-9e64-f8f6a3a531a2','次韻董彦孚獨臥逸堂之句','謝薖','宋','宋诗','song-poetry','','[]','遶舍檀欒五月凉，歲寒高節亦難忘。',64,'全唐诗/poet.song.79000.json','["遶舍檀欒五月凉，歲寒高節亦難忘。", "期君鴻鵠應高舉，頋我蚍蜉豈自量。", "索價舊曾晞少室，荷鋤猶可繼柴桑。", "虚堂若許連床臥，待看風吹細細香。"]'),
('1e95b557-43f4-4c1a-97ff-5b3221e6b9dd','送黄柑與彦孚二首  其一','謝薖','宋','宋诗','song-poetry','','[]','殘臘才經一番霜，青青三寸作金黄。',32,'全唐诗/poet.song.79000.json','["殘臘才經一番霜，青青三寸作金黄。", "故園兄弟懷思我，特地分甘到草堂。"]'),
('333b82af-7ef5-4d67-b6b2-bf97f5d040ba','送黄柑與彦孚二首  其二','謝薖','宋','宋诗','song-poetry','','[]','手拆奇苞遺細君，更思特送逸堂人。',32,'全唐诗/poet.song.79000.json','["手拆奇苞遺細君，更思特送逸堂人。", "甘寒定可錦繡口，看吐新詩泣鬼神。"]'),
('194d7a42-d4a8-4bbb-907e-4f0f5c1f9513','過金山下作','謝薖','宋','宋诗','song-poetry','','[]','揚子江中風浪生，小舟如葉任欹傾。',64,'全唐诗/poet.song.79000.json','["揚子江中風浪生，小舟如葉任欹傾。", "槳摇齊指金山寺，霧暗初疑鐡甕城。", "絕頂逈分雙塔秀，層樓危立一僧清。", "他年來訪結菴地，吾與此江春水盟。"]'),
('5a12219e-929f-4b84-b704-a5517dfe6e31','獨登有美堂','謝薖','宋','宋诗','song-poetry','','[]','龜趺雙跱日星懸，讀罷凴闌心浩然。',64,'全唐诗/poet.song.79000.json','["龜趺雙跱日星懸，讀罷凴闌心浩然。", "繚繞峰巒浮野色，參差樓閣起晴烟。", "湖光凈照山間寺，江浪遥連海外天。", "安得翰林風月手，一時摩寫入詩篇。"]'),
('f64441f1-a245-47f7-9a5c-aa096c012869','雨中漫成四首  其一','謝薖','宋','宋诗','song-poetry','','[]','東風渾作勒花寒，寂寞林塘不受看。',32,'全唐诗/poet.song.79000.json','["東風渾作勒花寒，寂寞林塘不受看。", "玉版鶴翎俱未識，梨梢空有淚闌干。"]'),
('8602264f-3435-475e-9c14-7182c4757708','雨中漫成四首  其二','謝薖','宋','宋诗','song-poetry','','[]','向老逢春懶問花，惡風吹雨故斜斜。',32,'全唐诗/poet.song.79000.json','["向老逢春懶問花，惡風吹雨故斜斜。", "一城桃李應漂盡，不到城南韋杜家。"]'),
('486f226a-d744-424c-9d03-de441de1d1e2','雨中漫成四首  其三','謝薖','宋','宋诗','song-poetry','','[]','一樹山礬宫樣黄，曉風微送雨中香。',32,'全唐诗/poet.song.79000.json','["一樹山礬宫樣黄，曉風微送雨中香。", "鼻端空寂誰知許，莫怪雄蜂取次狂。"]'),
('bf759fdb-95fe-4dfe-8180-0437e2da242d','雨中漫成四首  其四','謝薖','宋','宋诗','song-poetry','','[]','纔見花飛掃不開，只今青子落莓苔。',32,'全唐诗/poet.song.79000.json','["纔見花飛掃不開，只今青子落莓苔。", "當時一咲冰雪面，曾動揚州詩興來。"]'),
('a727d451-e54b-4b61-936d-8de3910de7e3','送王山人','謝薖','宋','宋诗','song-poetry','','[]','秋風蕭瑟賦歸歟，此去懸知金有魚。',32,'全唐诗/poet.song.79000.json','["秋風蕭瑟賦歸歟，此去懸知金有魚。", "我亦羡君無奪糈，長沙終負過秦書。"]'),
('c6d6c0a6-ff64-4681-99a8-ffa625fa747d','滴滴金花','謝薖','宋','宋诗','song-poetry','','[]','滿庭黄色抑何深，一滴梅霖一滴金。',32,'全唐诗/poet.song.79000.json','["滿庭黄色抑何深，一滴梅霖一滴金。", "莫使貪夫來見此，聞名亦起覬覦心。"]'),
('8f2bc3bd-7673-4858-b0e2-f2c8f147d5f2','洗墨池','謝薖','宋','宋诗','song-poetry','','[]','張芝學書池水黑，章草如芝古無敵。',32,'全唐诗/poet.song.79000.json','["張芝學書池水黑，章草如芝古無敵。", "右軍睥睨難抗衡，恨不臨池作書癡。"]'),
('fcba54dd-a9ca-432c-91c5-e61400428ea1','代柬仲彝索酒','謝薖','宋','宋诗','song-poetry','','[]','月色皎如許，其如無酒何。',24,'全唐诗/poet.song.79000.json','["月色皎如許，其如無酒何。", "從君覓一斗，午夜泛金波。"]'),
('f89110c2-fe63-4842-a161-f707e2bc7cd1','春閨','謝薖','宋','宋诗','song-poetry','','[]','曲欄干外柳垂垂，羅幕輕風燕子飛。',32,'全唐诗/poet.song.79000.json','["曲欄干外柳垂垂，羅幕輕風燕子飛。", "獨倚危檻思往事，落紅撩亂點春衣。"]'),
('ba1503f0-5206-4710-bf8f-7ea56493c4e6','宿文殊寺','謝薖','宋','宋诗','song-poetry','','[]','踏破春雲深萬層，山靈放我作幽行。',64,'全唐诗/poet.song.79000.json','["踏破春雲深萬層，山靈放我作幽行。", "花香掠面不知處，鳥語可人如有情。", "風急遠聞簷馬響，月高清送木魚聲。", "禪床光滑氍毹軟，曲臂支頭聽瀑傾。"]'),
('ea7d71db-8864-4547-bf8a-a89ce72dde15','題括蒼洞','林靈素','宋','宋诗','song-poetry','','[]','落石泉聲寒遶宮，倚闌山色翠摩空。',32,'全唐诗/poet.song.79000.json','["落石泉聲寒遶宮，倚闌山色翠摩空。", "劉晨去後門長啟，時見桃花滿地紅。"]'),
('3d6abbff-7677-4c70-8dc4-f7210cd712c7','頌','林靈素','宋','宋诗','song-poetry','','[]','四十五歲勞生，浮名滿世崢嶸。',28,'全唐诗/poet.song.79000.json','["四十五歲勞生，浮名滿世崢嶸。", "只記神霄舊路，中秋月上三更。"]'),
('d008ed7c-599c-465f-839e-715a490508aa','呂洞賓','林靈素','宋','宋诗','song-poetry','','[]','捻土爲香事有因，世間宜假在宜真。',32,'全唐诗/poet.song.79000.json','["捻土爲香事有因，世間宜假在宜真。", "洞賓卻識林靈素，靈素何嘗識洞賓。"]'),
('60bccb1a-1782-467d-bac3-42efa68a7426','無題','林靈素','宋','宋诗','song-poetry','','[]','蘇黄不作文章客，童蔡翻爲社稷臣。',32,'全唐诗/poet.song.79000.json','["蘇黄不作文章客，童蔡翻爲社稷臣。", "三十年來無定論，不知奸黨是何人。"]'),
('8a38ac4e-5238-463c-877e-8f8c8790c263','遊天壇','林靈素','宋','宋诗','song-poetry','','[]','擺脫塵纓淡無欲，閑閱圖經尋岳瀆。',384,'全唐诗/poet.song.79000.json','["擺脫塵纓淡無欲，閑閱圖經尋岳瀆。", "林泉何處愜予心，收拾琴書將卜筑。", "崎嶇不敢千里辭，東至太行人王屋。", "先探藏花塢裏春，蟠桃畢竟何時熟。", "燕蘿故宅陽臺宮，九龍戲珠畫屏簇。", "丹井沉沉寢月明，丫髻仙童把參斸。", "昂頭貪看華蓋峰，驀然悮入紫微谷。", "上方樓閣與雲閑，金碧交輝射林麓。", "遠塵溝有遠塵人，夜半聞歌採芝曲。", "策杖窮躋瘦龍嶺，險似劍閣西向蜀。", "捫參歷井上沖冥，千劍斷崖橫獨木。", "自辰及酉腳力窮，恰到紫金堂下宿。", "再拜新嘗太乙泉，頓覺灑然消病骨。", "褰衣竟入南天門，回首乾坤小蠻觸。", "恍兮惚兮九霄間，萬頃嵐光醒醉目。", "銀座金腰玉頂寒，帝遣仙官分部屬。", "小有中藏萬里地，都壓洞大三十六。", "日精月華左右奇，黛色倚空如削玉。", "東觀大海日輪紅，西望窮邊壇影綠。", "煉丹爐下土猶香，抱出神丹知幾斛。", "巡山使者持太阿，保護神宮誰敢黷。", "王母洞深非可測，雷霆屢震蛟龍窟。", "遙指三官校勘臺，樵人幾度聞絲竹。", "抱朴巖前採藥童，手撚金芝身薜服。"]'),
('902c3241-26e8-4941-98fa-e7f6905e78de','句','林靈素','宋','宋诗','song-poetry','','[]','政和丁酉西風秋，天子賜以騎青牛。',16,'全唐诗/poet.song.79000.json','["政和丁酉西風秋，天子賜以騎青牛。"]'),
('5b2db79b-38a3-4f38-a413-2b21b359d14b','偈','釋法燈','宋','宋诗','song-poetry','','[]','耳底泉聲，眼前山色。',36,'全唐诗/poet.song.79000.json','["耳底泉聲，眼前山色。", "簷頭雨滴，籬畔黄華。", "嗈嗈新雁唳南雲，片片亭梧紅滿地。"]'),
