('f88670ff-3160-44bb-844a-988ae5923479','句  其四','釋法燈','宋','宋诗','song-poetry','','[]','未取負雪山。',6,'全唐诗/poet.song.79000.json','["未取負雪山。"]'),
('283b212d-0978-441a-a6a1-ca647f5365c0','句  其五','釋法燈','宋','宋诗','song-poetry','','[]','幽鳥語如簧。',6,'全唐诗/poet.song.79000.json','["幽鳥語如簧。"]'),
('f8694569-e85c-428a-b652-5fe8f1804ecb','投海偈二首  其一','釋凈元','宋','宋诗','song-poetry','','[]','我捨世間如夢，眾人須我作頌。',28,'全唐诗/poet.song.79000.json','["我捨世間如夢，眾人須我作頌。", "頌即語言邊事，了取自家真夢。"]'),
('f17cc10d-831e-4d7b-ab04-92f0102c0d12','投海偈二首  其二','釋凈元','宋','宋诗','song-poetry','','[]','世間人心易了，只爲人多不曉。',28,'全唐诗/poet.song.79000.json','["世間人心易了，只爲人多不曉。", "了即皎在目前，未了千般學道。"]'),
('10acf0bf-63d5-4b6a-8828-5c08a87bb47c','辭眾偈','釋凈元','宋','宋诗','song-poetry','','[]','會得祖師真妙訣，無得無物又無說。',32,'全唐诗/poet.song.79000.json','["會得祖師真妙訣，無得無物又無說。", "喝散烏雲千萬重，一點靈心明皎潔。"]'),
('1ed994d5-47ea-4778-9d48-ac550b4cff16','句','盧法原','宋','宋诗','song-poetry','','[]','若要少年並美貌，須還下部小尚書。',16,'全唐诗/poet.song.79000.json','["若要少年並美貌，須還下部小尚書。"]'),
('57b7eb26-2b38-4f04-9b62-6a53ffaeaf17','題梵隱院方丈梅','晏敦復','宋','宋诗','song-poetry','','[]','椏檻欹簷一古梅，幾番有意喚春回。',64,'全唐诗/poet.song.79000.json','["椏檻欹簷一古梅，幾番有意喚春回。", "開花自許清香入，布葉不容炎暑來。", "日射冷光侵几案，風搖翠影鎖莓苔。", "游蜂野蝶休相顧，木性從來不染埃。"]'),
('5d320d12-38e0-4836-a8a4-a380679c38a1','句  其一','晏敦復','宋','宋诗','song-poetry','','[]','何用粉牆高百尺，任教牆外俗人看。',16,'全唐诗/poet.song.79000.json','["何用粉牆高百尺，任教牆外俗人看。"]'),
('87c8dc13-5485-4ccb-a34c-5ae84b7c23ca','句  其二','晏敦復','宋','宋诗','song-poetry','','[]','春風任花落，流水放杯行。',12,'全唐诗/poet.song.79000.json','["春風任花落，流水放杯行。"]'),
('2458f3b2-9a62-4e05-a2bb-9613e0a2a5f7','同雲叟道人季西弟宿祈澤寺晨起示以此詩','趙㠓','宋','宋诗','song-poetry','','[]','道人自捲衣，欲往夫子林。',107,'全唐诗/poet.song.79000.json','["道人自捲衣，欲往夫子林。", "形瘦若鸛鶴，復作鸛鶴音。", "此音久不已，擾我清靜心。", "聽爾縱好語，鼎足三竹簪。", "松扃啟虛曉，將見晨曦侵。", "霜風滿招提，出望青煙岑從君行逾年，壯我方外吟。", "會須速招隱，脫身事幽尋。", "尚爲城郭叟，愧爾壁間琴。"]'),
('7057508c-cb33-495e-a402-36912760fc11','雲叟道人自夫子林驟款段先我而歸口占一詩戲之','趙㠓','宋','宋诗','song-poetry','','[]','道人乘款段，輒爾馳山川。',72,'全唐诗/poet.song.79000.json','["道人乘款段，輒爾馳山川。", "翻然兩角巾，似與風爭顛。", "左手不停勒，右手復爭鞭。", "烏裙拍馬腋，欲擬鶴升天。", "釋耕觀者人，莫知所以然。", "定疑雲路闊，墜落騎鹿僊。"]'),
('742c74f8-1d8e-4d2e-a77d-f6f11efa115d','偈','釋清素','宋','宋诗','song-poetry','','[]','顛倒顛，顛倒顛，新婦騎驢阿家牽。',32,'全唐诗/poet.song.79000.json','["顛倒顛，顛倒顛，新婦騎驢阿家牽。", "便恁麽，太無端，回頭不覺布衫穿。"]'),
('a1d64a9a-8859-4934-80f1-7b18fdb5a4c9','臨終偈','釋清素','宋','宋诗','song-poetry','','[]','木人備舟，鐵人備馬。',26,'全唐诗/poet.song.79000.json','["木人備舟，鐵人備馬。", "丙丁童子穩穩登，喝散白雲歸去也。"]'),
('32373d37-cfa9-48e6-a391-ab36a718e75f','集句  其一','聞人祥正','宋','宋诗','song-poetry','','[]','五夜漏聲催曉箭，曈曈初日照樓臺。',32,'全唐诗/poet.song.79000.json','["五夜漏聲催曉箭，曈曈初日照樓臺。", "九天閶闔開宮殿，玉帛朝元萬國來。"]'),
('a7858851-ad32-4835-a79f-87dd4de62e2b','集句  其二','聞人祥正','宋','宋诗','song-poetry','','[]','春風院院落花堆，花氣濃薰入酒杯。',32,'全唐诗/poet.song.79000.json','["春風院院落花堆，花氣濃薰入酒杯。", "日千殿頭宣索鱠，小舟撐出柳陰來。"]'),
('1b15c592-3a61-40d3-ba6f-acd019e11da7','集句  其三','聞人祥正','宋','宋诗','song-poetry','','[]','清明時節好煙光，柳苑春深百草芳。',32,'全唐诗/poet.song.79000.json','["清明時節好煙光，柳苑春深百草芳。", "一夜漢宮傳蠟燭，柳邊新火起嚴妝。"]'),
('8541a9c0-54f4-481c-a847-5f6468af6da5','集句  其四','聞人祥正','宋','宋诗','song-poetry','','[]','內人相續報花開，天子春游特地來。',32,'全唐诗/poet.song.79000.json','["內人相續報花開，天子春游特地來。", "夜半宴歸宮漏永，沸天宵鼓動瑤臺。"]'),
('ab8f6c72-e381-4d8e-86d5-d194f9e550d9','集句  其五','聞人祥正','宋','宋诗','song-poetry','','[]','繡衣鸂鶒浴回塘，風動荷花水殿香。',32,'全唐诗/poet.song.79000.json','["繡衣鸂鶒浴回塘，風動荷花水殿香。", "坐對芳尊不知熱，冰肌玉骨自清涼。"]'),
('ce6b55b1-233f-4e73-9b95-99c0c76e1c6d','集句  其六','聞人祥正','宋','宋诗','song-poetry','','[]','耿耿銀河欲曙天，數聲雞唱錦樓前。',32,'全唐诗/poet.song.79000.json','["耿耿銀河欲曙天，數聲雞唱錦樓前。", "君王曉坐金鑾殿，繡被焚香獨自眠。"]'),
('3da482ce-125f-4184-bc37-f242ab258cd1','集句  其七','聞人祥正','宋','宋诗','song-poetry','','[]','月傍蓬萊漢閣殘，玉階仙杖擁千官。',32,'全唐诗/poet.song.79000.json','["月傍蓬萊漢閣殘，玉階仙杖擁千官。", "侍臣緩步歸青瑣，辨色爭朝咫尺顔。"]'),
('eac5915c-5509-4b79-b6ae-5626e0ce9387','集句  其八','聞人祥正','宋','宋诗','song-poetry','','[]','羯鼓聲高眾樂停，上林仙景似蓬真。',32,'全唐诗/poet.song.79000.json','["羯鼓聲高眾樂停，上林仙景似蓬真。", "輕雲閣雨迎天仗，花外風飄萬歲聲。"]'),
('efa28fcf-481d-4459-a45f-4292c70f8aab','集句  其九','聞人祥正','宋','宋诗','song-poetry','','[]','牡丹移向苑中栽，借得東風一夜開。',32,'全唐诗/poet.song.79000.json','["牡丹移向苑中栽，借得東風一夜開。", "盡日君王看不足，芳尊宜命管弦來。"]'),
('f7c6e553-bdb5-47ce-9b61-317a5b5c4d20','集句  其一○','聞人祥正','宋','宋诗','song-poetry','','[]','月倚觚稜宿霧收，三千珠翠擁宸游。',32,'全唐诗/poet.song.79000.json','["月倚觚稜宿霧收，三千珠翠擁宸游。", "霓旌影亂簫聲遠，天子龍輿過玉樓。"]'),
('efb7b9c1-b018-40b3-947c-13d8bead6227','集句  其一一','聞人祥正','宋','宋诗','song-poetry','','[]','碧紗窗下水沈煙，香入薰爐禁火天。',32,'全唐诗/poet.song.79000.json','["碧紗窗下水沈煙，香入薰爐禁火天。", "最是一年春好處，綠楊高映畫秋千。"]'),
('4c2f42a0-3a16-446b-a680-73fc3a0d7ae5','集句  其一二','聞人祥正','宋','宋诗','song-poetry','','[]','連夜瓊林散舞衣，披香新殿鬬腰肢。',32,'全唐诗/poet.song.79000.json','["連夜瓊林散舞衣，披香新殿鬬腰肢。", "今朝卻得君王顧，從此新承恩澤時。"]'),
('6a7a55a4-596b-4266-af0f-cb2743256b0c','集句  其一三','聞人祥正','宋','宋诗','song-poetry','','[]','內人曉起怯春寒，惆悵階前紅牡丹。',32,'全唐诗/poet.song.79000.json','["內人曉起怯春寒，惆悵階前紅牡丹。", "整了翠鬟勻了面，沈香亭北倚闌干。"]'),
('78b85682-6431-4898-8eb2-fcf98a05c6ca','集句  其一四','聞人祥正','宋','宋诗','song-poetry','','[]','珠簾約住牡丹風，金殿香銷翠綺櫳。',32,'全唐诗/poet.song.79000.json','["珠簾約住牡丹風，金殿香銷翠綺櫳。", "應作巫陽春夢句，日高猶睡綠窗中。"]'),
('5936ba95-b3aa-4dce-a7e8-8965a81caa5c','集句  其一五','聞人祥正','宋','宋诗','song-poetry','','[]','淡淡梳妝薄薄脂，自然富貴出天姿。',32,'全唐诗/poet.song.79000.json','["淡淡梳妝薄薄脂，自然富貴出天姿。", "一朝選在君王側，宮女三千盡妬伊。"]'),
('4baafd99-dde8-49d5-a50c-dd3aa09cb059','集句  其一六','聞人祥正','宋','宋诗','song-poetry','','[]','玉壺傳箭咽銅龍，金殿當頭紫閣重。',32,'全唐诗/poet.song.79000.json','["玉壺傳箭咽銅龍，金殿當頭紫閣重。", "閶闔開門朝百辟，未央月曉度疏鐘。"]'),
('74418758-4f9b-47a0-bfad-e18d10ac82ba','集句  其一七','聞人祥正','宋','宋诗','song-poetry','','[]','珠箔輕明拂玉墀，漢宮仙掌露淋漓。',32,'全唐诗/poet.song.79000.json','["珠箔輕明拂玉墀，漢宮仙掌露淋漓。", "金釵墜鬢分行立，等候官家未出時。"]'),
('51c4bfb9-df8c-44c7-baad-fa5fb1886f5b','集句  其一八','聞人祥正','宋','宋诗','song-poetry','','[]','學畫蛾眉獨出群，越羅巴錦不勝春。',32,'全唐诗/poet.song.79000.json','["學畫蛾眉獨出群，越羅巴錦不勝春。", "承恩數上南熏殿，無奈宮中妬殺人。"]'),
('99fd5b32-4795-47f8-82fb-543751529f0a','集句  其一九','聞人祥正','宋','宋诗','song-poetry','','[]','春風先發苑中梅，願春君王萬壽杯。',32,'全唐诗/poet.song.79000.json','["春風先發苑中梅，願春君王萬壽杯。", "舞罷霓裳歸苑去，簫聲猶繞鳳皇臺。"]'),
('de613231-95b3-410f-b0cf-028e59d481c0','集句  其二○','聞人祥正','宋','宋诗','song-poetry','','[]','帝宮三五戲春臺，玉漏銅壺且莫催。',32,'全唐诗/poet.song.79000.json','["帝宮三五戲春臺，玉漏銅壺且莫催。", "百辟九霄環帝座，六鰲海上駕山來。"]'),
('753c4593-0fc7-4b2b-9e34-c33021fdd90d','集句  其二一','聞人祥正','宋','宋诗','song-poetry','','[]','東華金闕萬重開，何處聞燈不看來。',32,'全唐诗/poet.song.79000.json','["東華金闕萬重開，何處聞燈不看來。", "行幸未停歌未發，君王又進紫霞杯。"]'),
('6259a29a-425e-4555-838e-9768b864de1a','集句  其二二','聞人祥正','宋','宋诗','song-poetry','','[]','朝光瑞氣滿宮樓，一例珠簾不下鈎。',32,'全唐诗/poet.song.79000.json','["朝光瑞氣滿宮樓，一例珠簾不下鈎。", "認得聖顔遙望見，香煙欲傍衮龍浮。"]'),
('6efc9f10-ac40-4344-b1d8-7e72faf6dcdb','集句  其二三','聞人祥正','宋','宋诗','song-poetry','','[]','清曉妝成寒食天，芙蓉深院鬬秋千。',32,'全唐诗/poet.song.79000.json','["清曉妝成寒食天，芙蓉深院鬬秋千。", "君王未起珠簾捲，房裏圍棋嬾自眠。"]'),
('b3fe3497-e24b-4f19-9d32-9122440b04ad','集句  其二四','聞人祥正','宋','宋诗','song-poetry','','[]','長眉畫了繡簾開，榆火新傳蠟炬來。',32,'全唐诗/poet.song.79000.json','["長眉畫了繡簾開，榆火新傳蠟炬來。", "撲蝶西圍隨伴走，晚歸多是看花回。"]'),
('37de96e8-7abf-4c1c-ba14-1aa4ee084de2','集句  其二五','聞人祥正','宋','宋诗','song-poetry','','[]','翠髻高叢綠鬢虛，娉娉嫋嫋十三餘。',32,'全唐诗/poet.song.79000.json','["翠髻高叢綠鬢虛，娉娉嫋嫋十三餘。", "未央宮裏三千女，捲上珠簾總不如。"]'),
('85d20794-a2e5-4fb2-8481-75f6ee370a07','集句  其二六','聞人祥正','宋','宋诗','song-poetry','','[]','道字嬌訛苦未成，淡蛾羞歛不勝情。',32,'全唐诗/poet.song.79000.json','["道字嬌訛苦未成，淡蛾羞歛不勝情。", "有時歌罷下階砌，閑把宮花獨自行。"]'),
('0d07fbd3-6bd8-4fa2-b8bf-e5e11b1bc17f','集句  其二七','聞人祥正','宋','宋诗','song-poetry','','[]','黄金閣子鎖牙牀，不是愁人也斷腸。',32,'全唐诗/poet.song.79000.json','["黄金閣子鎖牙牀，不是愁人也斷腸。", "簾日已高三丈透，銅爐謾炷一銖香。"]'),
('06a419fd-3784-4bc3-ad73-f05cbdd1bc5f','建炎丞相成國呂忠穆公退老堂詩  其一','韓肖胄','宋','宋诗','song-poetry','','[]','兩持魁柄輔皇圖，退隱林泉歲再除。',64,'全唐诗/poet.song.79000.json','["兩持魁柄輔皇圖，退隱林泉歲再除。", "勳烈早推戡難際，精神不減渡江初。", "遙知台嶽靈仙窟，雅稱磻溪將相居。", "好在先聲震南楚，一堂風月暫躊躇。"]'),
('60814121-697f-4b96-b01e-e4b8698b9722','建炎丞相成國呂忠穆公退老堂詩  其二','韓肖胄','宋','宋诗','song-poetry','','[]','煌煌衮繡竚歸周，卜築寧容便退休。',64,'全唐诗/poet.song.79000.json','["煌煌衮繡竚歸周，卜築寧容便退休。", "濟上風煙移仿佛，浙東山水占深幽。", "清樽□□□□□，□□□□□□□。", "□□□□□□□，知公志在復神州。"]'),
('520db67b-950f-4c62-86f4-b386277dfce9','偈','釋慧素','宋','宋诗','song-poetry','','[]','一壞一不壞，笑殺觀自在。',24,'全唐诗/poet.song.79000.json','["一壞一不壞，笑殺觀自在。", "師子驀齩人，狂狗盡逐塊。"]'),
('f2d91cc1-5f28-44f5-94b9-c7ffd8951315','臨終偈','釋慧素','宋','宋诗','song-poetry','','[]','昨夜風雷忽爾，露柱生出兩指。',44,'全唐诗/poet.song.79000.json','["昨夜風雷忽爾，露柱生出兩指。", "天明笑倒燈籠，拄杖依前扶起。", "拂子𨁝跳過流沙，奪轉胡僧一隻履。"]'),
('3907b9cf-b2f6-438a-963f-8f8fcfa27060','偈','釋惟足','宋','宋诗','song-poetry','','[]','奔流渡刃，疾焰過風，已是鷂子過新羅。',49,'全唐诗/poet.song.79000.json','["奔流渡刃，疾焰過風，已是鷂子過新羅。", "倒拈蝎尾，逆捋虎鬚，作死馬醫了。", "移星換斗，倒嶽傾湫，卻較些子。"]'),
('c34750ab-a41f-4d91-b26d-a69d3452a32d','偈','釋德宏','宋','宋诗','song-poetry','','[]','上士相逢擊石火，迸出流星眨眼過。',52,'全唐诗/poet.song.79000.json','["上士相逢擊石火，迸出流星眨眼過。", "是渠成佛已多時，堪笑癡禪黑處坐。", "阿呵呵，冥然作夢幾時休，守卻飯籮空忍餓。"]'),
('eb913fe7-5fc5-4e28-8462-e6f34eb18d23','句','常某','宋','宋诗','song-poetry','','[]','水清詎免雙螯黑，秋老難逃一背紅。',16,'全唐诗/poet.song.79000.json','["水清詎免雙螯黑，秋老難逃一背紅。"]'),
('9b340066-03b3-4253-aaee-48cd049db1fa','獨山橋','俞𣓨','宋','宋诗','song-poetry','','[]','十里東郊正稅驂，清泉白石路曾諳。',64,'全唐诗/poet.song.79000.json','["十里東郊正稅驂，清泉白石路曾諳。", "野田水碓都舂雪，山市炊煙半雜嵐。", "俗美兒童歸塾讀，時和父老趁墟談。", "遠游何事追禽向，便擬村中著草庵。"]'),
('f245c404-4d9c-41c6-a2cb-b4fde2ae3c52','參陪使騎祗謁真祠偶成小詩拜呈知府屯田','于巽','宋','宋诗','song-poetry','','[]','千騎驂驔出禁城，真祠款謁罄虔誠。',64,'全唐诗/poet.song.79000.json','["千騎驂驔出禁城，真祠款謁罄虔誠。", "袴襦載路歌仁政，簫鼓喧天樂太平。", "殘雪未消山下路，和風先颺馬前旌。", "爲民祈禱多靈應，來歲豐穰定有成。"]'),
('7bbac9e9-27e7-43c6-aa74-789bc455c492','次韻和于巽祗謁真祠','尚佐均','宋','宋诗','song-poetry','','[]','踏霜投曉賽祠廷，豪竹繁絃妙吐誠。',64,'全唐诗/poet.song.79000.json','["踏霜投曉賽祠廷，豪竹繁絃妙吐誠。", "嘉客滿筵青眼看，遠山數點白雲平。", "淺霞漏日迎前騎，輕吹含煙獵後旌。", "好處畫工傳不盡，只憑詩筆爲摹成。"]'),
('12fe6264-33a0-43ba-8e83-e3f419a12e40','次韻和于巽祗謁真祠','王需','宋','宋诗','song-poetry','','[]','真人廟食占茲城，欲乞豐年在至誠。',64,'全唐诗/poet.song.79000.json','["真人廟食占茲城，欲乞豐年在至誠。", "五馬二車恭款謁，豐香烈火報登平。", "犬雞仙去遺丹竈，鸞鶴飛來認翠旌。", "既就金方留世子，終聞玉帝錄功成。"]'),
('dfa5aa49-8308-4f67-ae87-9482800e8a57','次韻和于巽祗謁真祠','王允中','宋','宋诗','song-poetry','','[]','縹緲仙臺俯郡城，躬修祠事表精誠。',64,'全唐诗/poet.song.79000.json','["縹緲仙臺俯郡城，躬修祠事表精誠。", "天邊霧卷山峰出，澗下風輕水面平。", "不爲尋春馳五馬，聊因勸課駐雙旌。", "風流別乘多才調，彩筆先揮秀句成。"]'),
('c556e40d-adee-4cfe-92ba-d21419aea1b4','次韻和于巽祗謁真祠','張介夫','宋','宋诗','song-poetry','','[]','曈曈曉日照重城，車騎翩翩布德誠。',64,'全唐诗/poet.song.79000.json','["曈曈曉日照重城，車騎翩翩布德誠。", "綽約仙姿隨世遠，依俙樓觀與雲平。", "神靈響答歆香火，民庶歡呼擁旆旌。", "瑞雪呈祥和氣洽，行看闔境報嘉成。"]'),
('32dcefa9-848f-44a1-91a9-1c2b65f83a7e','次韻和于巽祗謁真祠','張魴','宋','宋诗','song-poetry','','[]','仙翁舊隱寄巖扃，千里蒙休合薦誠。',64,'全唐诗/poet.song.79000.json','["仙翁舊隱寄巖扃，千里蒙休合薦誠。", "菽粟有餘民暇逸，雨暘無爽氣和平。", "簫笙緩緩陳觴豆，耆艾紛紛逐旆旌。", "靈迹欲知垂不朽，使君妙製刻初成。"]'),
('510c8653-a918-4f24-a400-658babcd4cc2','次韻和于巽祗謁真祠','高鈞','宋','宋诗','song-poetry','','[]','二公祠事出重城，宜有休祥答至誠。',64,'全唐诗/poet.song.79000.json','["二公祠事出重城，宜有休祥答至誠。", "林壑靜深經雪後，樓臺高下與雲平。", "豐年簫鼓來仙宅，晴日煙霞上使旌。", "黎庶歡聲自偕樂，但聞高廩頌周成。"]'),
('c682e598-3566-4cc8-8bde-f14ee1d9cd41','辭眾頌','釋了證','宋','宋诗','song-poetry','','[]','來時本無，去亦非有。',20,'全唐诗/poet.song.79000.json','["來時本無，去亦非有。", "珍重諸人，月明清晝。"]'),
('f9e4e0e3-021c-46e1-837b-7cb58fb03016','贈徐師川','王模','宋','宋诗','song-poetry','','[]','當日僉邪皆誤國，先生奮髯叱昌奴。',64,'全唐诗/poet.song.79000.json','["當日僉邪皆誤國，先生奮髯叱昌奴。", "一門忠節憑孤立，千載綱常賴力扶。", "直道原來師柳下，高風久已屬東湖。", "詩名四海猶餘事，也入紫薇宗派圖。"]'),
('09866f5c-bf6d-4bd9-bfc3-a6236a97beef','跋四時景畫 春','李錞','宋','宋诗','song-poetry','','[]','九江應共五湖連，尺素能開萬里天。',32,'全唐诗/poet.song.79000.json','["九江應共五湖連，尺素能開萬里天。", "山杏野桃零落處，分明寒食曉風前。"]'),
('ba5b6225-fc01-4303-8ddf-98a28aecb027','跋四時景畫 夏','李錞','宋','宋诗','song-poetry','','[]','繁陰雜樹映汀沙，三伏江天自一家。',32,'全唐诗/poet.song.79000.json','["繁陰雜樹映汀沙，三伏江天自一家。", "欲喚扁舟渡雲錦，平鋪明鏡是荷花。"]'),
('cd5aa410-a862-440e-9bca-b0913d92ecf6','跋四時景畫 秋','李錞','宋','宋诗','song-poetry','','[]','舂鉏寂寞繞疏叢，霜後雲生浦溆風。',32,'全唐诗/poet.song.79000.json','["舂鉏寂寞繞疏叢，霜後雲生浦溆風。", "此處年年報秋色，只應衰柳與丹楓。"]'),
('c5df5451-0981-4b9b-82e1-ca0c43d4a966','跋四時景畫 冬','李錞','宋','宋诗','song-poetry','','[]','翦水飛花細舞風，斷蘆洲外水連空。',32,'全唐诗/poet.song.79000.json','["翦水飛花細舞風，斷蘆洲外水連空。", "剡溪幾曲知名處，何似今朝眼界中。"]'),
('8bb519da-1785-4d42-8a00-1e594d91e67e','雍丘懷古','李錞','宋','宋诗','song-poetry','','[]','雍丘西風鼓戰塵，令狐抵死撓張巡。',32,'全唐诗/poet.song.79000.json','["雍丘西風鼓戰塵，令狐抵死撓張巡。", "面當六矢無降色，驚訝雷公是木人。"]'),
('785c719d-5902-4525-abe4-4d55a052f83a','烏','李錞','宋','宋诗','song-poetry','','[]','城頭老烏尾畢逋，呀呀飛來聲相呼。',104,'全唐诗/poet.song.79000.json','["城頭老烏尾畢逋，呀呀飛來聲相呼。", "未央宮殿夜方徂，紅靴玉带開金鋪。", "寶蟾吐水石芙蕖，日奉君王同歡虞。", "舞衣香墜紅氍毹，漏聲琤琤滴銅壺。", "烏啼未已星漸無，炯炯燭龍上天衢。", "萬年枝影轉扶疏，峨峨當殿群臣趨，請上當時無逸圖。"]'),
('46d48f75-605c-48f1-a0c8-1323cf38dd50','早梅  其一','李錞','宋','宋诗','song-poetry','','[]','雪徑清寒蝶未知，暗香誰遣好風吹。',32,'全唐诗/poet.song.79000.json','["雪徑清寒蝶未知，暗香誰遣好風吹。", "野橋漏洩春光處，正爲橫斜一兩枝。"]'),
('1b88cd25-5116-4ddd-82a7-bee9078c701c','早梅  其二','李錞','宋','宋诗','song-poetry','','[]','雄蜂雌蝶兩紛紛，梅子花香着莫人。',32,'全唐诗/poet.song.79000.json','["雄蜂雌蝶兩紛紛，梅子花香着莫人。", "風急落芙無藉在，已應先減幾多春。"]'),
('d2f4d3c5-5ed3-42f3-b654-105d9d4b61b8','消梅','李錞','宋','宋诗','song-poetry','','[]','曾看寒花弄寒月，月下橫斜裊香雪。',64,'全唐诗/poet.song.79000.json','["曾看寒花弄寒月，月下橫斜裊香雪。", "纔令詩眼散春愁，已見青青子爭結。", "夢懷碧脆薦冰盤，細雨江南映遠山。", "好事園林肯分我，不知塵土在長安。"]'),
('4064a0a2-507c-42eb-b37d-50074f3cac39','元夕','李錞','宋','宋诗','song-poetry','','[]','銀花火樹已春容，貝闕珠宮十二重。',64,'全唐诗/poet.song.79000.json','["銀花火樹已春容，貝闕珠宮十二重。", "席有嘉賓樽有酒，車如流水馬如龍。", "旌旗影暖烘宵燭，笳鼓聲喧侵曉鐘。", "行樂豈關吾輩事，夢回推枕起猶慵。"]'),
('6b4c35c6-e9f2-40ab-8972-75861110f334','句  其一','李錞','宋','宋诗','song-poetry','','[]','綠凈隨時看上魚。',8,'全唐诗/poet.song.79000.json','["綠凈隨時看上魚。"]'),
('3f3fce0e-c8aa-4810-a9f0-6ea560a3fb99','句  其二','李錞','宋','宋诗','song-poetry','','[]','散盡平生眼中客，暖風晴日閉門居。',16,'全唐诗/poet.song.79000.json','["散盡平生眼中客，暖風晴日閉門居。"]'),
('9ad418fd-4c78-4ab9-972d-b4eee0ba9b52','題顔魯公畫像','徐俯','宋','宋诗','song-poetry','','[]','公生開元間，壯及天寶亂。',144,'全唐诗/poet.song.79000.json','["公生開元間，壯及天寶亂。", "捐軀范陽兵，竟死蔡州叛。", "其賢似魏徴，天下非貞觀。", "四帝數十年，一身逢百難。", "少時讀書史，此事心已斷。", "老來鬢髪衰，慨歎功名晚。", "嗟哉忠義徒，捷去不可緩。", "初無當年悲，只令後世歎。", "一朝絕霖雨，南畝常亢旱。", "小人計雖得，斯民蓋塗炭。", "長歌永君節，千載勇夫愞。", "敬書子張紳，庶幾古人半。"]'),
('b806230b-89ba-480e-84e0-723f014d8c5f','滕王閣  其一','徐俯','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','一日逢王造，千年與客遊。',48,'全唐诗/poet.song.79000.json','["一日逢王造，千年與客遊。", "雲邊梅嶺出，坐上贛江流。", "日落迴飛鳥，烟深失釣舟。", "蟬聲枯柳外，天地晚風秋。"]'),
('cd5bf463-3750-4717-9cd4-90d9d0adf78a','滕王閣  其二','徐俯','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','雲氣浮高棟，波瀾遶古城。',48,'全唐诗/poet.song.79000.json','["雲氣浮高棟，波瀾遶古城。", "雨餘山更碧，葉下水逾清。", "燕語留秋色，鴉聲落晚晴。", "昔王歌舞地，帆急見山行。"]'),
('b9b8625e-92ab-4128-a105-46851c822507','同曾戶部吳縣尉張秀才北山僧房尋梅令客對棋','徐俯','宋','宋诗','song-poetry','','[]','處處已收南畝稻，閒閒還看北山梅。',64,'全唐诗/poet.song.79000.json','["處處已收南畝稻，閒閒還看北山梅。", "累觴聊爾酡顔在，對局怡然笑口開。", "掃徑似知佳客至，杖藜惟可數君來。", "移松種樹鄱陽老，章貢風帆歲一迴。"]'),
('572b802a-54d5-42c7-8c8d-6cc68a2e3802','庭中梅花正開用舊韻貽端伯','徐俯','宋','宋诗','song-poetry','','[]','羌笛何勞塞北吹，江南何處不寒梅。',64,'全唐诗/poet.song.79000.json','["羌笛何勞塞北吹，江南何處不寒梅。", "千秋寂寂無人看，獨樹亭亭對客開。", "偏爲咨嗟惟爾念，是誰移種待君來。", "縱留一曲安能唱，恰似朝歌墨子迴。"]'),
('19abdc90-8e20-4efd-8cfb-d6538b08ad59','戊午山間對雪','徐俯','宋','宋诗','song-poetry','','[]','雪中出去雪邊行，屋下吹來屋上平。',64,'全唐诗/poet.song.79000.json','["雪中出去雪邊行，屋下吹來屋上平。", "積得重重那許重，飛來片片又何輕。", "簷間日暖重爲雨，林下風吹再落晴。", "表裏江山應更好，溪山已復不勝清。"]'),
('86ff1a0c-af65-4ab1-8ef1-6672a35e77ae','詠史','徐俯','宋','宋诗','song-poetry','','[]','楚漢分爭辨士憂，東歸那復割鴻溝。',32,'全唐诗/poet.song.79000.json','["楚漢分爭辨士憂，東歸那復割鴻溝。", "鄭君立義不名藉，項伯胡顔肯姓劉。"]'),
('5dcf8f37-2522-4e6a-9313-3983151d321a','游潛峰二首  其一','徐俯','宋','宋诗','song-poetry','','[]','昔年會稽探尚書，探得六甲開山圖。',112,'全唐诗/poet.song.79000.json','["昔年會稽探尚書，探得六甲開山圖。", "載之潛南天柱山，上侵霄漢下淵泉。", "真人秘語世不傳，但見絕頂蒙雲烟。", "漢武射蛟浮九江，舳艫千里來樅陽。", "築壇祈仙瞻杳茫，茂陵檜柱空青蒼。", "石牛一臥叱不起，白鹿還歸深洞裏。", "二月靈鶴有來時，洞口桃花泛流水。"]'),
('0df0e310-0751-4c72-ac37-255666c08259','游潛峰二首  其二','徐俯','宋','宋诗','song-poetry','','[]','久留舒子國，慣作北門遊。',24,'全唐诗/poet.song.79000.json','["久留舒子國，慣作北門遊。", "山遠三峰出，溪長二水流。"]'),
('7a71cbbf-cd99-494b-8af8-5f7f3f5f0baf','明皇夜游圖','徐俯','宋','宋诗','song-poetry','','[]','歌吹開元曲，鉛華天寶粧。',48,'全唐诗/poet.song.79000.json','["歌吹開元曲，鉛華天寶粧。", "苑風翠袖冷，宫露赭袍光。", "閨闥連閶闔，驊騮從驌驦。", "千門還欲曉，九陌乍聞香。"]'),
('2a0c250d-b94f-4dc2-93fa-f0d81e21d788','李賀晚歸圖','徐俯','宋','宋诗','song-poetry','','[]','近代推名畫，諸君作薦書。',48,'全唐诗/poet.song.79000.json','["近代推名畫，諸君作薦書。", "皇都開藝學，博士是新除。", "高柳長安道，亂雲昌谷居。", "丹青聊至此，僕馬晚歸歟。"]'),
('f974f597-d411-4d20-82a7-d0d9c19d705b','饒守董尚書令畫史繪釋迦出山相及維摩居士使靈山香火之因不斷復惠臘藥數種皆病夫所欲也作此寄之','徐俯','宋','宋诗','song-poetry','','[]','示病毗耶金粟影，出山五祖金仙相。',96,'全唐诗/poet.song.79000.json','["示病毗耶金粟影，出山五祖金仙相。", "神妙通靈顧虎頭，白蓮香火空諸妄。", "臘中發藥補衰朽，扶杖清風看花柳。", "捷書政用此時來，開顔正爾難忘酒。", "韓門弟子更誰如，即今猶有董安于。", "更有承明兩學士，與公相對白髭鬚。"]'),
('7d99e065-fb04-4046-9c41-27ffcd740761','成生山水畫歌','徐俯','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','畫水不畫濕，畫山不畫堅。',124,'全唐诗/poet.song.79000.json','["畫水不畫濕，畫山不畫堅。", "盈尺之紙數寸管，便有江湖萬里天。", "成生貎古心亦古，造化爲工筆端取。", "玄冬起雷夏造冰，翻手作雲覆手雨。", "嶺外荒山與野水，自昔不聞傳畫史。", "只畫瀟湘與洞庭，于今却在兵戈裏。", "翠峰碧嶂鬰然來，病眼愁心次第開。", "人家浦溆扁舟渡，何日真能到一迴。"]'),
('85559241-cc51-42c1-8762-93cfbf6da3d1','次韻可師題于逢辰畫山水二首  其一','徐俯','宋','宋诗','song-poetry','','[]','江漢踰千里，陰晴自一川。',48,'全唐诗/poet.song.79000.json','["江漢踰千里，陰晴自一川。", "故山黄葉下，夢境白鷗前。", "巫峽常雲雨，香爐舊紫烟。", "布帆無恙在，速上釣魚船。"]'),
('fd62773e-f8d9-43b9-af33-8dc2c51d27ca','次韻可師題于逢辰畫山水二首  其二','徐俯','宋','宋诗','song-poetry','','[]','席上浮三楚，毫端會百川。',48,'全唐诗/poet.song.79000.json','["席上浮三楚，毫端會百川。", "名今大年亞，意古惠崇前。", "竟日對秋色，無時散暝烟。", "知君不浪語，一眼認歸船。"]'),
('d70b1801-9c5f-4383-a955-82b2f20f557d','單老畫樹石山水歌','徐俯','宋','宋诗','song-poetry','','[]','老樹筆間生，奇石筆下出。',60,'全唐诗/poet.song.79000.json','["老樹筆間生，奇石筆下出。", "濃淡高低遠近山，陰晴朝暮烟雲沒。", "漠漠江天杳杳空，不勞施力自然中。", "便于沙際尋歸路，却怪霜林葉不紅。"]'),
('1a18c7bd-93bb-4e10-9a7e-702c2b08cb29','畫虎行爲吉州假守蘇公作','徐俯','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔日何人畫於菟，君家獨有他家無。',160,'全唐诗/poet.song.79000.json','["昔日何人畫於菟，君家獨有他家無。", "宣城老包骨已朽，紛紛俗子尚讙呼。", "大虎蹲踞小虎戲，目光注射百步外。", "名畫多聞內府收，人間豈惜千金費。", "巉巉岩岩谷中石，老樹穹枝拂秋色。", "銳頭將軍射不得，卻挂江南使君壁。", "林間一嘯四山風，麏驚狐號鳥墮空。", "不向南山隨李廣，只愁東海笑黄公。", "憶昔余頑少小時，先生教誦荆公詩。", "只今耆舊無新語，賴有廬山病可師。"]'),
('78d8f892-d4d0-425d-9610-617e8ab86ff6','再次韻題于生畫豹二首  其一','徐俯','宋','宋诗','song-poetry','','[]','耽酒豐城客子，醉畫山崦人家。',28,'全唐诗/poet.song.79000.json','["耽酒豐城客子，醉畫山崦人家。", "他日營丘伯仲，高名遠出長沙。"]'),
('bb05a63f-af8d-45d3-927a-e74300ed4ade','再次韻題于生畫豹二首  其二','徐俯','宋','宋诗','song-poetry','','[]','彭蠡何限秋鴈，此君胸次爲家。',28,'全唐诗/poet.song.79000.json','["彭蠡何限秋鴈，此君胸次爲家。", "醉裏舉羣飛出，著行排立平沙。"]'),
('77f4f8dd-7e13-46c2-8f29-5588a1708123','春日登眺遊寶勝諸寺且觀名畫','徐俯','宋','宋诗','song-poetry','','[]','護法儼神龍，諸天擁梵宫。',48,'全唐诗/poet.song.79000.json','["護法儼神龍，諸天擁梵宫。", "樓臺春日麗，海岳畫圖雄。", "浦樹重重綠，園花灼灼紅。", "微風吹細雨，只在夕陽中。"]'),
('9217cd50-4067-495c-a550-a4af6e078a64','次可師韻','徐俯','宋','宋诗','song-poetry','','[]','五湖出畫師手，一葉浮漁父家。',28,'全唐诗/poet.song.79000.json','["五湖出畫師手，一葉浮漁父家。", "風裏芙蓉野色，雨中鴻鴈汀沙。"]'),
('82395734-0d07-42f4-bfac-c5874dfe4c63','白鷺洲','徐俯','宋','宋诗','song-poetry','','[]','金陵與廬陵，俱出白鷺洲。',24,'全唐诗/poet.song.79000.json','["金陵與廬陵，俱出白鷺洲。", "相望萬里江，中同二水流。"]'),
('ea35b422-3927-4c39-a500-ee08e44a4748','雙廟','徐俯','宋','宋诗','song-poetry','','[]','開元天寶間，衮衮見諸公。',24,'全唐诗/poet.song.79000.json','["開元天寶間，衮衮見諸公。", "不聞張與許，名在臺省中。"]'),
('95219328-0d10-4b34-a7cf-a7a6ef6838ad','跋韓子蒼代葛亞卿詩','徐俯','宋','宋诗','song-poetry','','[]','夏木陰陰欲放船，黄鸝啼了落花天。',32,'全唐诗/poet.song.79000.json','["夏木陰陰欲放船，黄鸝啼了落花天。", "十詩盡說人間事，付與風流葛稚川。"]'),
('dafd14b0-f09c-4993-92c4-1293469e5187','訪鄒道卿故居','徐俯','宋','宋诗','song-poetry','','[]','履霜頗强徤，晨興恣所適。',72,'全唐诗/poet.song.79000.json','["履霜頗强徤，晨興恣所適。", "兩兒休籃輿，呼客同蠟屐。", "危橋出隘巷，憑高聊物色。", "蒿然但林莽，蕪廢長荆棘。", "井灶那復移，江山依舊碧。", "要知千載下，懷賢求所歷。"]'),
('51e4f1e2-e7bb-4aea-b55e-a92a733f71fd','詩一首','徐俯','宋','宋诗','song-poetry','','[]','人言春事已，我言未遽央。',24,'全唐诗/poet.song.79000.json','["人言春事已，我言未遽央。", "試向後湖去，菰葉如許長。"]'),
('5ac23aef-f50f-4097-a95a-717f68a5ca25','陪李泰發登洪川南樓','徐俯','宋','宋诗','song-poetry','','[]','十年不復上南樓，直爲干戈作遠游。',64,'全唐诗/poet.song.79000.json','["十年不復上南樓，直爲干戈作遠游。", "滿地江湖春入望，連天章貢水爭流。", "青雲聊爾居金馬，紫氣還應射斗牛。", "公是主人身是客，舉觴登望得無愁。"]'),
('b83b3b12-594a-44e8-ab66-e542fd0e801b','昭州感梅公摯鄒道鄉遺蹟','徐俯','宋','宋诗','song-poetry','','[]','正言鄒子獨留名，法從梅公尚有亭。',64,'全唐诗/poet.song.79000.json','["正言鄒子獨留名，法從梅公尚有亭。", "藥是苦言能治瘴，竹生屈曲坐看經。", "風前雲似秋前赤，雨後山能燒後青。", "戀土懷鄉頻作惡，懷賢感舊嘆飄零。"]'),
('a95ff8ef-b87c-4d23-9848-22299ea13d40','上郡守','徐俯','宋','宋诗','song-poetry','','[]','尚書八座貴，大使十州雄。',24,'全唐诗/poet.song.79000.json','["尚書八座貴，大使十州雄。", "仁民兼愛物，時雨及春風。"]'),
('eae21356-4d07-4c61-8dd3-61f4b5a0f073','題畫','徐俯','宋','宋诗','song-poetry','','[]','五日十日一水石，此言雖工蓋其跡。',48,'全唐诗/poet.song.79000.json','["五日十日一水石，此言雖工蓋其跡。", "請看天地開闢初，煉就日魂鎔月魄。", "貴人費盡數寸管，中有江湖萬里客。"]'),
('b647b55d-808d-4afc-aea3-f7c0b5ace858','安慶府','徐俯','宋','宋诗','song-poetry','','[]','君過秋浦正逢秋，亦到樅陽皖水頭。',32,'全唐诗/poet.song.79000.json','["君過秋浦正逢秋，亦到樅陽皖水頭。", "九派先將明月去，三峰少爲白雲留。"]'),
('36306a5a-023a-4e74-ac34-4fc42051429d','喜王秀才見過小酌玩月','徐俯','宋','宋诗','song-poetry','','[]','君家近市，所見天咫。',40,'全唐诗/poet.song.79000.json','["君家近市，所見天咫。", "庭戶之間，容光能幾。", "蒓蒲之中，江湖之涘。", "雲碧萬頃，長空千里。"]'),
('ceb76e6f-4c8b-4e78-acca-2faed7a09b79','太平州二首  其一','徐俯','宋','宋诗','song-poetry','','[]','便風擊鼓太平州，斜日落帆大信口。',32,'全唐诗/poet.song.79000.json','["便風擊鼓太平州，斜日落帆大信口。", "二年兩見黄山塔，平生不飲姑孰酒。"]'),
('b6895160-afc2-4835-98ef-0677a13fa852','太平州二首  其二','徐俯','宋','宋诗','song-poetry','','[]','南人北人朝暮船，東梁西梁今古天。',32,'全唐诗/poet.song.79000.json','["南人北人朝暮船，東梁西梁今古天。", "茲地何時復回首，遡流千里到家園。"]'),
('00c14d46-064f-434e-86b9-85409dd42569','詩一首','徐俯','宋','宋诗','song-poetry','','[]','雲洞看雲坐，月巖和月留。',24,'全唐诗/poet.song.79000.json','["雲洞看雲坐，月巖和月留。", "元來是野老，強喚作知州。"]'),
('9ecc0ba3-fb58-46b7-b229-9e43648ac1e4','鄥子值風雨','徐俯','宋','宋诗','song-poetry','','[]','重湖浪正起，支川舟不行。',24,'全唐诗/poet.song.79000.json','["重湖浪正起，支川舟不行。", "急雨夜臥聽，顛風晝眠驚。"]'),
('9a790e71-db7e-4191-9d8e-55fd5b033c8c','清逸樓','徐俯','宋','宋诗','song-poetry','','[]','馮高覽章貢，登樓見吳楚。',24,'全唐诗/poet.song.79000.json','["馮高覽章貢，登樓見吳楚。", "帆遠行盡山，江長流入霧。"]'),
('d95e56a9-9cf7-4e03-beb3-dc6a083260f0','廬陵中秋對月','徐俯','宋','宋诗','song-poetry','','[]','嶺近山相屬，江通水不流。',24,'全唐诗/poet.song.79000.json','["嶺近山相屬，江通水不流。", "無雲方萬里，有月正中秋。"]'),
('4bd9a609-90de-4280-9cd6-2e5013cbdad2','司空山','徐俯','宋','宋诗','song-poetry','','[]','主簿峰高昔所見，司空山深初未遊。',32,'全唐诗/poet.song.79000.json','["主簿峰高昔所見，司空山深初未遊。", "但願承平無路梗，不憚登涉尋巖幽。"]'),
('97bca289-82b0-4984-b492-861bf8bf448f','舒州  其一','徐俯','宋','宋诗','song-poetry','','[]','昔爲郡下客，曾借水邊居。',24,'全唐诗/poet.song.79000.json','["昔爲郡下客，曾借水邊居。", "秋水月爲晝，春風花作廬。"]'),
('47685f97-bb58-41a3-a1f0-a8bd2ecb287d','舒州  其二','徐俯','宋','宋诗','song-poetry','','[]','林依玉照遠，雲爲石盆留。',24,'全唐诗/poet.song.79000.json','["林依玉照遠，雲爲石盆留。", "春色年年好，溪山事事幽。"]'),
('772a5c40-2aa2-4be9-af11-ceaec5efbb41','昭州自強齋','徐俯','宋','宋诗','song-poetry','','[]','青蕪且作弦歌地，白屋曾爲將相家。',32,'全唐诗/poet.song.79000.json','["青蕪且作弦歌地，白屋曾爲將相家。", "莫倚田疇日富足，門標六戟自光華。"]'),
('a9e53f6e-af15-4b70-83f0-9d7078f55c6f','春日遊湖上','徐俯','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u6625", "\u5199\u666f", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7", "\u6625\u6e38"]','雙飛燕子幾時回，夾岸桃花蘸水開。',32,'全唐诗/poet.song.79000.json','["雙飛燕子幾時回，夾岸桃花蘸水開。", "春雨斷橋人不渡，小舟撐出柳蔭來。"]'),
('d0136136-2e41-4e97-9221-4e2a27a37d82','渡彭蠡湖','徐俯','宋','宋诗','song-poetry','','[]','沙岸委蛇白，雲林迤邐青。',48,'全唐诗/poet.song.79000.json','["沙岸委蛇白，雲林迤邐青。", "千山擁廬岳，百水會宮庭。", "旋食猶能飯，叢祠更乞靈。", "江湖萬里浪，政爾片帆輕。"]'),
