('313ea5d7-d436-4bff-8a76-bc3f2844999a','句  其六七','徐俯','宋','宋诗','song-poetry','','[]','頗知鶴脛緣詩瘦，早棄魚須伴我閑。',16,'全唐诗/poet.song.79000.json','["頗知鶴脛緣詩瘦，早棄魚須伴我閑。"]'),
('c6986baa-c0d9-42c2-8fc2-65eb27bd0379','句  其六八','徐俯','宋','宋诗','song-poetry','','[]','向使不死賊，未必世能容。',12,'全唐诗/poet.song.79000.json','["向使不死賊，未必世能容。"]'),
('d9e0d4ed-5dcb-470e-8582-cb817b982ab5','句  其六九','徐俯','宋','宋诗','song-poetry','','[]','今時習主簿，還是魯諸王。',12,'全唐诗/poet.song.79000.json','["今時習主簿，還是魯諸王。"]'),
('8eea6d27-ddb7-4d4e-b0d6-37db67f36a26','次正平上座韻贈子充','李彭','宋','宋诗','song-poetry','','[]','吾宗大宛種，未入十二閑。',48,'全唐诗/poet.song.79000.json','["吾宗大宛種，未入十二閑。", "膺門沬流赭，氣已無燕山。", "何時黄金羈，鞍轡長楸閒。", "皎皎自空谷，待君當御還。"]'),
('049afa92-315e-49d1-80de-638d96c55c38','戲贈兼簡李翹叟','李彭','宋','宋诗','song-poetry','','[]','荆州有醉客，踏雪至我廬。',60,'全唐诗/poet.song.79000.json','["荆州有醉客，踏雪至我廬。", "缺月寒皎皎，掛在東南隅。", "索我五字句，慚非競病徒。", "賣菜欲求益，故態發狂奴。", "寄聲李夫人，聊爲一笑娱。"]'),
('4addd686-e596-43f5-8c26-6d26f7de5a23','贈子充','李彭','宋','宋诗','song-poetry','','[]','阿充克家才，昭代真孝秀。',84,'全唐诗/poet.song.79000.json','["阿充克家才，昭代真孝秀。", "白髪在板輿，色養侍昏晝。", "來營甘脆具，底事成宿留。", "到骨似我窮，黄鐘滿君脰。", "落帆哉生魄，步屧月成彀。", "幽園語更僕，莫遣雙眉皺。", "覓句洗愁兵，河傾轉箕斗。"]'),
('efc1af22-9aef-4446-bf81-d421e40adbee','贈無著','李彭','宋','宋诗','song-poetry','','[]','蕭蕭玉澗翁，韻調實瓌朗。',108,'全唐诗/poet.song.79000.json','["蕭蕭玉澗翁，韻調實瓌朗。", "懷人修文去，音塵生逸想。", "豈唯招重客，我廬亦時枉。", "徽軫發妙言，幽園復清曠。", "飄忽下巖隈，歲月駛兩槳。", "寒蟬久停號，新禽哢佳響。", "去者念履綦，方來驚蕙帳。", "伊予厭囂塵，絕壑期自放。", "從君割半峰，披雲同矯掌。"]'),
('454ef015-1496-4307-ac07-01952318e02c','送人遊吴','李彭','宋','宋诗','song-poetry','','[]','朔風號木末，迫此歲時晏。',144,'全唐诗/poet.song.79000.json','["朔風號木末，迫此歲時晏。", "驅車不停軌，客子老昏宦。", "平生蔣詡徑，求羊毎娱玩。", "持觴送落日，抵掌河宿爛。", "胡爲向吴會，雅意訪親串。", "親串者誰歟，昂昂金閨彦。", "嘘枯由涵照，要津藉推挽。", "念子赴修塗，發軔在昧旦。", "娟娟所嬌兒，嶷嶷赴門限。", "閨人密縫裳，遐征苦多綻。", "結束志千里，二事忘一眄。", "莫遣扊扅歌，愆期發長嘆。"]'),
('2a55dbd2-9f91-40e1-b2d9-b66f79031c69','宿歸宗贈軾老','李彭','宋','宋诗','song-poetry','','[]','平生丘壑心，祇園多幽趣。',156,'全唐诗/poet.song.79000.json','["平生丘壑心，祇園多幽趣。", "杖藜過懸崖，投足澄百慮。", "涓涓一滴泉，湛湛三危露。", "淵源自曹溪，甘腴勝牛乳。", "諸峰羅孫寧，一一尊鼻祖。", "法筵碧眼人，家世本鄠杜。", "紫樞與黄閤，去天纔尺五。", "不爲世網嬰，粲可叶心素。", "繩牀作禪定，大音響韶濩。", "應夢先補陀，祝髪得玉斧。", "我來心眼明，意氣諧律呂。", "金地雨曼殊，天香遶巾屨。", "明當整歸鞍，天末蜚鴻度。"]'),
('de03e6a6-5ba2-4b03-ae4b-d02499971efd','奉贈正平上座','李彭','宋','宋诗','song-poetry','','[]','若人韻凝遠，天資復敦厖。',120,'全唐诗/poet.song.79000.json','["若人韻凝遠，天資復敦厖。", "蕭然出塵表，幽寺聽逢逢。", "劍峰極天净，懸瀑聲舂撞。", "心猿久調御，業白瑩明缸。", "殘河横曉鉢，霽霧起寒窗。", "禪餘覓佳句，鼎鼐筆能扛。", "我來孟冬月，望履塵心降。", "世紛劇羊負，是身如帝江。", "願借三峡水，一滋隴頭瀧。", "永辦桑門服，猶堪追老龐。"]'),
('45b56367-ad71-430f-8e42-04124dde75d8','和連雨獨飲','李彭','宋','宋诗','song-poetry','','[]','力田勝巧宦，燕息自超然。',96,'全唐诗/poet.song.79000.json','["力田勝巧宦，燕息自超然。", "懶覷竹素書，俯仰丘壑間。", "時時過祇園，亦復舞胎仙。", "偶然得歡趣，舉觴望青天。", "六鑿自無競，歘見象帝先。", "羲皇隔晨炊，坐見淳風還。", "磨螘不少留，鼎鼎遂百年。", "但得會心侶，相對兩忘言。"]'),
('2e661a22-e187-4e52-bf83-a5400342cbd0','次秦處度贈歸宗老示中上座韻','李彭','宋','宋诗','song-poetry','','[]','夕霏催節往，槁葉徑辭風。',96,'全唐诗/poet.song.79000.json','["夕霏催節往，槁葉徑辭風。", "力疾招秦叔，望山扶老笻。", "泄雲爲卿靄，牽余來鷲峰。", "中有龐眉老，常持半聖弓。", "一席跨牛地，誅茅期此同。", "虚懷包朗月，意表得詩翁。", "遠志是小草，慎在出處中。", "公莫厭苦相，歲晏長相從。"]'),
('084efc4e-6c63-49ce-b8db-09c1dcae63e1','嗣首座以老夫詩西嶺障斜日爲韻作五章見寄次韻答之  其一','李彭','宋','宋诗','song-poetry','','[]','尋春舍南北，呼酒玉東西。',48,'全唐诗/poet.song.79000.json','["尋春舍南北，呼酒玉東西。", "絕勝劉校尉，太乙持青藜。", "天邊藝蘭人，風光今幾畦。", "胡爲寂滅海，妙語紓虹霓。"]'),
('0774f05f-e4cd-41eb-9f7b-d89ace9b4d32','嗣首座以老夫詩西嶺障斜日爲韻作五章見寄次韻答之  其二','李彭','宋','宋诗','song-poetry','','[]','清霜熟柿栗，會面一俄頃。',48,'全唐诗/poet.song.79000.json','["清霜熟柿栗，會面一俄頃。", "蕨拳漸紫苞，鳥語度諸嶺。", "仰頭占昏中，弧星光炳炳。", "何當聽談玄，令我發深省。"]'),
('08ca49c5-1453-494f-9b86-7e31e19813f2','嗣首座以老夫詩西嶺障斜日爲韻作五章見寄次韻答之  其三','李彭','宋','宋诗','song-poetry','','[]','我家二季子，風標荀令上。',48,'全唐诗/poet.song.79000.json','["我家二季子，風標荀令上。", "優孟何足求，慎勿作楚相。", "毛顔獨摧頹，兒能縛籬障。", "摩挲繭栗姿，我老那復壯。"]'),
('7c84f1b9-279e-4a57-92a0-f6df993b27f4','嗣首座以老夫詩西嶺障斜日爲韻作五章見寄次韻答之  其四','李彭','宋','宋诗','song-poetry','','[]','争端起儒墨，春蚓兼秋蛇。',48,'全唐诗/poet.song.79000.json','["争端起儒墨，春蚓兼秋蛇。", "筆研真淺事，専門自名家。", "但有香積飯，不妨薰毗耶。", "温風媚高柳，招客整還斜。"]'),
('ba03e091-6fe3-44dd-a6b4-ce8bb51eb12e','嗣首座以老夫詩西嶺障斜日爲韻作五章見寄次韻答之  其五','李彭','宋','宋诗','song-poetry','','[]','歐峰壓半天，堦除轉晴日。',48,'全唐诗/poet.song.79000.json','["歐峰壓半天，堦除轉晴日。", "落磑多雪芽，香草皆碧苾。", "嗣公釋門老，眈眈虎而翼。", "我欲往叩之，藤蘿迷石室。"]'),
('09240e29-f589-4d41-8964-6f3592e8faa4','再和嗣首座五詩寄舒老微老  其一','李彭','宋','宋诗','song-poetry','','[]','在昔董仲舒，屈身相膠西。',48,'全唐诗/poet.song.79000.json','["在昔董仲舒，屈身相膠西。", "窮經著繁露，窺園廢扶藜。", "而我異於是，清晨來灌畦。", "雨餘聊自適，微吟看斷蜺。"]'),
('2946615b-ed6f-4df3-90c8-adaaf061a08d','再和嗣首座五詩寄舒老微老  其二','李彭','宋','宋诗','song-poetry','','[]','黄生牛醫兒，襟量包萬頃。',48,'全唐诗/poet.song.79000.json','["黄生牛醫兒，襟量包萬頃。", "稱譏等夢事，緩带耳不領。", "公議如丹青，千載焕且炳。", "古人何必遠，薄躬吾屢省。"]'),
('30e748b6-55e9-451b-bda7-ec60aa438255','再和嗣首座五詩寄舒老微老  其三','李彭','宋','宋诗','song-poetry','','[]','堂堂一舒翁，道價融壑上。',48,'全唐诗/poet.song.79000.json','["堂堂一舒翁，道價融壑上。", "煙霞斷塵緣，那復知苦相。", "會將超諸緣，奪我事理障。", "莫言霜滿頤，矍鑠一何壯。"]'),
('004bc339-6e22-4e37-b1dc-9ead7c94af3c','再和嗣首座五詩寄舒老微老  其四','李彭','宋','宋诗','song-poetry','','[]','嗣公丹鳳羽，高笑破羣蛙。',48,'全唐诗/poet.song.79000.json','["嗣公丹鳳羽，高笑破羣蛙。", "汲引後來秀，義俠如朱家。", "出語掩顔謝，遊戲達摩耶。", "卧讀春風句，飛鴻澹墨斜。"]'),
('10b29a43-e962-4854-828d-ef2bbda4933a','再和嗣首座五詩寄舒老微老  其五','李彭','宋','宋诗','song-poetry','','[]','牧菴擔板翁，銳氣如平日。',48,'全唐诗/poet.song.79000.json','["牧菴擔板翁，銳氣如平日。", "明璧不可瑕，崇蘭有餘苾。", "何嘗疲津梁，苦鎩垂天翼。", "索價無乃高，孤峰問少室。"]'),
('12aa08b6-064e-482f-8203-30ab6920faee','送杲上人復往荆南','李彭','宋','宋诗','song-poetry','','[]','荆州老居士，寧著進賢冠。',216,'全唐诗/poet.song.79000.json','["荆州老居士，寧著進賢冠。", "似欲専一壑，其誰知孔鸞。", "蒼苔門巷秋，不許造席客。", "世無王粲流，倒屣端不惜。", "上人宣城彦，俊氣横九州。", "學道貧徹骨，與世初無求。", "馬駒大道場，屬者失宗匠。", "欲銘窣堵波，見此真漢相。", "行乞千里餘，朔風枯葉顛。", "曉踏澗下雪，暝宿天邊烟。", "赤手泛滄溟，笑此太草草。", "不爲丞相嗔，乃得照乘寶。", "歸來寂無聞，翠琰開險艱。", "精衛既填海，愚公果移山。", "力貧辦行李，復作南郡去。", "游子多苦顔，開士淡無慮。", "霜風木颼颼，便當賦式微。", "日涉望烟靄，扶笻遲來歸。"]'),
('cd941c3b-72d7-4047-a343-f020d8f20601','奉贈歸宗才首座','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','五着匡山屐，三息紫霄陰。',156,'全唐诗/poet.song.79000.json','["五着匡山屐，三息紫霄陰。", "龔聞耶舍塔，勢吞天姥岑。", "俯窺雕鶚背，上聆鐘梵音。", "未航蕭梁葦，峻風先少林。", "靈骨化大璐，鉅名偕南金。", "松門欲牽葉，苦雨毎見臨。", "才公三衢秀，古貌又古心。", "老胡即渠是，宴坐藏幽深。", "何用登紫霄，自足披煩襟。", "我過避秦客，茗椀來相尋。", "真成虎溪笑，稍寬梁甫吟。", "衲子歎雌伏，道師非陸沉。", "世多石窟病，須下鼓山針。"]'),
('bfb9d7e2-2999-4683-a039-c03d7de6927f','送寧上人歸净慈','李彭','宋','宋诗','song-poetry','','[]','之子遠行邁，眷言款松門。',60,'全唐诗/poet.song.79000.json','["之子遠行邁，眷言款松門。", "雲物起離色，况乃聞清猿。", "頗云吴會去，飽參南山禪。", "南山燕頷郎，氣敵千人軍。", "要當理斷履，過我藝蘭蓀。"]'),
('c787ba4c-5ee1-4c92-9848-1c2dd702d768','寄珍首座','李彭','宋','宋诗','song-poetry','','[]','詩寧淺而静，不貴深而蕪。',108,'全唐诗/poet.song.79000.json','["詩寧淺而静，不貴深而蕪。", "觀公秋懷作，峻潔仍紆餘。", "譬之列華饌，陸海盈中厨。", "食蟹貴抱黄，食魚先腹腴。", "多入出或少，我昔聞先儒。", "年來病蹇拙，意廣材復疏。", "之子禪定起，焚香滿晴虚。", "坐看氤氲處，緜緜詩思俱。", "應作牛腰束，能寄草堂無。"]'),
('7b7ade8c-3544-474f-b2f2-b01761a9a676','題胡九齡畫夏景牛','李彭','宋','宋诗','song-poetry','','[]','陰岑不造天，憩此老觳觫。',48,'全唐诗/poet.song.79000.json','["陰岑不造天，憩此老觳觫。", "輟耕壟上來，投閑慰心曲。", "養牲奉嚴禋，蓋用繭栗犢。", "莫起陸沈悲，焉知果非福。"]'),
('7cb11f65-9b78-43a4-8e93-5c2da86ddacd','送敦詩遊臨川','李彭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','呂郎客秦淮，詩思翻秋濤。',216,'全唐诗/poet.song.79000.json','["呂郎客秦淮，詩思翻秋濤。", "徐郎憩灊峰，句壓天柱高。", "相此兩公子，信是千人豪。", "叔也往從之，似欲訴不遭。", "探囊得長句，如取綏山桃。", "療饑非蒸砂，禦寒必綈袍。", "一簪未著身，所得不補勞。", "復爲饑所驅，未許學卧陶。", "窮軍敵孤客，如在皋蘭鏖。", "幾成劉文叔，須髪變二毛。", "搘笻躡草鞋，進退似桔槔。", "引領長江西，沙頭唤魚舠。", "金溪有謝侯，胸多略與韜。", "天資類文靖，貌實中郎曹。", "叔也往從之，攻愁解鞬櫜。", "毋輕歌驪駒，不復吟畔牢。", "待公稇載歸，爲我攜蒲萄。", "來賞傲霜菊，一尊澆老饕。"]'),
('f510ed78-343c-44d4-9881-b22c74e9b3e3','和季敵戲書','李彭','宋','宋诗','song-poetry','','[]','短草被南陌，晴絲颺幽軒。',48,'全唐诗/poet.song.79000.json','["短草被南陌，晴絲颺幽軒。", "心静境云寂，默居宣妙言。", "林深鳥烏樂，花繁蜂蝶喧。", "是中即真意，何須祇樹園。"]'),
('f8216377-5369-49ac-9c63-9789e9abe644','元夕高卧','李彭','宋','宋诗','song-poetry','','[]','伊昔宅關輔，門閭萃冠蓋。',120,'全唐诗/poet.song.79000.json','["伊昔宅關輔，門閭萃冠蓋。", "停杯邀明月，意氣殊藹藹。", "春風墮江城，蒐獮顔鬢改。", "糞除二畝地，羊裘力薪採。", "矯首望舒圓，何由賞心在。", "烟村雜簫皷，叢祠響竽籟。", "誰能伴兒嬉，頗復償睡債。", "初驚釡鳴雷，遽作濤擣海。", "非關骨相屯，長閑荷真宰。", "吾生計已决，無勞問蓍蔡。"]'),
('fbb36fd1-743e-4a57-ab1a-2593b068b49f','宿西林寺有先特進及先學士詩','李彭','宋','宋诗','song-poetry','','[]','渡江送行人，我行亦清興。',120,'全唐诗/poet.song.79000.json','["渡江送行人，我行亦清興。", "草木春路賖，斜斜復整整。", "獨造此寶坊，深穩庭宇静。", "複閣襯烟霞，疏林泄鐘磬。", "殘僧澀對人，短童工汲井。", "杖屨若能神，迥知兹遊勝。", "楹間盤硬語，怪底光炯炯。", "追還曾高風，熟復發深省。", "來歸十陽秋，足不踐斯境。", "猿鶴情未忘，拾松來煮茗。"]'),
('7c35c26d-7521-4068-b220-4b83ab3d6ffc','何生用韻見寄復答之兼示小何  其一','李彭','宋','宋诗','song-poetry','','[]','繞屋陰扶疏，空堦蘚文皺。',60,'全唐诗/poet.song.79000.json','["繞屋陰扶疏，空堦蘚文皺。", "懷人殊未來，安得傾蓋舊。", "好鳥政相呼，吟蛩俄應候。", "夜夢嵇阮輩，醉鄉須少留。", "莫踏肥馬塵，我自貧馬痩。"]'),
('3d8cae34-9e2b-4f6e-914b-0c8d2fd02d8a','何生用韻見寄復答之兼示小何  其二','李彭','宋','宋诗','song-poetry','','[]','水部有耳孫，湖海胸中浩。',60,'全唐诗/poet.song.79000.json','["水部有耳孫，湖海胸中浩。", "小陸復何人，相逢歲亦早。", "並游蘇黄門，我曹不容掃。", "梧桐生朝陽，要須聞鳴鳥。", "雲中遣馮唐，據鞍未渠老。"]'),
('ea999ae5-555f-48eb-86ba-ce1f1cd73df3','次韻答禹功兼簡周國振時禹功一夕泛舟歸郡不及話離  其一','李彭','宋','宋诗','song-poetry','','[]','攀蘿委松宿，潄石看雲行。',48,'全唐诗/poet.song.79000.json','["攀蘿委松宿，潄石看雲行。", "松疏暝色漫，雲度夕陰生。", "若人有高躅，領略遺世情。", "聊爲公府步，冉冉復盈盈。"]'),
('757af5d6-4e40-4209-a02a-92408be24e3c','次韻答禹功兼簡周國振時禹功一夕泛舟歸郡不及話離  其二','李彭','宋','宋诗','song-poetry','','[]','蒼苔映槿墉，商飇薄庭樹。',48,'全唐诗/poet.song.79000.json','["蒼苔映槿墉，商飇薄庭樹。", "方期著屐來，遽作張帆去。", "擇交如擇金，披沙歘相遇。", "慈明畏無雙，偉節慚最怒。"]'),
('9fbfb9ec-671c-455b-ad02-4a297a79b2d2','次韻答禹功兼簡周國振時禹功一夕泛舟歸郡不及話離  其三','李彭','宋','宋诗','song-poetry','','[]','公抱青田姿，俛啄家鷄羣。',48,'全唐诗/poet.song.79000.json','["公抱青田姿，俛啄家鷄羣。", "徽之拄頰外，遐矚西山雲。", "昔我藻鑒士，拱木蔽孤墳。", "詎意王子敬，晚乃知羊欣。"]'),
('29c5e7d3-7af0-474f-afcd-665c75219590','次韻答禹功兼簡周國振時禹功一夕泛舟歸郡不及話離  其四','李彭','宋','宋诗','song-poetry','','[]','相望兩牛鳴，頓覺千里别。',48,'全唐诗/poet.song.79000.json','["相望兩牛鳴，頓覺千里别。", "未别如懷冰，别來三伏熱。", "賴有清輝吟，當窗時玩閲。", "音塵在我前，悠然情話悦。"]'),
('bf9cf8e4-aca7-4893-8461-430fe91fcee7','次韻答禹功兼簡周國振時禹功一夕泛舟歸郡不及話離  其五','李彭','宋','宋诗','song-poetry','','[]','飃飃顧曲郎，恬愉仍静深。',48,'全唐诗/poet.song.79000.json','["飃飃顧曲郎，恬愉仍静深。", "相逢何必早，但貴相知心。", "臨博斯識道，聞韶真賞音。", "端須理三徑，歲華多浸淫。"]'),
('17b9d30d-a914-43ed-838a-64dcefcc3030','王生以詩見貽次韻答之生視脊中環中實仲父','李彭','宋','宋诗','song-poetry','','[]','渠渠太火門，諸郎蓋當世。',216,'全唐诗/poet.song.79000.json','["渠渠太火門，諸郎蓋當世。", "大匠無棄材，知人亦未易。", "阿戎兩雲孫，駸駸遣人畏。", "難兄江南秀，美比嘗託意。", "歘爲修文郎，不作活國士。", "令弟老數奇，禪寂甘窮顇。", "時於翰墨場，往往見高致。", "揚州故時語，弈弈好風氣。", "獨識史君顔，周禮秉早歲。", "背城幾借一，問學晚尤粹。", "相逢且班荆，十事欲九異。", "何須張女彈，端爲建康醉。", "請抛高門竿，莫反魯麟袂。", "花藥聘君湖，暄風攬春思。", "人生行樂耳，餘事栩栩寐。", "崇蘭有國香，寧以不服廢。", "雖無雙南金，可報綠綺惠。", "此豈小物哉，吾言未渠棄。"]'),
('c5c2ec42-6957-4fa0-99ae-a7580361da6d','杜欽之次淵明答龐參軍韻見送用韻答之','李彭','宋','宋诗','song-poetry','','[]','征南遠韻度，詣絕皆妙言。',96,'全唐诗/poet.song.79000.json','["征南遠韻度，詣絕皆妙言。", "銀臺陳諫疏，恥作賦兔園。", "手板聊拄頰，爽氣來新萹。", "臨窗無謝守，僧珍自超然。", "我遊赤壁下，爲君且延緣。", "周禮盡在魯，驚嗟類韓宣。", "候雁響横河，遊子念故山。", "行當理烟艇，相期醉餘年。"]'),
('1de72f66-8902-4f16-96fe-873549272175','送潤上人歸宛陵','李彭','宋','宋诗','song-poetry','','[]','我昔遊宣城，稚節等雛鳳。',168,'全唐诗/poet.song.79000.json','["我昔遊宣城，稚節等雛鳳。", "稍知風物奇，未解入嘲弄。", "歘爾鬢負霜，歲月雜機綜。", "唯有謝公亭，頗復到清夢。", "上人宛陵秀，禪餘喜吟諷。", "胸中淡無畦，妙覺自能種。", "偶隨歐峰雲，悠然入茅棟。", "談間無俗調，不應亭午供。", "誰云佳少年，意氣極莊重。", "别我歸故山，索我贈言送。", "鄰邦古法窟，老衲妙擒縱。", "伽黎宴湖海，名字走梁宋。", "吾其從之遊，射隼期必中。", "勿學漢陰人，終年徒抱甕。"]'),
('46c2767d-7466-4dfb-8e6a-b21f9ccb603e','蒲塘道中寄懷歸宗逈中法闡法仁三僧','李彭','宋','宋诗','song-poetry','','[]','窗鷄唤晨炊，轂聲轉水轍。',240,'全唐诗/poet.song.79000.json','["窗鷄唤晨炊，轂聲轉水轍。", "出遨得會稽，辨嚴未明發。", "朔氣犯襟裾，露華襲毛髪。", "仿像滹沱河，幽事期可悦。", "旅雁起寒塘，疏林耿明月。", "挽彼歲寒姿，然萁共明滅。", "豈惟甦奚奴，政可烘履襪。", "黎明詣蕭寺，餉糜隨盥櫛。", "風廊謔談僧，蒲團尋老衲。", "堂堂大圜照，此渠親記莂。", "緬懷湯惠休，妙理頗詣絕。", "超然宴法窟，胸次包禹穴。", "闡師遠遊孫，卓卓霜下傑。", "真成一角麟，笑我緣盎鼈。", "寂子延陵秀，暉映敵冰雪。", "渥洼真龍媒，作駒已汗血。", "刮膜藉金篦，嘉言霏玉屑。", "德星毎難聚，顧兔復易缺。", "紫霄上巑岏，石鏡懸瑩澈。", "幽期不嫌頻，難遣芳歲歇。"]'),
('ca552c4d-6bb1-4083-8b10-e9917aa60a50','次韻謝朓觀朝雨','李彭','宋','宋诗','song-poetry','','[]','凉飇起屋角，微雲天際來。',96,'全唐诗/poet.song.79000.json','["凉飇起屋角，微雲天際來。", "摵摵荷上雨，冉冉自陽臺。", "軒窗積餘潤，竹樹絕纖埃。", "懶放事幽屏，柴扉爲誰開。", "肥遯病使然，黄門豈負哉。", "可憐南巷翁，攜魚柳貫腮。", "餉我共杯盞，眷焉久徘徊。", "憑虚耳熱後，褰裳望蓬萊。"]'),
('88fbd515-1035-46c1-bff5-4d2f544e41f4','奉同伯固駒甫師川聖功養直及阿虎尋春因賦問柳尋花到野亭分得野字','李彭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','曜靈運行春，蘅若被原野。',168,'全唐诗/poet.song.79000.json','["曜靈運行春，蘅若被原野。", "客子具歸驂，暄風挽羸馬。", "屬國賢耳孫，當代豪長者。", "勝游參羊何，重客或屈賈。", "木末仲宣樓，華榱大蘭若。", "徐步幽屢尋，銷憂日聊假。", "手無垂露資，發興爲君寫。", "晚過岱宗吏，寥闊存大雅。", "犧樽追三代，琴筑觀九夏。", "粲粲懸牙籤，照眼不容捨。", "歸酌顧建康，我實陪樽下。", "雄豪先競病，遲遯瀕喑啞。", "匪惟稱行樂，性靈賴陶冶。", "他時儻重來，更結離騷社。"]'),
('3d6c23f3-079a-4a49-bfc6-9ab13688ab70','里儒程君窮居教弟子員喜雨作詩見貽次韻謝之','李彭','宋','宋诗','song-poetry','','[]','柴門臨江皋，炎蒸頗云極。',168,'全唐诗/poet.song.79000.json','["柴門臨江皋，炎蒸頗云極。", "金稚無壯心，火老有驕色。", "慈雲辦甘雨，電掃不容隙。", "勞生天邊月，躔次飽更歷。", "緬懷程夫子，熱客難造席。", "涵濡被童蒙，肥瘠各有適。", "瓌材構露寒，揮斤由匠石。", "不邀里閭敬，人自觀至德。", "鄙夫極荒蕪，何能臻壼域。", "弱齡再皷衰，櫜弓避勍敵。", "蕭然専一丘，非關與塵隔。", "董生悲不遇，而我異休戚。", "高林收晚靄，歸鳥俱斂翼。", "詩成獨微吟，長懷矯雲翮。"]'),
('7c748b48-1470-4093-acdb-dbaa6ddf3773','遊同安寺','李彭','宋','宋诗','song-poetry','','[]','雨歇漲江急，野興聊胥疏。',144,'全唐诗/poet.song.79000.json','["雨歇漲江急，野興聊胥疏。", "漾舟拂林表，擊汰驚飛鳬。", "雲端僧坐夏，遂造林公廬。", "猊坐演妙理，法筵滄海珠。", "舌本落雄辯，奔放懸江湖。", "巽公庭宇淨，爐煙堂晏如。", "略無客造請，杳黑耽毗盧。", "吾家大長者，惠光充太虚。", "著論役天女，寶笈負於莬。", "開圖拜遺像，悲嘆隨卷舒。", "歸來掩關卧，念冷無贏餘。", "譬如能櫜鞬，境界自于于。"]'),
('eb82f32d-af45-472d-a30c-183da3526dfc','和苦雨韻','李彭','宋','宋诗','song-poetry','','[]','春歸已獺祭，微綠先道周。',144,'全唐诗/poet.song.79000.json','["春歸已獺祭，微綠先道周。", "衡門少燈火，征夫竭乾餱。", "雨工挽九河，洊作南國憂。", "君詩形苦詞，高義薄中州。", "歌聲滿天地，宰物能聞不。", "凡今世賢知，耄及誰不偷。", "唯我與之子，炯炯定寡求。", "安得習習風，凍枿新萌抽。", "遙山滌餘靄，歸雲下巖幽。", "紫鳳會騫翥，百鳥勞喧啾。", "蒼生得税駕，王度日清休。", "醉眼眩章句，煩君爲校讎。"]'),
('fa6892a1-2d26-4c90-8551-a19c2dad4c50','遊簡寂觀','李彭','宋','宋诗','song-poetry','','[]','仲夏暑方壯，游子巾柴車。',96,'全唐诗/poet.song.79000.json','["仲夏暑方壯，游子巾柴車。", "崖斷眇空曠，遂造羣仙居。", "闊步烟靄外，追凉晚風餘。", "泉聲遠逾響，猿掛時相呼。", "仙人翔寥廓，曾不念故廬。", "蒼珉禮斗處，往往聞笙竽。", "我復恣雲卧，悠然隘寰區。", "妄念鼓不作，長歗聊虚徐。"]'),
('3169b124-80c1-4f57-8743-ece9cc57a240','奉酬蕭子植','李彭','宋','宋诗','song-poetry','','[]','太丘廊廟具，活國方暢謀。',264,'全唐诗/poet.song.79000.json','["太丘廊廟具，活國方暢謀。", "虎豹阨九關，全軀荷靈修。", "元方開美度，奮舌同尊周。", "悠悠釋嶠雲，亭亭留海陬。", "别時閨中女，娟娟未知愁。", "小襦繡爛漫，擷草鬬新柔。", "甲子歘流電，窈窕今好逑。", "擇對得妙士，邁往氣横秋。", "既逾絕塵到，復軼黄中劉。", "屬者過我廬，並坐崖谷幽。", "高標極迥映，出語如冥捜。", "想當飽四庫，那肯事五樓。", "回首問童稚，頗有此客不。", "分攜月屢彀，好音俄見投。", "蠻牋落大句，豪潤仍清遒。", "顧兹坦腹郎，信矣百不憂。", "側聞奏雲門，總章定諮諏。", "翁當乘安車，姓名覆金甌。", "冰清遂賜環，德星聚中州。", "陋巷寡輪鞅，寒烟滿林丘。", "滌耳聽老語，餘生復何求。", "哦詩聊送似，長懷付溟鷗。"]'),
('e4268b73-ff44-4792-80ee-2bac221f8c28','奉酬湖陰韋深道','李彭','宋','宋诗','song-poetry','','[]','淮南廢沐浴，望漢三十秋。',240,'全唐诗/poet.song.79000.json','["淮南廢沐浴，望漢三十秋。", "丞相發蒙耳，衛青奴虜儔。", "終藉汲長孺，毅然寢陰謀。", "正人國之紀，進退繫戚休。", "鶚立聳朝著，深藏耀巖幽。", "湖陰有真隱，趣尚協滄洲。", "奇胸飽風霜，大筆森戈矛。", "急賢甚漁獵，網羅英雋收。", "終南與少室，朝暮拔其尤。", "胡爲卧江津，尚阻瞻冕旒。", "顧令繭栗犢，升禋薦圜丘。", "開軒榜獨樂，高躅追前修。", "志士遺草澤，餘波及湯流。", "益使山林尊，豪奪不可求。", "但恐赴隴書，未能逃大蒐。", "嗟余牛馬走，鬢斑年亦遒。", "烟霞入種藝，松桂助颼飀。", "書來挾妙句，眷言頗綢繆。", "乃知氣先感，臭味還相侔。", "詩成月生嶺，迴溪上明樓。"]'),
('2752eff1-7577-4c10-9644-90dccd308a5e','奉酬石元涇','李彭','宋','宋诗','song-poetry','','[]','往時萬石君，諸郎皆孝秀。',72,'全唐诗/poet.song.79000.json','["往時萬石君，諸郎皆孝秀。", "身自浣厠牏，已足垂不朽。", "君侯驅卉木，去病如滌垢。", "以兹壽白髪，不落西京後。", "新章來全楚，爽氣起懷袖。", "覓句代寒温，慚非報瓊玖。"]'),
('d1ea4217-711f-4cb8-96a2-0a83cf701ae5','奉酬程子尚','李彭','宋','宋诗','song-poetry','','[]','彼美洛陽人，貽我柏梁句。',108,'全唐诗/poet.song.79000.json','["彼美洛陽人，貽我柏梁句。", "艷雪敵清妍，春雲多態度。", "憶昔郎官湖，秋風落烟樹。", "使君出程門，蕭蕭髪垂素。", "平時仲尼履，尚可藏武庫。", "不見揚子雲，欣與侯芭遇。", "况兹得小阮，風流肖諸父。", "曠懷滄洲期，恊我塵外趣。", "尚無金玉音，歸鴻來枉渚。"]'),
('50fb6970-01a3-4ca1-9baf-98ad20e8cd51','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其一','李彭','宋','宋诗','song-poetry','','[]','鄱陽山水國，東南一都會。',48,'全唐诗/poet.song.79000.json','["鄱陽山水國，東南一都會。", "朗玉得斯人，駸駸越流輩。", "島可不足吞，支許欲追配。", "新詩如絃簧，窈眇歌一再。"]'),
('093643a1-9237-498d-b044-74bf84da4193','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其二','李彭','宋','宋诗','song-poetry','','[]','璧公釋門老，室有芝蘭薰。',48,'全唐诗/poet.song.79000.json','["璧公釋門老，室有芝蘭薰。", "昔爲一逢掖，直諒頗多聞。", "枯禪百無染，静擁襄漢雲。", "不隨兒女曹，搴旗樹功勲。"]'),
('1c3a3278-fc8d-41fa-8968-575a45137bb0','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其三','李彭','宋','宋诗','song-poetry','','[]','蟬噪嗟齊梁，鳳鳴推沈宋。',48,'全唐诗/poet.song.79000.json','["蟬噪嗟齊梁，鳳鳴推沈宋。", "諸人勤著脚，何嘗窺妙用。", "獨有杜參謀，變態無與共。", "絕唱冠古今，孤高追惜誦。"]'),
('10655a0c-e72d-4be9-924e-238f0e64f0a0','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其四','李彭','宋','宋诗','song-poetry','','[]','嘉平送餘運，丘園先欲春。',48,'全唐诗/poet.song.79000.json','["嘉平送餘運，丘園先欲春。", "東風堂堂來，不畏北風嗔。", "緬想萱芽動，高標壓常珍。", "川岑互映徹，草木俱鮮新。"]'),
('baea9b12-b8a0-40ba-a264-95ba131bc9d2','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其五','李彭','宋','宋诗','song-poetry','','[]','吾友韓子蒼，霧豹閟關鑰。',48,'全唐诗/poet.song.79000.json','["吾友韓子蒼，霧豹閟關鑰。", "一朝出陰崖，蓬山真著作。", "絕倫共推讓，痛掃凈瑕膜。", "行矣貳紫微，居然賦紅藥。"]'),
('acc6a243-9b09-47f4-96af-3a7de81ec72d','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其六','李彭','宋','宋诗','song-poetry','','[]','材名參上流，徙薪知曲突。',48,'全唐诗/poet.song.79000.json','["材名參上流，徙薪知曲突。", "趣嚮期真源，悟悦須法窟。", "楚謠與漢風，要自非凡骨。", "幻藥不可當，靈根貴英發。"]'),
('e65789e0-ef00-4862-9c06-811769e28d92','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其七','李彭','宋','宋诗','song-poetry','','[]','我生如艅艎，罅漏頓補過。',48,'全唐诗/poet.song.79000.json','["我生如艅艎，罅漏頓補過。", "涉世任風帆，唱予聊復和。", "髪短巾屢欹，食艱齒仍墮。", "自嗟叔夜懶，又疑武侯卧。"]'),
('023556fb-4f5f-4d45-a24d-f262e1fdee0f','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其八','李彭','宋','宋诗','song-poetry','','[]','田園本地著，耕耘不忘初。',48,'全唐诗/poet.song.79000.json','["田園本地著，耕耘不忘初。", "修桑復浴種，力作共征輸。", "榮名愧八俊，典學欣三餘。", "安敢望輓汲，雲林當晏如。"]'),
('1ecc89e4-f46c-41b8-b124-0cb816d11d05','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其九','李彭','宋','宋诗','song-poetry','','[]','子居招隱巖，妙解招隱詩。',48,'全唐诗/poet.song.79000.json','["子居招隱巖，妙解招隱詩。", "濟勝良有具，幽討捷若馳。", "秀峙王郎子，斵句時相依。", "異世得岳湛，連璧真妍姿。"]'),
('d930cfd4-8b43-48bb-91c4-d1dc42c0656c','慶上人以再聞誦新作突過黄初詩爲韻作十詩見寄次韻酬之  其一○','李彭','宋','宋诗','song-poetry','','[]','札札寒女機，織素工流黄。',48,'全唐诗/poet.song.79000.json','["札札寒女機，織素工流黄。", "何如風塵外，翠袖倚修篁。", "幽居渺天末，肯傍霍衛墻。", "饔人解黿處，誰能染指嘗。"]'),
('c039380f-a7ff-4868-9c90-398b16243064','九日奉呈元亮兄','李彭','宋','宋诗','song-poetry','','[]','窮秋風落山，歲事幾轉軸。',144,'全唐诗/poet.song.79000.json','["窮秋風落山，歲事幾轉軸。", "蕭然四壁空，觸眼困羈束。", "我塵已生甑，兄亦未有屋。", "少也不如人，自視真陸陸。", "北阮烏賀蘭，絕影追風足。", "誰知薦圜丘，乃用繭栗犢。", "棄置勿復陳，萬事蕉夢鹿。", "渺渺天界高，宫黄著畦菊。", "能來慰艱勤，濁醪巾可漉。", "雖無熊耳杯，要自尊中淥。", "屬厭謝珍羞，無禍可當福。", "回觀夸奪兒，往往加煩促。"]'),
('c29ab5da-2364-4db7-9e8d-336ca86a8fbf','用前韻','李彭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','離索未相逢，情親在詩軸。',144,'全唐诗/poet.song.79000.json','["離索未相逢，情親在詩軸。", "歸來兩丹楓，詩作牛腰束。", "妙語挾風霜，勁氣穿我屋。", "眼中識慈明，尊下慚小陸。", "念昔少年時，洞庭思濯足。", "援琴寫將歸，臨河歎鳴犢。", "正爾巢一枝，何勞排五鹿。", "江闊洲渚寒，微風泛時菊。", "劇談斗低昂，露草復淋漉。", "誰家酒杯寬，滿引甕頭淥。", "何知程衛尉，未暇顧藉福。", "鼓柂牽牛河，頓覺滄溟促。"]'),
('886fec59-b05c-4951-ab4d-90b287673c9e','農家三首  其一','李彭','宋','宋诗','song-poetry','','[]','力田徇所務，蓐食赴其勞。',60,'全唐诗/poet.song.79000.json','["力田徇所務，蓐食赴其勞。", "譬之賈欲贏，疇能惡喧囂。", "逢年未前期，敢緩芟與薅。", "黔雷無偏頗，多稼埋牛尻。", "倉廩自兹實，含飴弄兒曹。"]'),
('3f46fc16-cbce-4f3d-8db3-7145fde9f810','農家三首  其二','李彭','宋','宋诗','song-poetry','','[]','自我曾高時，以有此土田。',84,'全唐诗/poet.song.79000.json','["自我曾高時，以有此土田。", "一朝均租賦，吏文沸相煎。", "南鄰勢炙手，北鄰富薰天。", "歗聚烏合衆，變詐揮金錢。", "本心抑兼并，瘠土賦委填。", "如聞下温詔，膏澤爲洗湔。", "但願多樂歲，鼓腹常便便。"]'),
('fce5fb1e-8a0b-4117-ac2b-6ab8f9035b3c','農家三首  其三','李彭','宋','宋诗','song-poetry','','[]','牛羊腯以肥，鴨鷄大且碩。',72,'全唐诗/poet.song.79000.json','["牛羊腯以肥，鴨鷄大且碩。", "里正少經過，誰能事烹擊。", "年豐大作社，婦姑得紡績。", "吾生本完膚，箴砭困無疾。", "十年遭追胥，翻倒徒四壁。", "從今得安眠，絡緯鳴唧唧。"]'),
('bb5a8196-ce9c-4535-845c-125c0516752e','聞官軍已破賊巢','李彭','宋','宋诗','song-poetry','','[]','海內政不苛，民望罷危苦。',216,'全唐诗/poet.song.79000.json','["海內政不苛，民望罷危苦。", "劇賊藏禍心，全吴俄歗聚。", "僣號着赭黄，竊發遽如許。", "喧然大點兵，移檄插毛羽。", "推轂遣軍容，壯士皆貔虎。", "府縣調急夫，騷動煩里旅。", "富室齎金璧，細民攜婦女。", "巖谷遠遁逃，股慄畏刀鋸。", "寒儒守松楸，效死安忍去。", "南風吹捷音，破竹聞吉語。", "聖朝乾坤大，鼠輩敢予侮。", "妖氛已盪盡，和氣滿南土。", "但願勤民瘼，治安每危懼。", "昨抱心腹疴，砭劑得良愈。", "要於匕筯間，毋忘伏枕慮。", "諸公頗皋夔，臨軒跨堯禹。", "鄙夫芻蕘言，庶或資小補。", "倚松一長吟，停雲洒朝雨。"]'),
('09376399-b0b1-4e1e-9af0-1a19d4034814','吕信道以詩見遺作五字句報之','李彭','宋','宋诗','song-poetry','','[]','江州持月旦，嚴於亞夫營。',84,'全唐诗/poet.song.79000.json','["江州持月旦，嚴於亞夫營。", "君爲倒屣客，濩落四坐驚。", "我從鄂沔來，會面邾子城。", "新詩照窗几，頗復深而清。", "作人有佳處，喜客家釀傾。", "幽花不遣賞，未免遭譏評。", "何當小拂掠，拚飲罄玉缾。"]'),
('4a8a943b-385a-4cdf-aa30-5cd628def211','有慶上人數以詩見贈慶始學詩於祖可爾來擺脱故步進而不已未可量也作短句以報之','李彭','宋','宋诗','song-poetry','','[]','晝公無恙時，句吐春空雲。',156,'全唐诗/poet.song.79000.json','["晝公無恙時，句吐春空雲。", "筆端斂萬壑，中聞清夜猿。", "門生霑賸馥，派别自淵源。", "深嶺蘿月妙，縱觀嵐氣昏。", "時蒙一顧重，騰驤空馬羣。", "大師於越秀，幽氣如芳蓀。", "玉笈發金籥，闊步登詞門。", "脱略塵外躅，摩霄鬱飛翻。", "豈惟足風露，定復多皇墳。", "昨枉招隱句，深靚麗且温。", "挽我誘松桂，要移北山文。", "諸郎短兵接，此事獨策勲。", "慚非鍾嶸評，更休知音論。"]'),
('53e29c44-5c44-4eab-8638-21977160f902','自武寧捨舟度嶺投宿南山寺','李彭','宋','宋诗','song-poetry','','[]','水落晚灘澀，雲生寒嶺昏。',96,'全唐诗/poet.song.79000.json','["水落晚灘澀，雲生寒嶺昏。", "捨舟步崎峰，鬱蘿陟松門。", "孤烟望墟落，浮林自一源。", "野杓方屢渡，槿籬時扣閽。", "弄孫何許翁，夷面復鳥言。", "問津了不解，路窮斜谷分。", "暝投古蘭若，鐘磬清塵根。", "猶疑武陵客，誤宿桃花村。"]'),
('c34b2d3c-b90f-4086-bed3-25247e0a1934','遊真風觀','李彭','宋','宋诗','song-poetry','','[]','緣雲得支徑，遂造幽人居。',48,'全唐诗/poet.song.79000.json','["緣雲得支徑，遂造幽人居。", "夕風冒梁棟，蒼苔上庭除。", "仙崖衣襞積，玉磬韻虚徐。", "回首塵外躅，浩歌將焉如。"]'),
('b6d698af-331e-461e-9ad1-bcd206f24628','歸來堂爲韓子蒼題','李彭','宋','宋诗','song-poetry','','[]','出處無定在，閲世關盛衰。',240,'全唐诗/poet.song.79000.json','["出處無定在，閲世關盛衰。", "令德山林尊，昭代丘園非。", "達人解其趣，頗復擇所歸。", "淵明傲世故，葛巾風欹欹。", "偶隨出岫雲，戲作三徑資。", "少日辭吏去，新菊親風期。", "韓侯極簡秀，早蒙當宁知。", "未吐五色綫，小試聊補遺。", "高詠少司命，乘風載雲旗。", "一坐空無人，安能免深排。", "昨來天東壁，少欲乘泰階。", "誤隨曉星去，流落天南陲。", "得縣篁竹中，簿領頗沈迷。", "奈何訓誥筆，反用催科爲。", "度堂痛掃溉，勝氣自爾隨。", "風度窗户急，雲生梁棟遲。", "不減田園居，歸去將安之。", "窈窈青禁闥，沈沈黄金閨。", "至尊下温詔，羣公歌式微。", "行矣戒徂兩，長吟收夕霏。"]'),
('022a7be1-6662-49fb-8a3c-2ae371342a92','曉發章水道中有懷伯固駒甫師川養直效何水部體以寄恨','李彭','宋','宋诗','song-poetry','','[]','幽窗未全曙，百鳥忽忽鳴。',84,'全唐诗/poet.song.79000.json','["幽窗未全曙，百鳥忽忽鳴。", "分袂會心侣，歸艎章水平。", "寒温乍回互，適兹凋兩蓂。", "水南花未放，水北柳渾青。", "春物幾駘蕩，浮雲俄變更。", "念昨一笑適，愁分兩地情。", "縹瓷舉桑落，醒醉醉還醒。"]'),
('56901409-84b1-4538-b24a-decc78f625ac','發故篋獲端石蟾蜍研形模極小蓋予幼小時几案間物對之肅然如與故人相遇感而賦詩','李彭','宋','宋诗','song-poetry','','[]','誰從浴日淵，得此赬虬卵。',168,'全唐诗/poet.song.79000.json','["誰從浴日淵，得此赬虬卵。", "雕鐫勞哲匠，皤腹目仍睅。", "良非銅雀渴，頗覺鳳咮短。", "憶昔少年日，濡毫輒塗竄。", "蒼苔時覓句，賦雪起爲亂。", "麟經析凡例，羲易明象彖。", "冉冉桑榆交，忽忽顔鬂换。", "發囊逢故人，清夢聊爲唤。", "李膺交北海，中郎識元歎。", "當時臨所遇，與我意俱滿。", "翻思辭學官，噉月復不淺。", "起予剛直胸，往往期并案。", "願同戀棧馬，作我郊園伴。", "新詩真類俳，破睡資一粲。"]'),
('ea370a7c-175f-4a8b-897a-628cd38257a8','宿開先','李彭','宋','宋诗','song-poetry','','[]','建業未焚櫬，蓀山實靈囿。',168,'全唐诗/poet.song.79000.json','["建業未焚櫬，蓀山實靈囿。", "推輪碧眼胡，篤老勤井臼。", "草樹百經霜，往事如運帚。", "遠懷一味禪，徒酌三昧酒。", "尋源徹河漢，窈窕出幽竇。", "卧看落山腰，雙鳥起驚救。", "稍深藤蘿昏，扶蓼入徑取。", "伽陀古錄鈎，殷勤牧羊叟。", "礪角煩羸牛，外苞蘚紋皺。", "往者不可作，念切病軀痩。", "眼明逢島可，秦度復畏友。", "俯手攜阿連，冥搜逃折柳。", "竟亦不能奇，荒蕪但如舊。", "更須尋紫霄，寒廳視牛斗。"]'),
('dbd1bebd-9883-4ae0-9380-cc1eeced4d92','寄侍其雲叟','李彭','宋','宋诗','song-poetry','','[]','建業有高士，幽棲閟巖扄。',168,'全唐诗/poet.song.79000.json','["建業有高士，幽棲閟巖扄。", "時從出岫雲，縹緲來青冥。", "昨者修水頭，伴我騎長鯨。", "貌古心更古，膚清神愈清。", "朝談織烏墜，夜坐玉繩横。", "辯舌不掛壁，泊然忘譏評。", "嶧琴孤風嘯，鏖棋飛電鳴。", "慈明投祖去，霜風助揚舲。", "自我不見子，三占少微星。", "殷勤行沙鴈，素書毎丁寧。", "悠悠望塵友，變態鴻毛輕。", "盟血未曾乾，飛語聊相傾。", "少聞高士風，汗下顔甚赬。", "吾言蓋有激，因之見交情。"]'),
('02e2557f-628d-462a-8da2-d087bdb18181','宿雲居十住軒','李彭','宋','宋诗','song-poetry','','[]','塵事起濫觴，洶洶濤頭聚。',156,'全唐诗/poet.song.79000.json','["塵事起濫觴，洶洶濤頭聚。", "對鏡眼生花，尋幽心脱兔。", "歐峰阻躋攀，榆柳春再暮。", "維時春作夏，起我勤杖屨。", "捫蘿惑去蹊，陟巘忘故步。", "大壑埋白雲，陰崖崩老樹。", "縈紆幽鳥道，突兀升洞府。", "厖眉老比丘，倒屣蒙顧遇。", "曾未契三關，遽已棲十住。", "暉暉天横參，稍稍窗送曙。", "華鯨破短夢，山禽唤新句。", "伊予羣念息，亦遭回俗馭。", "徒爲三日留，復在邯鄲路。"]'),
('41cba20b-5889-40aa-95e3-8e263f632ace','雪夜戲玉侯','李彭','宋','宋诗','song-poetry','','[]','望舒離金虎，晚雨幻玉沙。',120,'全唐诗/poet.song.79000.json','["望舒離金虎，晚雨幻玉沙。", "觸楹勢頗疾，打窗風正斜。", "西家有勝士，夢回筆生花。", "孺人近行邁，章江駐雲車。", "銀屏擁絳桃，繡帳戲蘭牙。", "暫停短轅馭，清歡春思賖。", "陋巷笑短李，柴門蓬藋遮。", "裋褐對孟光，冰柱吟劉义。", "想君獨樂時，覓句剩欲誇。", "脉脉無由語，疏林集暝鴉。"]'),
('a773eeab-dbf4-4199-944a-2d3bf1c9bd4e','對雪','李彭','宋','宋诗','song-poetry','','[]','晏陰城郭昏，窮巷寒意沍。',72,'全唐诗/poet.song.79000.json','["晏陰城郭昏，窮巷寒意沍。", "回飈卷玉塵，稍稍凝曙露。", "應煩阿香手，終日舂薄暮。", "獨鳥避寒柯，驚麕迷故步。", "木冰達官怕，向來聞此語。", "擁絮卧北窗，鼻端從栩栩。"]'),
('bd245d58-128f-4983-8b7f-40c7bc013ec0','遣興','李彭','宋','宋诗','song-poetry','','[]','彌年倦行役，丘園曠幽尋。',120,'全唐诗/poet.song.79000.json','["彌年倦行役，丘園曠幽尋。", "殷勤響晴哢，爲我貽好音。", "梨花映皓月，猶作故時面。", "歸來雪如花，坐看花如霰。", "中朝懸美祿，椎鋒號能軍。", "而我於此時，不武亦不文。", "平生嚴子陵，故自狂奴態。", "箕踞問君房，素癡寧小差。", "上馬須不落，起居善何如。", "吾生行樂爾，何用明區區。"]'),
('0e3cd108-75de-4db9-bcbd-aa31c9759299','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其一','李彭','宋','宋诗','song-poetry','','[]','嚴霜知勁柏，大節見固窮。',48,'全唐诗/poet.song.79000.json','["嚴霜知勁柏，大節見固窮。", "懷人居白下，抱道立黄中。", "秦淮浩茫茫，楚山耿叢叢。", "胡爲恡音素，過盡南歸鴻。"]'),
('fc468780-5662-4fae-bc48-f87696e4b69f','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其二','李彭','宋','宋诗','song-poetry','','[]','達士庶可慕，勞生良足悲。',48,'全唐诗/poet.song.79000.json','["達士庶可慕，勞生良足悲。", "君看嘉賓黠，何如方回癡。", "榮衰等湛露，變更如劇棋。", "冥冥萬事定，何用機心爲。"]'),
('7227e7c5-4214-40bc-b546-bbb04732e8ab','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其三','李彭','宋','宋诗','song-poetry','','[]','學詩如食蜜，甘芳無中邊。',48,'全唐诗/poet.song.79000.json','["學詩如食蜜，甘芳無中邊。", "陳言初務去，晚乃换骨仙。", "我昔實知此，老懶挽不前。", "兒曹喜吟諷，快意艷陽天。"]'),
('f0ce7a7b-3573-4822-b014-390eb8bce290','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其四','李彭','宋','宋诗','song-poetry','','[]','曩時阮步兵，埋照毎沉醉。',48,'全唐诗/poet.song.79000.json','["曩時阮步兵，埋照毎沉醉。", "是身託麯蘖，真若有所避。", "誰知名教中，固自多樂地。", "花氣雜和風，相我曲肱睡。"]'),
('6739b28e-8ed0-49ad-af0a-01cdbcf06e4c','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其五','李彭','宋','宋诗','song-poetry','','[]','西京執戟郎，老嗜杯中物。',48,'全唐诗/poet.song.79000.json','["西京執戟郎，老嗜杯中物。", "觀其所著書，澀讀由蹇吃。", "劇秦見平生，何心窺彷彿。", "唯有四愁賦，至今猶炳蔚。"]'),
('73a63fb5-35a2-45ea-8d9d-16603567aa85','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其六','李彭','宋','宋诗','song-poetry','','[]','孔融天下士，荀彧雙南金。',48,'全唐诗/poet.song.79000.json','["孔融天下士，荀彧雙南金。", "既爲阿瞞用，復爲阿瞞禽。", "獨聞管幼安，龍蟠滄海深。", "難用固難殺，耿光垂古今。"]'),
('a7b77cde-7dac-4341-a3ce-4642c3648cf1','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其七','李彭','宋','宋诗','song-poetry','','[]','器博無近用，胸中要縱横。',48,'全唐诗/poet.song.79000.json','["器博無近用，胸中要縱横。", "腐儒昧行藏，寒窗守一經。", "營營市道交，務利如兼并。", "無復典刑在，况當觀老成。"]'),
('99bc0afc-d70e-4576-a640-dc084b6c34ef','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其八','李彭','宋','宋诗','song-poetry','','[]','陽城海內豪，隱居晉之鄙。',48,'全唐诗/poet.song.79000.json','["陽城海內豪，隱居晉之鄙。", "養此冰霰姿，諫官安足起。", "欲沮延齡相，悠悠自風靡。", "何以昭無窮，政賴有此爾。"]'),
('666d0770-0bee-460a-a776-df4108f38ad4','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其九','李彭','宋','宋诗','song-poetry','','[]','灌園如結廬，畦蔬如養雛。',48,'全唐诗/poet.song.79000.json','["灌園如結廬，畦蔬如養雛。", "敏耘斯易壯，稍墮或攘羭。", "賣菜厭求益，得酒聊歌呼。", "醒來北窗下，解衣誦潛夫。"]'),
('fe186da6-ab3f-41e3-8dd0-2257090f7689','謝靈運詩云中爲天地物今成鄙夫有取以爲韻遣興作十章兼寄雲叟  其一○','李彭','宋','宋诗','song-poetry','','[]','幽雲生簷楹，落日掛戶牖。',48,'全唐诗/poet.song.79000.json','["幽雲生簷楹，落日掛戶牖。", "茂樹發華顛，歸鳥鳴高柳。", "春風可憐人，舉兹爲我壽。", "行樂當及時，浮名竟何有。"]'),
('21452f18-7dec-4909-af7c-4e32f498d7d7','次韻吕居仁見寄','李彭','宋','宋诗','song-poetry','','[]','井銼澹疏烟，幽憂廢寒暑。',120,'全唐诗/poet.song.79000.json','["井銼澹疏烟，幽憂廢寒暑。", "孤雲起幽嶼，澤物猶能雨。", "殷殷空裏雷，何曾濡厚土。", "燕鴻且長饑，誰能投枉渚。", "知心不識面，公子實楚楚。", "五葉活國謀，摩挲噤不吐。", "勝日覓羊何，幽期得支許。", "才高賦雌蜺，識遠辯鼮鼠。", "蘭蓀無異縣，臭味同此舉。", "開歲欲問津，夢逐寒江櫓。"]'),
('a2ce7299-4d36-4abb-bb13-3de945430b88','次九弟韻','李彭','宋','宋诗','song-poetry','','[]','觀山如觀畫，入眼詩輒進。',120,'全唐诗/poet.song.79000.json','["觀山如觀畫，入眼詩輒進。", "厭則收卷之，去留情不吝。", "老境喜平夷，落紙風雨迅。", "誰能肝賢愁，虚名媒疾疢。", "屬聞殷國師，已發吴越軔。", "破竹擒諸偷，長纓收犯順。", "官軍將解嚴，胸懷俱朗潤。", "小鴈讀我詩，出語亦遒峻。", "流霞暾槁顔，如彼潮有信。", "但願吉語聞，稱觴兀斑鬢。"]'),
('7d34ed1d-8e0e-409d-94d8-ab91e2956c10','次韻元亮行沙頭','李彭','宋','宋诗','song-poetry','','[]','甘雪餞餘運，行春慰清愁。',108,'全唐诗/poet.song.79000.json','["甘雪餞餘運，行春慰清愁。", "曠懷萬物表，妙趣寄滄洲。", "視我園中蔬，陳根發新柔。", "恨無清渭姿，入涇不同流。", "老鴈唼菰蒲，非忘稻梁謀。", "天涯網羅密，所以挽不留。", "倚杖一蕭散，好鳥鳴林丘。", "誰同北山老，不動移文羞。", "仲兄儻能來，長嘯狎鳬鷗。"]'),
('a8a149d4-de64-485b-9d68-9284a241b3b2','再次元亮韻','李彭','宋','宋诗','song-poetry','','[]','艇子打兩槳，石城催莫愁。',108,'全唐诗/poet.song.79000.json','["艇子打兩槳，石城催莫愁。", "不嫌波浪闊，但懼水生洲。", "大堤多女兒，草暖復桑柔。", "盈盈成雅步，皎皎臨清流。", "翠釵掛人冠，自作横陳謀。", "非無一時好，高懷詎能留。", "朝歌回墨翟，饋藥逃東丘。", "此豈聊復爾，頗似憐包羞。", "長吟望烟際，飛來雙白鷗。"]'),
('13305463-a130-4535-acbf-42b11522b762','從弟用前韻作人日詩見寄復和以贈之','李彭','宋','宋诗','song-poetry','','[]','涉七日爲人，眷言空復愁。',108,'全唐诗/poet.song.79000.json','["涉七日爲人，眷言空復愁。", "既念襧處士，骨驚鸚鵡洲。", "更憐劉太孫，擇鄉得温柔。", "二兒千金軀，輕生隨轉流。", "樽中有歡伯，一笑爲爾謀。", "白髪生如寄，時駛不可留。", "我有騰化術，長袂挹浮丘。", "若言可持餉，定免二子羞。", "煩君一來過，春色著汀鷗。"]');
